-- ============================================
-- 基本情報技術者試験 -用語集- (exam_id=5, section_id=17〜39)
-- 問題形式: 4択単一選択（用語の説明 → 正しい用語を選ぶ）
-- 各分野1問の初期セット
-- ============================================

DO $$
DECLARE
  qid integer;
BEGIN

  -- ─── 17: 基礎理論 ───────────────────────────────────────────
  VALUES (17, 1, 'choice', 1, 1,
    '位取り記数法において，各桁の重みの底となる数はどれか。2進数では2，10進数では10，16進数では16がこれにあたる。',
    '基数はradixともいう。基数rのn桁の数はr^n種類の値を表現できる。2進数は基数2，16進数は基数16。コンピュータ内部は基数2（2進数）で処理される。'
  ) RETURNING id INTO qid;


END $$;

-- ============================================
-- 基礎理論 (section_id=17) 追加問題 Q2〜Q50
-- 用語リスト順: 2の補数〜分散
-- ============================================

DO $$
DECLARE
  qid integer;
BEGIN

  -- Q2: 2の補数
  VALUES (17, 2, 'choice', 1, 1,
    '2進数で負の数を表現する方式の一つで，全ビットを反転（1の補数）した後に1を加えることで得られる表現はどれか。',
    '2の補数は加算器のみで加減算を実現できるため，コンピュータの負数表現として広く用いられる。0の表現が一通りで，符号絶対値や1の補数より扱いやすい。'
  ) RETURNING id INTO qid;

  -- Q3: 固定小数点数
  VALUES (17, 3, 'choice', 1, 1,
    '小数点の位置をあらかじめ固定して数値を表現する方式で，整数演算と同じハードウェアで処理できるが，表現できる値の範囲が限られる数値表現形式はどれか。',
    '固定小数点数は小数点位置を一定とするため，同じビット数なら浮動小数点数より精度は高いが表現範囲が狭い。DSPや組み込みシステムの音声処理などで使われる。'
  ) RETURNING id INTO qid;

  -- Q4: 単精度浮動小数点数
  VALUES (17, 4, 'choice', 1, 1,
    'IEEE 754規格で定義された浮動小数点形式のうち，符号1ビット・指数部8ビット・仮数部23ビットの計32ビットで数値を表現するものはどれか。',
    '単精度浮動小数点数（float）は有効桁数が約7桁。倍精度（64ビット）より省メモリだが精度が低い。GPU演算やゲームエンジンなど高速処理が優先される場面で使われる。'
  ) RETURNING id INTO qid;

  -- Q5: 倍精度浮動小数点数
  VALUES (17, 5, 'choice', 1, 1,
    'IEEE 754規格で定義された浮動小数点形式のうち，符号1ビット・指数部11ビット・仮数部52ビットの計64ビットで数値を表現するものはどれか。',
    '倍精度浮動小数点数（double）は有効桁数が約15〜16桁。科学技術計算や財務計算など高精度が求められる場面で広く使われ，多くの言語のデフォルト浮動小数点型。'
  ) RETURNING id INTO qid;

  -- Q6: 仮数部
  VALUES (17, 6, 'choice', 1, 1,
    '浮動小数点数を構成する3要素（符号・指数部・〇〇）のうち，数値の有効数字（精度）を表す部分はどれか。',
    '仮数部（significand/mantissa）のビット数が多いほど精度が高い。IEEE 754単精度では23ビット，倍精度では52ビット。正規化により最上位ビットは常に1（暗黙ビット）。'
  ) RETURNING id INTO qid;

  -- Q7: 指数部
  VALUES (17, 7, 'choice', 1, 1,
    '浮動小数点数において，小数点の位置（スケール）を示す部分で，この値が大きいほど表現できる数値の絶対値が大きくなる部分はどれか。',
    '指数部（exponent）はバイアス表現で格納される。IEEE 754単精度ではバイアス値127を加えて0〜255で表す。指数部のビット数が大きいほど表現範囲が広がる。'
  ) RETURNING id INTO qid;

  -- Q8: BCD
  VALUES (17, 8, 'choice', 1, 1,
    '10進数の各桁を4ビットの2進数で個別に符号化する方式で，「Binary Coded Decimal」の略称はどれか。',
    'BCDは1桁の10進数を4ビットで表す（例：9→1001）。金融計算や表示装置などで誤差なしの10進処理が必要な場面に使われる。'
  ) RETURNING id INTO qid;

  -- Q9: パック10進数
  VALUES (17, 9, 'choice', 1, 1,
    '1バイト（8ビット）に2桁のBCDを詰め込んで格納し，最後のニブルに符号を置く数値表現形式はどれか。',
    'パック10進数はCOBOLや汎用機で広く使われてきた。1バイトに2桁格納できるため，アンパック10進数（1バイト1桁）よりメモリ効率が良い。'
  ) RETURNING id INTO qid;

  -- Q10: 論理シフト
  VALUES (17, 10, 'choice', 1, 1,
    'ビット列をずらす際に符号ビットを考慮せず，あふれたビットを捨て，空いた桁に0を補充するシフト演算はどれか。',
    '論理シフトは符号なし整数の乗除算（左n回=2^n倍，右n回=2^n除算）に使われる。右論理シフトでは最上位ビットに必ず0が入る。'
  ) RETURNING id INTO qid;

  -- Q11: 算術シフト
  VALUES (17, 11, 'choice', 1, 1,
    '符号付き2進数において，右シフト時に符号ビット（最上位ビット）の値を保持したまま空いた上位ビットを埋めるシフト演算はどれか。',
    '算術右シフトは符号付き整数の2^n除算（切捨て）に対応する。負の数でも符号が保たれるため，2の補数表現での符号付き演算に使われる。'
  ) RETURNING id INTO qid;

  -- Q12: 桁落ち
  VALUES (17, 12, 'choice', 1, 1,
    '値がほぼ等しい2つの浮動小数点数を減算したとき，有効桁数が大きく減少してしまう演算誤差はどれか。',
    '桁落ちは「1.0000001 − 1.0000000」のような計算で発生し，結果の有効桁がほぼゼロになる。数値計算アルゴリズムの設計で回避策が重要となる。'
  ) RETURNING id INTO qid;

  -- Q13: 情報落ち
  VALUES (17, 13, 'choice', 1, 1,
    '絶対値の差が非常に大きい2つの浮動小数点数を加減算したとき，小さい方の数が仮数部の桁数不足で無視されてしまう演算誤差はどれか。',
    '情報落ちは「1000000.0 + 0.0001」の結果が「1000000.0」になるようなケース。大きな値に小さな値を加算し続けると誤差が蓄積される。'
  ) RETURNING id INTO qid;

  -- Q14: オーバーフロー
  VALUES (17, 14, 'choice', 1, 1,
    '演算結果が使用している数値表現形式で表現できる最大値を超えてしまう状態はどれか。',
    'オーバーフローが発生すると結果が正しく格納されずプログラムが誤動作する。符号付き整数では正負が逆転することがある。加算・乗算時に特に注意が必要。'
  ) RETURNING id INTO qid;

  -- Q15: アンダーフロー
  VALUES (17, 15, 'choice', 1, 1,
    '浮動小数点演算の結果が表現できる最小の正の値より小さくなり，0として扱われてしまう状態はどれか。',
    'アンダーフローは浮動小数点数の指数部が表現可能な下限を下回るときに発生する。オーバーフローとは逆に，絶対値が極端に小さい値で起きる。'
  ) RETURNING id INTO qid;

  -- Q16: 単精度
  VALUES (17, 16, 'choice', 1, 1,
    'IEEE 754で定義された浮動小数点数の精度区分のうち，32ビットで表現され有効桁数が約7桁のものはどれか。',
    '単精度（single precision）はfloat型に相当する。倍精度（double，64ビット）より省メモリで演算が速いが精度が劣る。グラフィクス処理などで多用される。'
  ) RETURNING id INTO qid;

  -- Q17: 倍精度
  VALUES (17, 17, 'choice', 1, 1,
    'IEEE 754で定義された浮動小数点数の精度区分のうち，64ビットで表現され有効桁数が約15〜16桁のものはどれか。',
    '倍精度（double precision）は単精度の2倍のビット幅を持ち，科学技術計算や財務計算で標準的に使われる。多くの言語のデフォルト浮動小数点型。'
  ) RETURNING id INTO qid;

  -- Q18: ベン図
  VALUES (17, 18, 'choice', 1, 1,
    '集合の関係（積集合・和集合・補集合など）を，重なり合う円形の図形を用いて視覚的に表現した図はどれか。',
    'ベン図（Venn diagram）はジョン・ベンが考案。集合の論理関係を直感的に把握できる。論理回路のカルノー図とは異なり，集合の包含・共通部分を表す。'
  ) RETURNING id INTO qid;

  -- Q19: 和集合
  VALUES (17, 19, 'choice', 1, 1,
    '集合AまたはBのどちらか一方，あるいは両方に属する全ての要素からなる集合（A∪B）はどれか。',
    '和集合は論理演算のORに対応し，ベン図では2つの円全体に相当する。A∪B = {x | x∈A または x∈B} と定義される。'
  ) RETURNING id INTO qid;

  -- Q20: 積集合
  VALUES (17, 20, 'choice', 1, 1,
    '集合AとBの両方に属する要素だけからなる集合（A∩B）はどれか。',
    '積集合（共通部分）は論理演算のANDに対応し，ベン図では2つの円の重なる部分に相当する。A∩B = {x | x∈A かつ x∈B} と定義される。'
  ) RETURNING id INTO qid;

  -- Q21: 補集合
  VALUES (17, 21, 'choice', 1, 1,
    '全体集合Uの中で，集合Aに属さない要素全体からなる集合（Ā）はどれか。',
    '補集合は論理演算のNOTに対応する。ド・モルガンの法則は補集合と積集合・和集合の関係を示す：(A∩B)の補=Āの和B̄，(A∪B)の補=Ā∩B̄。'
  ) RETURNING id INTO qid;

  -- Q22: 部分集合
  VALUES (17, 22, 'choice', 1, 1,
    '集合Aの全ての要素が集合Bにも含まれるとき，AとBの関係を表す用語はどれか。',
    '部分集合（subset）はA⊆Bで表す。AがBの部分集合かつA≠BのときAはBの真部分集合（A⊂B）という。空集合はあらゆる集合の部分集合。'
  ) RETURNING id INTO qid;

  -- Q23: 真
  VALUES (17, 23, 'choice', 1, 1,
    '命題論理において，ある命題が成立している状態を表す論理値はどれか。',
    '論理値「真」（true，1）は命題が正しいことを表す。コンピュータ内部では1ビットで表現され，条件分岐や論理演算の基礎となる。'
  ) RETURNING id INTO qid;

  -- Q24: 偽
  VALUES (17, 24, 'choice', 1, 1,
    '命題論理において，ある命題が成立していない状態を表す論理値はどれか。',
    '論理値「偽」（false，0）は命題が正しくないことを表す。否定演算（NOT）を適用すると「真」になる。'
  ) RETURNING id INTO qid;

  -- Q25: 命題論理
  VALUES (17, 25, 'choice', 1, 1,
    '命題（真偽が定まる文）を基本単位として，否定・論理和・論理積などの演算子で複合命題の真偽を扱う論理体系はどれか。',
    '命題論理は述語論理よりシンプルな体系で，論理回路設計の基礎。「もしAならばB」のような含意（→）も定義できる。'
  ) RETURNING id INTO qid;

  -- Q26: 否定
  VALUES (17, 26, 'choice', 1, 1,
    '論理演算の一つで，入力が真なら偽を，入力が偽なら真を出力する1入力の演算はどれか。',
    '否定（NOT）はインバータとも呼ばれる。二重否定（NOTのNOT）は元の値に戻る。ド・モルガンの法則でANDとOR変換に使われる。'
  ) RETURNING id INTO qid;

  -- Q27: 論理和
  VALUES (17, 27, 'choice', 1, 1,
    '2入力の少なくとも一方が真（1）のとき出力が真（1）となる論理演算（OR）はどれか。',
    '論理和（OR）はビット演算では特定ビットを1に設定するのに使われる。集合の和集合（A∪B）に対応し，真理値表では「0,0→0，それ以外→1」。'
  ) RETURNING id INTO qid;

  -- Q28: 論理積
  VALUES (17, 28, 'choice', 1, 1,
    '2入力がともに真（1）のときのみ出力が真（1）となる論理演算（AND）はどれか。',
    '論理積（AND）はビット演算では特定ビットをマスクして0に設定するのに使われる。集合の積集合（A∩B）に対応する。'
  ) RETURNING id INTO qid;

  -- Q29: 排他的論理和
  VALUES (17, 29, 'choice', 1, 1,
    '2入力が異なる値（一方が真，他方が偽）のときのみ出力が真（1）となる論理演算（XOR）はどれか。',
    '排他的論理和（XOR）は同じ値を2回演算すると元に戻る性質があり，暗号化・誤り訂正・パリティ計算に活用される。加算器の和の出力もXORで実現できる。'
  ) RETURNING id INTO qid;

  -- Q30: 否定論理和
  VALUES (17, 30, 'choice', 1, 1,
    '論理和（OR）の結果を反転した演算で，2入力がともに偽（0）のときのみ出力が真（1）となる論理演算（NOR）はどれか。',
    '否定論理和（NOR）はNANDと並んで論理的完全性を持ち，NORゲートだけで全ての論理演算を実現できる。フリップフロップの基本回路にも使われる。'
  ) RETURNING id INTO qid;

  -- Q31: 否定論理積
  VALUES (17, 31, 'choice', 1, 1,
    '論理積（AND）の結果を反転した演算で，2入力の少なくとも一方が偽（0）のとき出力が真（1）となる論理演算（NAND）はどれか。',
    '否定論理積（NAND）は論理的完全性を持ち，NANDゲートだけで全ての論理演算を実現できる。CMOSトランジスタで実装しやすいため，集積回路の基本ゲート。'
  ) RETURNING id INTO qid;

  -- Q32: 論理関数
  VALUES (17, 32, 'choice', 1, 1,
    '0または1の値を取る論理変数を入力とし，論理演算を組み合わせて出力を定める関数はどれか。',
    '論理関数はブール関数とも呼ばれる。n変数の論理関数は真理値表で2^n行として完全に定義できる。カルノー図や積和標準形で最簡化できる。'
  ) RETURNING id INTO qid;

  -- Q33: 分配則
  VALUES (17, 33, 'choice', 1, 1,
    'ブール代数において「A∧(B∨C) = (A∧B)∨(A∧C)」および「A∨(B∧C) = (A∨B)∧(A∨C)」が成立する法則はどれか。',
    '分配則は論理回路の最適化に使われる。通常の代数と同様にANDがORに対して分配できるだけでなく，逆にORがANDに対しても分配できる点がブール代数の特徴。'
  ) RETURNING id INTO qid;

  -- Q34: ド・モルガンの法則
  VALUES (17, 34, 'choice', 1, 1,
    'NOT(A AND B) = (NOT A) OR (NOT B)，および NOT(A OR B) = (NOT A) AND (NOT B) が成立するブール代数の法則はどれか。',
    'ド・モルガンの法則は論理式の変形・回路最適化やプログラムの条件式リファクタリングに使われる。集合論では補集合との関係として表れる。'
  ) RETURNING id INTO qid;

  -- Q35: 階乗
  VALUES (17, 35, 'choice', 1, 1,
    '正の整数nに対して，1からnまでの全ての整数の積をn!と表す演算はどれか。',
    '階乗（factorial）は順列・組み合わせの計算に使われる。n! = n×(n-1)×…×2×1 で，特に0! = 1 と定義される。アルゴリズムの計算量評価にも登場する。'
  ) RETURNING id INTO qid;

  -- Q36: 加法定理
  VALUES (17, 36, 'choice', 1, 1,
    'P(A∪B) = P(A) + P(B) − P(A∩B) という，事象AまたはBが起こる確率を求める確率の定理はどれか。',
    '加法定理はAとBが排反（P(A∩B)=0）のとき P(A∪B)=P(A)+P(B) に簡略化される。3事象以上への拡張（包除原理）もある。'
  ) RETURNING id INTO qid;

  -- Q37: 乗法定理
  VALUES (17, 37, 'choice', 1, 1,
    'P(A∩B) = P(A) × P(B|A) という，事象AとBが同時に起こる確率を求める確率の定理はどれか。',
    '乗法定理はAとBが独立のとき P(A∩B)=P(A)×P(B) に簡略化される。条件付き確率とセットで理解する必要がある。'
  ) RETURNING id INTO qid;

  -- Q38: 同時確率
  VALUES (17, 38, 'choice', 1, 1,
    '2つの事象AとBが同時（または同一試行内で共に）発生する確率 P(A∩B) はどれか。',
    '同時確率（結合確率）は乗法定理 P(A∩B)=P(A)×P(B|A) で求められる。AとBが独立なら P(A)×P(B) に等しい。'
  ) RETURNING id INTO qid;

  -- Q39: 条件付き確率
  VALUES (17, 39, 'choice', 1, 1,
    '事象Bが既に起きたという条件のもとで，事象Aが起きる確率 P(A|B) = P(A∩B) / P(B) はどれか。',
    '条件付き確率はベイズの定理の基礎。P(A|B)は「Bが分かっているときのAの確率」を表し，スパムフィルタや医療診断などに応用される。'
  ) RETURNING id INTO qid;

  -- Q40: ベイズの定理
  VALUES (17, 40, 'choice', 1, 1,
    '事前確率P(A)と尤度P(B|A)から事後確率P(A|B)を求める式 P(A|B) = P(B|A)P(A) / P(B) はどれか。',
    'ベイズの定理は新しい証拠に基づいて確率を更新するベイズ更新の基礎。ナイーブベイズ分類器やスパムフィルタ，医療診断など多くの分野で応用される。'
  ) RETURNING id INTO qid;

  -- Q41: ポアソン分布
  VALUES (17, 41, 'choice', 1, 1,
    '単位時間（または単位面積）に平均λ回発生する事象が，ちょうどk回発生する確率を P(X=k)=λ^k e^−λ/k! で表す離散確率分布はどれか。',
    'ポアソン分布は稀な事象の発生回数をモデル化する。コールセンターへの着信件数・放射性崩壊の回数など，単位時間のランダムな事象の個数に適用される。'
  ) RETURNING id INTO qid;

  -- Q42: ベルヌーイ分布
  VALUES (17, 42, 'choice', 1, 1,
    '1回の試行で確率pで成功（1），確率1−pで失敗（0）となる，最も基本的な離散確率分布はどれか。',
    'ベルヌーイ分布はコイン投げのような二値結果を持つ試行のモデル。二項分布はベルヌーイ試行をn回繰り返した成功回数の分布。'
  ) RETURNING id INTO qid;

  -- Q43: 二項分布
  VALUES (17, 43, 'choice', 1, 1,
    '成功確率pの独立なベルヌーイ試行をn回繰り返したとき，成功回数kの確率を P(X=k)=C(n,k)p^k(1-p)^(n-k) で表す離散確率分布はどれか。',
    '二項分布はn回試行でk回成功する確率を表す。nが大きくpが小さいとき（np=λ一定）はポアソン分布に近似でき，nが大きいと正規分布に近似できる。'
  ) RETURNING id INTO qid;

  -- Q44: 正規分布
  VALUES (17, 44, 'choice', 1, 1,
    '平均μを中心に左右対称の釣鐘形（ガウス曲線）をした連続確率分布で，自然界や測定誤差など多くの現象に現れるものはどれか。',
    '正規分布（ガウス分布）は中心極限定理により，多数の独立な確率変数の和が近似する分布。平均±1σに68%，±2σに95%，±3σに99.7%が含まれる。'
  ) RETURNING id INTO qid;

  -- Q45: 指数分布
  VALUES (17, 45, 'choice', 1, 1,
