    '等差数列（arithmetic sequence）の和は Sn = n(a₁+a_n)/2 で求められる。プログラミングのforループのインデックス列が典型的な例。'
  ) RETURNING id INTO qid;

  -- Q82: 等比数列
  VALUES (17, 82, 'choice', 1, 1,
