    '等比数列（geometric sequence）の和は Sn = a₁(1−rⁿ)/(1−r)（r≠1）。2の累乗（1,2,4,8,…）が典型例。バイナリツリーの段ごとのノード数も等比数列。'
  ) RETURNING id INTO qid;

  -- Q83: フィボナッチ数列
  VALUES (17, 83, 'choice', 1, 1,
