    'ニュートン法（ニュートン・ラフソン法）は収束が速い（2次収束）が，初期値の選択に依存する。深層学習の最適化でも微分を利用する勾配降下法と概念的に関連する。'
  ) RETURNING id INTO qid;

  -- Q87: 絶対誤差
  VALUES (17, 87, 'choice', 1, 1,
    '近似値と真の値との差の絶対値で表される，誤差の大きさを直接示す指標はどれか。',
    '絶対誤差（absolute error）＝|近似値 − 真値|。単位付きの数値に対して誤差の大きさを直接示す。相対誤差との違いは，真値の大きさを考慮しない点。'
  ) RETURNING id INTO qid;

  -- Q88: 相対誤差
  VALUES (17, 88, 'choice', 1, 1,
    '絶対誤差を真の値（または近似値）で割った比率で，数値の大きさに対する誤差の割合を示す指標はどれか。',
    '相対誤差（relative error）＝|近似値 − 真値| / |真値|。単位がなく，スケールの異なる数値間で誤差の大きさを比較するのに適している。'
  ) RETURNING id INTO qid;

  -- Q89: 丸め誤差
  VALUES (17, 89, 'choice', 1, 1,
    '有限桁数に収めるために端数を切捨て・切上げ・四捨五入することで生じる誤差はどれか。',
    '丸め誤差（rounding error）は浮動小数点演算で必ず発生する。繰り返し計算では誤差が累積することがあり，数値計算では注意が必要。'
  ) RETURNING id INTO qid;

  -- Q90: 打切り誤差
  VALUES (17, 90, 'choice', 1, 1,
    '無限級数や反復計算を有限回で打ち切ることによって生じる誤差はどれか。',
    '打切り誤差（truncation error）はテイラー展開を有限項で近似したときなどに発生する。丸め誤差と打切り誤差はどちらも数値計算の精度を低下させる主な要因。'
  ) RETURNING id INTO qid;

  -- Q91: 因数分解
  VALUES (17, 91, 'choice', 1, 1,
    '多項式または整数をより低次の多項式や素因数の積の形に分解する操作はどれか。',
    '因数分解（factorization）は方程式の解法・RSA暗号（大きな整数の素因数分解の困難さに基づく）・プログラムの式の簡略化などに用いられる。'
  ) RETURNING id INTO qid;

  -- Q92: 微分
  VALUES (17, 92, 'choice', 1, 1,
    '関数の瞬間的な変化率（接線の傾き）を求める操作で，機械学習における誤差逆伝播法（バックプロパゲーション）の数学的基礎となるものはどれか。',
    '微分（differentiation）は最適化問題に不可欠。ニューラルネットワークの学習では損失関数を各パラメータで偏微分した値（勾配）を使って重みを更新する。'
  ) RETURNING id INTO qid;

  -- Q93: 積分
  VALUES (17, 93, 'choice', 1, 1,
    '関数の曲線と軸で囲まれた面積（累積量）を求める操作で，微分の逆演算でもあるものはどれか。',
    '積分（integration）は確率密度関数の累積確率計算・信号処理・物理シミュレーションなどに使われる。微積分学の基本定理により微分と積分は互いに逆演算。'
  ) RETURNING id INTO qid;

  -- Q94: グラフ理論
  VALUES (17, 94, 'choice', 1, 1,
    '頂点（ノード）と辺（エッジ）からなる構造を研究対象とし，ネットワーク・経路問題・SNS分析などに応用される数学の分野はどれか。',
    'グラフ理論は最短経路問題（ダイクストラ法）・最小全域木・ネットワークフローなどのアルゴリズムの基礎。コンピュータサイエンスと数学の接点として重要。'
  ) RETURNING id INTO qid;

  -- Q95: 有向グラフ
  VALUES (17, 95, 'choice', 1, 1,
    'グラフの各辺に方向（向き）が定められており，辺を一方向にのみたどれるグラフはどれか。',
    '有向グラフ（directed graph，ダイグラフ）はWebページのリンク構造・タスクの依存関係（DAG）・状態遷移図などを表現する。最短経路は辺の向きに従って探索する。'
  ) RETURNING id INTO qid;

  -- Q96: 無向グラフ
  VALUES (17, 96, 'choice', 1, 1,
    'グラフの各辺に方向がなく，両方向にたどることができるグラフはどれか。',
    '無向グラフ（undirected graph）は道路網・友人関係ネットワークなどを表現する。辺{u,v}はuからvへもvからuへも移動できる。連結性・最小全域木などが研究対象。'
  ) RETURNING id INTO qid;

  -- Q97: 待ち行列モデル
  VALUES (17, 97, 'choice', 1, 1,
    '到着するリクエストがサービスを待つ行列を形成するシステムを数学的に分析し，待ち時間や行列長を求めるモデルはどれか。',
    '待ち行列モデル（queueing model）はM/M/1モデルが基本。リトルの法則 L=λW（平均待ち客数=平均到着率×平均滞在時間）が成立する。コールセンターやWebサーバの性能設計に使われる。'
  ) RETURNING id INTO qid;

  -- Q98: サービス時間
  VALUES (17, 98, 'choice', 1, 1,
    '待ち行列モデルにおいて，サービス窓口が1件のリクエストの処理を開始してから完了するまでに要する時間はどれか。',
    'サービス時間（service time）は待ち行列の性能分析の基本パラメータ。平均サービス率μはサービス時間の逆数。利用率ρ=λ/μが1未満でないと行列が無限に伸び続ける。'
  ) RETURNING id INTO qid;

  -- Q99: 待ち時間
  VALUES (17, 99, 'choice', 1, 1,
    '待ち行列モデルにおいて，リクエストが到着してからサービスを受け始めるまでの，行列で待機する時間はどれか。',
    '待ち時間（waiting time）はシステムの混雑度（利用率ρ）が高いほど長くなる。滞在時間（=待ち時間+サービス時間）との区別が重要。リトルの法則で平均行列長と関係付けられる。'
  ) RETURNING id INTO qid;

  -- Q100: 到着時間
  VALUES (17, 100, 'choice', 1, 1,
    '待ち行列モデルにおいて，リクエスト（客）がシステムに到着する時刻，またはリクエスト間の時間間隔（到着間隔）はどれか。',
    '到着時間（arrival time）はM/M/1モデルでは指数分布に従うと仮定される。平均到着率λは単位時間当たりの平均到着件数で，その逆数が平均到着間隔。'
  ) RETURNING id INTO qid;

END $$;

-- ============================================
-- 基礎理論 (section_id=17) Q101〜Q112
-- 用語リスト101番〜112番: 平均到着率〜Unicode
-- ============================================

DO $$
DECLARE
  qid integer;
BEGIN

  -- Q101: 平均到着率
  VALUES (17, 101, 'choice', 1, 1,
    '待ち行列モデルにおいて，単位時間当たりに平均何件のリクエストが到着するかを表すパラメータはどれか。',
    '平均到着率λ（ラムダ）は単位時間当たりの平均到着件数。その逆数1/λが平均到着間隔。M/M/1モデルでは利用率ρ=λ/μが1未満のとき系が安定し，待ち行列が無限に伸びない。'
  ) RETURNING id INTO qid;

  -- Q102: 平均サービス率
  VALUES (17, 102, 'choice', 1, 1,
    '待ち行列モデルにおいて，サービス窓口が単位時間当たりに処理できる平均件数を表すパラメータはどれか。',
    '平均サービス率μ（ミュー）はサービス時間の逆数。利用率ρ=λ/μがサーバの混雑度を表し，ρ<1でないと待ち行列が定常状態にならない。'
  ) RETURNING id INTO qid;

  -- Q103: 最適化問題
  VALUES (17, 103, 'choice', 1, 1,
    '制約条件のもとで目的関数の値を最大または最小にする変数の値を求める問題はどれか。',
    '最適化問題（optimization problem）は機械学習の学習（損失関数の最小化）・スケジューリング・経路計画などの基礎。線形計画・整数計画・凸最適化などの分類がある。'
  ) RETURNING id INTO qid;

  -- Q104: 動的計画法
  VALUES (17, 104, 'choice', 1, 1,
    '問題を重複する部分問題に分割し，各部分問題の解をメモ化（表に保存）しながら再利用することで，全体の計算量を削減するアルゴリズム設計手法はどれか。',
    '動的計画法（DP）はフィボナッチ数列・最短経路（ベルマン-フォード法）・ナップサック問題・編集距離などに使われる。再帰の重複計算をメモ化で排除する点が特徴。'
  ) RETURNING id INTO qid;

  -- Q105: 通信路符号化
  VALUES (17, 105, 'choice', 1, 1,
    'データを通信路で伝送する際に，雑音による誤りを検出・訂正できるよう冗長ビットを付加して符号化することを何というか。',
    '通信路符号化（channel coding）は誤り検出・訂正のための符号を付加する技術。パリティチェック・ハミング符号・CRC・ターボ符号・LDPC符号などがある。情報源符号化とは目的が異なる。'
  ) RETURNING id INTO qid;

  -- Q106: ハフマン符号
  VALUES (17, 106, 'choice', 1, 1,
    '出現頻度の高い記号に短い符号を，頻度の低い記号に長い符号を割り当てることで平均符号長を最小化する，可変長の情報源符号化方式はどれか。',
    'ハフマン符号（Huffman coding）はエントロピーに最も近い平均符号長を実現する最適な可変長符号。JPEG・ZIP・gzipなどの圧縮フォーマットの基礎技術として使われる。'
  ) RETURNING id INTO qid;

  -- Q107: 情報源符号化
  VALUES (17, 107, 'choice', 1, 1,
    'データの冗長性を取り除いて符号語の平均長を短くすることを目的とした，データ圧縮に相当する符号化はどれか。',
    '情報源符号化（source coding）はデータ圧縮の理論的基礎。シャノンの情報源符号化定理により，平均符号長の下限はエントロピーで決まる。通信路符号化（誤り訂正）とは目的が逆。'
  ) RETURNING id INTO qid;

  -- Q108: ASCIIコード
  VALUES (17, 108, 'choice', 1, 1,
    '英字・数字・記号・制御文字を7ビット（128種類）で表現する，コンピュータの文字コードの基礎となった米国規格の文字符号化方式はどれか。',
    'ASCII（American Standard Code for Information Interchange）は1963年制定。7ビットで0x00〜0x7Fを定義する。8ビット拡張のISO 8859やUnicodeの基礎となった。'
  ) RETURNING id INTO qid;

  -- Q109: EUC
  VALUES (17, 109, 'choice', 1, 1,
    'UNIXシステムで日本語などの多バイト文字を扱うために使われた文字符号化方式で，「Extended Unix Code」の略称はどれか。',
    'EUC（Extended Unix Code）はASCIIとの後方互換性を保ちながら多バイト文字を扱う。日本語向けのEUC-JPはJIS X 0208を2バイトで符号化する。現在はUTF-8に置き換わりつつある。'
  ) RETURNING id INTO qid;

  -- Q110: JISコード
  VALUES (17, 110, 'choice', 1, 1,
    '日本工業規格（JIS）が制定した文字集合の符号化で，エスケープシーケンスで1バイト文字と2バイト文字を切り替えるISO-2022-JPベースの文字符号化はどれか。',
    'JISコード（ISO-2022-JP）は電子メールや電報で広く使われた。エスケープシーケンスで文字集合を切り替えるため，同一ファイル内に複数の文字集合が混在できる。'
  ) RETURNING id INTO qid;

  -- Q111: シフトJISコード
  VALUES (17, 111, 'choice', 1, 1,
    'Microsoftが策定した日本語文字コードで，1バイトのASCII文字と2バイトの日本語文字を混在させられる符号化方式はどれか。',
    'シフトJISコード（Shift_JIS）はWindowsや旧来のWebで広く使われた。1バイト目の値をシフトすることでASCIIと区別する設計。現在はUTF-8への移行が進んでいる。'
  ) RETURNING id INTO qid;

  -- Q112: Unicode
  VALUES (17, 112, 'choice', 1, 1,
    '世界中の文字を統一的に扱うために策定された文字コード規格で，U+0000〜U+10FFFFのコードポイントに各文字を割り当てるものはどれか。',
    'Unicode（ISO/IEC 10646）は世界の文字を単一の文字集合に統合する規格。符号化形式としてUTF-8（可変長）・UTF-16・UTF-32がある。UTF-8はASCII互換でWebの標準エンコーディング。'
  ) RETURNING id INTO qid;

END $$;

-- ============================================
-- 基礎理論 (section_id=17) Q113〜Q162
-- 用語リスト113番〜162番: UCS〜中間言語
-- ============================================

DO $$
DECLARE
  qid integer;
BEGIN

  -- Q113: UCS
  VALUES (17, 113, 'choice', 1, 1,
    'ISOが制定した国際標準の文字集合規格で，Unicodeと実質的に統合されており，世界中の文字に一意のコードポイントを割り当てるものはどれか。',
    'UCS（Universal Coded Character Set，ISO/IEC 10646）はUnicodeコンソーシアムと協調して管理されており，現在はUnicodeと同一のコードポイント体系を持つ。'
  ) RETURNING id INTO qid;

  -- Q114: 述語論理
  VALUES (17, 114, 'choice', 1, 1,
    '命題論理を拡張し，個体・述語・量化子（∀全称・∃存在）を用いて「すべてのxについて…」「あるxが存在して…」という構造を扱える論理体系はどれか。',
    '述語論理（一階述語論理）はデータベースの問合せ言語・Prologなどの論理プログラミング・定理証明の基礎。命題論理より表現力が高いが，決定可能性が失われる。'
  ) RETURNING id INTO qid;

  -- Q115: 演繹推論
  VALUES (17, 115, 'choice', 1, 1,
    '一般的な前提（公理・規則）から個別の結論を論理的必然性をもって導く推論形式はどれか。',
    '演繹推論（deductive reasoning）は前提が真なら結論も必ず真。数学の定理証明・三段論法が典型。エキスパートシステムの前向き・後ろ向き推論も演繹を基礎とする。'
  ) RETURNING id INTO qid;

  -- Q116: 帰納推論
  VALUES (17, 116, 'choice', 1, 1,
    '個別の観察事例から一般的な規則・法則を導く推論形式で，機械学習の学習プロセスの概念的基礎でもあるものはどれか。',
    '帰納推論（inductive reasoning）は「多数の事例を観察して一般化する」推論。演繹と異なり，結論が必ずしも真とは限らない（反証可能）。科学的方法の基礎。'
  ) RETURNING id INTO qid;

  -- Q117: 形式言語
  VALUES (17, 117, 'choice', 1, 1,
    'アルファベット（記号の有限集合）上の文字列の集合として数学的に定義される言語で，文法規則によって生成される文字列の集まりはどれか。',
    '形式言語（formal language）はチョムスキー階層（正規言語・文脈自由言語・文脈依存言語・帰納的可算言語）で分類される。プログラミング言語の構文定義に使われる。'
  ) RETURNING id INTO qid;

  -- Q118: 逆ポーランド表記法
  VALUES (17, 118, 'choice', 1, 1,
    '演算子をオペランドの後ろに置く記法で，括弧を使わずに演算の優先順位を表現でき，スタックを用いて効率的に評価できる数式の表記法はどれか。',
    '逆ポーランド表記法（後置記法，RPN）は「3 4 +」で3+4を表す。スタックマシンで左から右へ処理するだけで評価できるため，コンパイラの中間コード生成に使われる。'
  ) RETURNING id INTO qid;

  -- Q119: 有限オートマトン
  VALUES (17, 119, 'choice', 1, 1,
    '有限個の状態・入力記号・遷移関数・初期状態・受理状態からなる計算モデルで，正規言語の認識と等価な能力を持つ抽象機械はどれか。',
    '有限オートマトン（FA）は決定性（DFA）と非決定性（NFA）があり，どちらも同等の表現能力を持つ。正規表現と等価で，字句解析器（レキサ）の理論的基礎となる。'
  ) RETURNING id INTO qid;

  -- Q120: 時間計算量
  VALUES (17, 120, 'choice', 1, 1,
    'アルゴリズムが入力サイズnに対して実行する基本操作の回数（ステップ数）の増加傾向をO記法で表したものはどれか。',
    '時間計算量（time complexity）はアルゴリズムの実行速度の理論的指標。O(1)＜O(log n)＜O(n)＜O(n log n)＜O(n²)＜O(2ⁿ) の順に遅くなる。空間計算量と対比される。'
  ) RETURNING id INTO qid;

  -- Q121: エキスパートシステム
  VALUES (17, 121, 'choice', 1, 1,
    '特定分野の専門家の知識をルールとして知識ベースに蓄積し，推論エンジンを用いてその分野の問題を解くAIシステムはどれか。',
    'エキスパートシステムは1970〜80年代のAI黄金期に注目された。医療診断・化学分析（DENDRAL）・税務処理などに応用された。知識獲得のボトルネックが普及の課題となった。'
  ) RETURNING id INTO qid;

  -- Q122: 知識ベース
  VALUES (17, 122, 'choice', 1, 1,
    'エキスパートシステムにおいて，専門家から獲得したルール・事実・制約などの知識を構造化して蓄積したデータベースはどれか。',
    '知識ベース（knowledge base）はIF-THENルール形式や意味ネットワークなどで知識を表現する。推論エンジンと組み合わせて問題解決に使われる。'
  ) RETURNING id INTO qid;

  -- Q123: 推論エンジン
  VALUES (17, 123, 'choice', 1, 1,
    'エキスパートシステムにおいて，知識ベースのルールを適用して結論を導くメカニズムはどれか。',
    '推論エンジン（inference engine）は前向き推論（データから結論へ）と後ろ向き推論（目標から証拠へ）の2方式がある。知識ベースとは独立して再利用できる点が特徴。'
  ) RETURNING id INTO qid;

  -- Q124: 汎化
  VALUES (17, 124, 'choice', 1, 1,
    '機械学習において，学習データだけでなく未知のデータに対しても正確に予測・分類できるモデルの能力はどれか。',
    '汎化（generalization）は機械学習の最終目標。訓練データへの過度な適合（過学習）を避け，未知データにも対応できるモデルを構築することが重要。正則化・ドロップアウトなどで改善する。'
  ) RETURNING id INTO qid;

  -- Q125: 機械学習
  VALUES (17, 125, 'choice', 1, 1,
    'データから自動的にパターンやルールを学習し，明示的にプログラムしなくても予測・分類・判断ができるようにするAIの手法の総称はどれか。',
    '機械学習（machine learning）は教師あり学習・教師なし学習・強化学習の3種類に大別される。統計的学習理論を基礎とし，深層学習（ディープラーニング）もその一分野。'
  ) RETURNING id INTO qid;

  -- Q126: 教師あり学習
  VALUES (17, 126, 'choice', 1, 1,
    '入力データと正解ラベル（教師信号）のペアを用いてモデルを学習させ，未知データへの予測・分類を行う機械学習の学習方式はどれか。',
    '教師あり学習（supervised learning）は回帰・分類問題に使われる。線形回帰・決定木・SVM・ニューラルネットワークなどが該当する。正解ラベルの準備コストが課題。'
  ) RETURNING id INTO qid;

  -- Q127: 教師なし学習
  VALUES (17, 127, 'choice', 1, 1,
    '正解ラベルなしのデータからパターン・構造・グループを自動的に発見する機械学習の学習方式はどれか。',
    '教師なし学習（unsupervised learning）はクラスタリング（k-means）・次元削減（PCA）・異常検知・生成モデルなどに使われる。ラベルなしデータを活用できる利点がある。'
  ) RETURNING id INTO qid;

