DO $$
DECLARE
  qid integer;
BEGIN

-- Q1: RDB
VALUES (25, 1, 'choice', 1, 1,
  'データを表（テーブル）の形式で管理し，SQL を用いて操作できる，現在最も広く使われているデータベースモデルはどれか。',
  'RDB（Relational Database：関係データベース）は，関係モデルに基づきデータを行と列からなる表で管理する。SQLで操作でき，Oracle・MySQL・PostgreSQLなどが代表的なRDBMS。'
) RETURNING id INTO qid;

-- Q2: 構造型データベース（HDB）
VALUES (25, 2, 'choice', 1, 1,
  '階層モデル・ネットワークモデルなど，データ間の構造を明示的に定義して管理するデータベースの総称はどれか。',
  '構造型データベースは，データ間の親子関係やリンク構造を事前に定義して管理する。階層型（HDB）やネットワーク型（NDB）が代表例で，RDB普及以前に主流だった。'
) RETURNING id INTO qid;

-- Q3: HDB
VALUES (25, 3, 'choice', 1, 1,
  'データを木構造（ツリー）の親子関係で管理し，親から子へ一方向にたどることでデータを取り出すデータベースモデルはどれか。',
  'HDB（Hierarchical Database：階層型データベース）は，データを親子の木構造で管理する。IBMのIMS（1960年代）が代表例。検索が速い反面，構造変更が難しくデータ重複が生じやすい。'
) RETURNING id INTO qid;

-- Q4: NDB
VALUES (25, 4, 'choice', 1, 1,
  'データ間の関係をネットワーク（グラフ）構造で表し，子レコードが複数の親を持てるデータベースモデルはどれか。',
  'NDB（Network Database：ネットワーク型データベース）は，CODASYL仕様が代表例。階層型の制約を緩和し，多対多の関係を直接表現できる。しかしスキーマ変更が困難という欠点を持つ。'
) RETURNING id INTO qid;

-- Q5: OODB
VALUES (25, 5, 'choice', 1, 1,
  'オブジェクト指向プログラミングの概念（クラス・継承・カプセル化など）をそのままデータベースに適用したデータベースモデルはどれか。',
  'OODB（Object-Oriented Database：オブジェクト指向データベース）は，オブジェクトをそのまま格納できる。複雑なデータ構造やメディアデータの管理に適するが，普及はRDBに及ばなかった。'
) RETURNING id INTO qid;

-- Q6: XMLデータベース
VALUES (25, 6, 'choice', 1, 1,
  'XML文書をそのまま格納・検索・管理できる，半構造化データ向けのデータベースはどれか。',
  'XMLデータベースは，XML文書をネイティブに格納・XQueryやXPathで検索できるDB。文書の構造が不規則でも扱えるため，設定ファイルや文書管理に利用される。MarkLogicなどが代表例。'
) RETURNING id INTO qid;

-- Q7: 分散データベース
VALUES (25, 7, 'choice', 1, 1,
  'データを複数のコンピュータ（ノード）に分散して格納・管理し，利用者には1つのデータベースに見えるシステムを何というか。',
  '分散データベースは，データが複数サイトに分散しているがユーザには単一DBに見える（透過性）。負荷分散・耐障害性・地理的分散が利点。CAP定理（一貫性・可用性・分断耐性）がトレードオフとなる。'
) RETURNING id INTO qid;

-- Q8: ドキュメント指向データベース
VALUES (25, 8, 'choice', 1, 1,
  'JSON・BSONなどの形式で表現された柔軟な構造のドキュメントを単位としてデータを格納・管理するNoSQLデータベースはどれか。',
  'ドキュメント指向データベースは，スキーマレスでJSONのようなドキュメントを格納する。MongoDBが代表例。ドキュメントごとに構造が異なってもよく，Webアプリのコンテンツ管理に適する。'
) RETURNING id INTO qid;

-- Q9: 列指向データベース
VALUES (25, 9, 'choice', 1, 1,
  'データを行単位ではなく列単位で格納・圧縮するデータベースで，集計・分析クエリに高い性能を発揮するものはどれか。',
  '列指向データベース（カラム指向DB）は，同一列のデータをまとめて格納するためI/Oを削減でき，集計分析に優れる。Apache Cassandra・Amazon Redshiftなどが代表例。OLAPに適している。'
) RETURNING id INTO qid;

-- Q10: グラフデータベース
VALUES (25, 10, 'choice', 1, 1,
