) RETURNING id INTO qid;

-- Q26: 実現値
VALUES (25, 26, 'choice', 1, 1,
  '関係モデルにおいて，あるタプルの特定の属性に実際に格納されている値を何というか。',
  '実現値（instance value）は，関係スキーマが定義する属性に実際に格納されているデータ値。スキーマ（構造の定義）に対してインスタンス（実際のデータ）にあたる概念。'
) RETURNING id INTO qid;

-- Q27: 定義域（ドメイン）
VALUES (25, 27, 'choice', 1, 1,
  '関係モデルにおいて，ある属性が取りうる値の集合（データ型や制約を含む）を何というか。',
