VALUES (25, 108, 'choice', 1, 1,
  'テーブルの行データをインデックスキーの順序でディスクに物理的に並べ替えて格納するインデックスを何というか。',
  'クラスタ化インデックス（クラスタードインデックス）は，テーブルに1つだけ設定できる。範囲検索で連続したデータを効率的に読み取れる。SQL Serverの「クラスタードインデックス」，MySQLのInnoDB主キーがこれに相当。'
) RETURNING id INTO qid;

-- Q109: B-treeインデックス
VALUES (25, 109, 'choice', 1, 1,
  'ほとんどのRDBMSで標準的に使われる，バランス木構造を使ったインデックスで，等値検索・範囲検索・ソートに効率的なものはどれか。',
  'B-treeインデックスは，ルートから葉ノードへの検索がO(log n)で行える。等値検索・範囲検索・ORDER BY・GROUP BYに適する。PostgreSQL・MySQL・Oracleでデフォルトのインデックス種別。'
) RETURNING id INTO qid;

-- Q110: ビットマップインデックス
VALUES (25, 110, 'choice', 1, 1,
  '各値ごとにビット列を作成し，どの行がその値を持つかを0/1で表すインデックスで，カーディナリティ（値の種類）が少ない列の集計に有効なものはどれか。',
  'ビットマップインデックスは，性別・ステータスなど値の種類が少ない列に有効。複数列のビットマップをAND/OR演算で組み合わせて高速集計できる。DWH・OLAPで多用される。更新が多いOLTPには不向き。'
) RETURNING id INTO qid;

-- Q111: ハッシュインデックス
VALUES (25, 111, 'choice', 1, 1,
  'キー値をハッシュ関数でバケット番号に変換して格納するインデックスで，等値検索では非常に高速だが範囲検索には使えないものはどれか。',
  'ハッシュインデックスは，等値検索（WHERE id = 42）でO(1)に近い性能を発揮する。ただし範囲検索・ORDER BYには使えない。PostgreSQLのHASHインデックス，MySQLのMEMORYエンジンなどで利用できる。'
) RETURNING id INTO qid;

-- Q112: カバリングインデックス
VALUES (25, 112, 'choice', 1, 1,
  'クエリで必要とするすべての列がインデックスに含まれており，テーブル本体へのアクセス（テーブルフェッチ）を不要にできるインデックスを何というか。',
  'カバリングインデックス（Covering Index）は，SELECT・WHERE・ORDER BYで使う全列をインデックスに含めることで，インデックスのみでクエリが完結する。テーブルI/Oが削減されて高速化する。'
) RETURNING id INTO qid;

-- Q113: 転置インデックス
VALUES (25, 113, 'choice', 1, 1,
  '全文検索エンジンや検索サービスで使われる，各単語（トークン）がどのドキュメントに出現するかをリスト化したインデックス構造を何というか。',
  '転置インデックス（Inverted Index）は，「単語→出現ドキュメントIDのリスト」を保持する。Elasticsearch・Apache Solr・PostgreSQLのGINインデックスで採用。全文検索を高速化する。'
) RETURNING id INTO qid;

-- Q114: 参照権限
VALUES (25, 114, 'choice', 1, 1,
  'データベースにおいて，テーブルやビューのデータをSELECT文で読み取ることを許可する権限を何というか。',
  '参照権限（SELECT権限）は，GRANT SELECT ON テーブル名 TO ユーザ名 で付与する。読み取りのみを許可し，更新・削除は別途権限が必要。ビューを使えば特定列・行のみ参照させることもできる。'
) RETURNING id INTO qid;

-- Q115: 挿入権限
VALUES (25, 115, 'choice', 1, 1,
  'データベースにおいて，テーブルにINSERT文で新しい行を追加することを許可する権限を何というか。',
  '挿入権限（INSERT権限）は，GRANT INSERT ON テーブル名 TO ユーザ名 で付与する。列を指定して特定列のみ挿入を許可することもできる。参照権限・更新権限・削除権限とは個別に管理される。'
) RETURNING id INTO qid;

-- Q116: 削除権限
VALUES (25, 116, 'choice', 1, 1,
  'データベースにおいて，テーブルからDELETE文で行を削除することを許可する権限を何というか。',
  '削除権限（DELETE権限）は，GRANT DELETE ON テーブル名 TO ユーザ名 で付与する。削除は取り消しが困難な操作のため，一般ユーザには付与せず管理者・特定ロールにのみ与えることが多い。'
) RETURNING id INTO qid;

-- Q117: データウェアハウス
VALUES (25, 117, 'choice', 1, 1,
  '組織内の複数のシステムからデータを収集・統合し，経営分析・意思決定支援を目的として蓄積した大規模なデータ格納庫を何というか。',
  'データウェアハウス（DWH）は，OLTPシステムとは分離した分析用DBで，履歴データを大量に保持する。スタースキーマやスノーフレークスキーマで設計される。Amazon Redshift・Google BigQueryなどが代表例。'
) RETURNING id INTO qid;

-- Q118: データマート
VALUES (25, 118, 'choice', 1, 1,
  'データウェアハウスから特定の部門・業務用途のデータだけを抽出・整形した，小規模な分析用データ格納庫を何というか。',
  'データマートは，DWHの一部または派生物で，特定の事業部・目的（営業分析・在庫分析など）に特化している。DWHより規模が小さく，部門ごとに管理される場合もある。'
) RETURNING id INTO qid;

-- Q119: データマイニング
VALUES (25, 119, 'choice', 1, 1,
  '大量のデータから統計・機械学習などの手法を使って，人間が気づきにくいパターン・相関・規則を自動的に発見する分析技術を何というか。',
  'データマイニングは，分類・回帰・クラスタリング・アソシエーション分析（バスケット分析）などの手法を用いる。小売業の購買パターン分析・不正検知・顧客セグメンテーションなどに活用される。'
) RETURNING id INTO qid;

-- Q120: OLTP
VALUES (25, 120, 'choice', 1, 1,
  '業務システムで日常的に行われる，少数行に対する高頻度の挿入・更新・削除・参照のトランザクション処理方式を何というか。',
  'OLTP（Online Transaction Processing）は，受注管理・銀行ATM・ECなどの業務システムで使われる。短時間の小さなトランザクションを多数処理する。OLAPとは対比される概念。'
) RETURNING id INTO qid;

-- Q121: ETL
VALUES (25, 121, 'choice', 1, 1,
  'データウェアハウス構築で使われる，複数ソースからデータを抽出（Extract）し，変換（Transform）してから格納先に読み込む（Load）一連のデータ連携プロセスを何というか。',
  'ETL（Extract・Transform・Load）は，DWH/データマートへのデータ取り込みの標準プロセス。変換ステップでクレンジング・形式統一・集計を行う。ELTは変換をDB側で行う逆順のアプローチ。'
) RETURNING id INTO qid;

-- Q122: ELT
VALUES (25, 122, 'choice', 1, 1,
  'データをまず格納先（データウェアハウス・データレイク）にロードし，その後に変換処理をDB側で行うデータ連携アプローチを何というか。',
  'ELT（Extract・Load・Transform）は，クラウドDWHの大規模な処理能力を活用して変換をDB内で実行する。BigQuery・SnowflakeなどクラウドネイティブなDWHの台頭で普及した。ETLとは変換とロードの順が逆。'
) RETURNING id INTO qid;

-- Q123: データクレンジング
VALUES (25, 123, 'choice', 1, 1,
  'データウェアハウスや分析システムに取り込む前に，欠損値・重複・不整合・誤記などの品質問題を検出・修正する作業を何というか。',
  'データクレンジング（データクリーニング）は，ETLの変換ステップに含まれる。名寄せ（同一人物を示す異なる表記の統一）・欠損値補完・外れ値除去などが含まれる。データ品質がDWHの信頼性を左右する。'
) RETURNING id INTO qid;

-- Q124: ビッグデータ
VALUES (25, 124, 'choice', 1, 1,
  '従来のRDBMSでは処理困難な，大量性（Volume）・多様性（Variety）・高速性（Velocity）の3Vを特徴とする大規模データの総称を何というか。',
  'ビッグデータは，3V（Volume：データ量，Variety：構造化・非構造化・半構造化の多様性，Velocity：リアルタイム性）で定義される。Hadoop・Spark・クラウドデータレイクなどで処理される。'
) RETURNING id INTO qid;

-- Q125: 文書管理システム
VALUES (25, 125, 'choice', 1, 1,
  '組織内の文書を電子的に作成・管理・検索・共有・版管理するための情報システムを何というか。',
  '文書管理システム（DMS：Document Management System）は，紙文書のデジタル化・検索・アクセス制御・版管理・ワークフロー機能を持つ。SharePoint・Confluenceなどが代表例。'
) RETURNING id INTO qid;

-- Q126: 営業支援システム
VALUES (25, 126, 'choice', 1, 1,
  '顧客情報・商談履歴・活動記録などを一元管理し，営業活動の効率化と売上予測を支援するシステムを何というか。',
  'SFA（Sales Force Automation：営業支援システム）は，顧客・案件・活動管理と売上予測を提供する。SalesforceやHubSpotが代表例。CRM（顧客関係管理）と統合されることが多い。'
) RETURNING id INTO qid;

-- Q127: 透過性
VALUES (25, 127, 'choice', 1, 1,
  '分散データベースにおいて，データが複数のサイトに分散していることを利用者に意識させず，あたかも1台のDBを使っているように見せる性質を何というか。',
  '透過性（Transparency）は，分散DBの重要な性質。位置透過性（どこにデータがあるか意識しない）・複製透過性（複製の存在を意識しない）・分割透過性（データの分割方法を意識しない）などがある。'
) RETURNING id INTO qid;

-- Q128: コミットメント制御
VALUES (25, 128, 'choice', 1, 1,
  'トランザクションの完了（COMMIT）または取り消し（ROLLBACK）を明示的に管理することで，データの整合性と原子性を保証する制御機構を何というか。',
  'コミットメント制御は，ACID特性のうち原子性（A）と耐久性（D）を実現する仕組み。COMMIT実行で変更が永続化され，ROLLBACK実行で変更が取り消される。分散DBでは2相コミットメントを使う。'
) RETURNING id INTO qid;

-- Q129: レプリケーション
VALUES (25, 129, 'choice', 1, 1,
  'データベースの内容をリアルタイムまたは定期的に別のサーバに複製・同期することで，可用性・耐障害性・参照性能を向上させる仕組みを何というか。',
  'レプリケーションは，プライマリDB（書き込み担当）とレプリカDB（読み取り担当）で構成されることが多い。障害時のフェイルオーバ，地理的分散，読み取りスケールアウトに活用される。'
) RETURNING id INTO qid;

-- Q130: メタデータ（DWH文脈）
VALUES (25, 130, 'choice', 1, 1,
  'データウェアハウスにおいて，データの出所・変換履歴・意味・所有者・品質などを説明する管理情報を何というか。',
  'DWHにおけるメタデータは，ビジネスメタデータ（意味・用語）・技術メタデータ（スキーマ・データ型）・運用メタデータ（更新履歴・品質指標）に分類される。データカタログとして一元管理することが多い。'
) RETURNING id INTO qid;

-- Q131: データディクショナリ（DWH/ツール文脈）
VALUES (25, 131, 'choice', 1, 1,
  'データウェアハウスや情報システム全体で使われるデータ項目の定義・意味・形式・所在などを一元的に登録・管理する辞書的なリポジトリを何というか。',
  'データディクショナリは，組織全体のデータ標準化・共通理解を支援する。DBMSのシステムカタログとは異なり，業務的な意味付け（ビジネス定義）まで含む場合がある。データガバナンスの基盤となる。'
) RETURNING id INTO qid;

-- Q132: リポジトリ
VALUES (25, 132, 'choice', 1, 1,
  'ソフトウェア開発やデータ管理において，成果物・メタデータ・定義情報などを一元的に格納・管理する中央管理型の保管場所を何というか。',
  'リポジトリは，データ管理文脈ではデータ定義・ルール・メタデータの格納場所を指す。ソフトウェア開発ではソースコードの版管理（Git等）を指す場合もある。IRDSはリポジトリの国際標準規格。'
) RETURNING id INTO qid;

-- Q133: IRDS
VALUES (25, 133, 'choice', 1, 1,
  'ISO/IECが策定した，データ資源（定義・意味・構造）を管理するリポジトリシステムの国際標準規格を何というか。',
  'IRDS（Information Resource Dictionary System）は，ISO/IEC 10027として標準化された情報資源辞書システムの規格。データディクショナリ・リポジトリの国際標準的な位置付け。実装はベンダーごとに異なる。'
) RETURNING id INTO qid;

-- Q134: 分散ファイルシステム
VALUES (25, 134, 'choice', 1, 1,
  '複数のサーバにまたがってファイルを分散格納し，ネットワーク経由で単一のファイルシステムとして見せるシステムを何というか。',
  '分散ファイルシステムは，大量データを複数ノードで並列処理するビッグデータ基盤の核心技術。HDFS（Hadoop Distributed File System）・GFS・Ceph・GlusterFSなどが代表例。スケールアウトと耐障害性を両立する。'
) RETURNING id INTO qid;

-- Q135: 構造化データ
VALUES (25, 135, 'choice', 1, 1,
  'あらかじめ定義されたスキーマ（行・列の構造）に従って整然と格納されたデータで，RDBテーブルやCSVファイルが代表例のものを何というか。',
  '構造化データは，決まった形式で格納されSQLで容易に検索・集計できる。売上データ・顧客マスタなどが該当。非構造化データ（テキスト・画像など）・半構造化データ（JSON・XMLなど）とは対比される。'
) RETURNING id INTO qid;

-- Q136: 半構造化データ
VALUES (25, 136, 'choice', 1, 1,
  '厳密なスキーマは持たないが，タグや階層構造（JSON・XML・CSVヘッダなど）によって自己記述的な構造を持つデータを何というか。',
  '半構造化データは，JSON・XML・YAMLなどが代表例。スキーマが柔軟でドキュメント指向DBとの親和性が高い。完全にスキーマレスな非構造化データ（自然言語テキスト・画像など）とは区別される。'
) RETURNING id INTO qid;

-- Q137: 非構造化データ
VALUES (25, 137, 'choice', 1, 1,
  '定義されたスキーマや構造を持たず，テキスト・画像・音声・動画などの形式で格納されるデータを何というか。',
  '非構造化データは，Eメールの本文・SNS投稿・画像・動画・音声ファイルなどが該当。全データの約80%が非構造化と言われる。自然言語処理・画像認識などのAI技術で価値を引き出す。'
) RETURNING id INTO qid;

-- Q138: ストリーミングデータ
VALUES (25, 138, 'choice', 1, 1,
  'センサ・SNS・ログなどから継続的にリアルタイムで生成・送信されるデータで，バッチ処理ではなくリアルタイム処理が求められるものを何というか。',
  'ストリーミングデータは，IoTセンサ・株価・クリックストリーム・ログなど常時流れ続けるデータ。Apache Kafka・Amazon Kinesis・Apache Flinkなどのリアルタイム処理基盤で処理する。'
) RETURNING id INTO qid;

-- Q139: データレイク
VALUES (25, 139, 'choice', 1, 1,
  '構造化・半構造化・非構造化を問わず，あらゆる形式のデータを変換せずに原形のまま大規模に蓄積する中央集約型のデータリポジトリを何というか。',
  'データレイク（Data Lake）は，ELTアプローチでデータを先に蓄積し後から活用する。AWS S3・Azure Data Lake・GCS+BigQueryなどで実装される。DWH（加工済みデータのみ）とは異なり生データも保持する。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q1: LAN
VALUES (26, 1, 'choice', 1, 1,
  '同一建物・フロア・キャンパスなど限られた地理的範囲内に構築されたコンピュータネットワークを何というか。',
  'LAN（Local Area Network）は，建物・フロア・キャンパス内などの局所的なネットワーク。有線（Ethernet）と無線（Wi-Fi）がある。WAN（広域ネットワーク）と対比される。'
) RETURNING id INTO qid;

-- Q2: WAN
VALUES (26, 2, 'choice', 1, 1,
  '地理的に離れた複数の拠点やネットワークを，通信事業者の回線を利用して広域に接続したネットワークを何というか。',
  'WAN（Wide Area Network）は，都市・国・大陸をまたぐ広域ネットワーク。専用線・VPN・インターネット回線などで構成される。インターネット自体もWANの一形態。'
) RETURNING id INTO qid;

-- Q3: インターネットサービスプロバイダ
VALUES (26, 3, 'choice', 1, 1,
  '個人・企業にインターネット接続サービスを提供する事業者を何というか。',
  'ISP（Internet Service Provider：インターネットサービスプロバイダ）は，インターネット接続回線・メール・DNSなどのサービスを提供する。NTT・KDDI・ソフトバンクなどが代表例。'
) RETURNING id INTO qid;

-- Q4: 従量制
VALUES (26, 4, 'choice', 1, 1,
  '通信料金の課金体系で，実際に利用したデータ転送量や接続時間に応じて料金が変わる方式を何というか。',
  '従量制は，使った分だけ課金される方式。使用量が少ない場合は安く済むが，大量利用時はコストが増大する。月額固定（定額）制とは対比される概念。モバイルデータ通信の超過分課金もこれに該当。'
) RETURNING id INTO qid;

-- Q5: 月額固定料金
VALUES (26, 5, 'choice', 1, 1,
  '通信料金の課金体系で，利用量にかかわらず毎月一定の料金を支払う方式を何というか。',
  '月額固定料金（定額制・フラットレート）は，利用量に関わらず固定費用で利用できる。大量利用者にとって有利で，費用の予測が立てやすい。従量制とは対比される。'
) RETURNING id INTO qid;

-- Q6: IDF
VALUES (26, 6, 'choice', 1, 1,
  '建物内ネットワーク配線において，各フロアに設置されMDFから配線を受け各部屋のコンセントへ分配する中間配線盤を何というか。',
  'IDF（Intermediate Distribution Frame：中間配線盤）は，フロアごとに設置される配線集約装置。MDFから受け取った幹線ケーブルを各部屋のアウトレットへ分岐する。スイッチングハブ等を収容する。'
) RETURNING id INTO qid;

-- Q7: MDF
VALUES (26, 7, 'choice', 1, 1,
  '建物への外部回線引き込み点に設置され，外部回線と建物内配線を接続する主配線盤を何というか。',
  'MDF（Main Distribution Frame：主配線盤）は，建物への外部通信回線の引き込み点。ISPからの回線をここで終端し，各フロアのIDFへ幹線ケーブルを配線する。サーバ室・1Fに設置されることが多い。'
) RETURNING id INTO qid;

-- Q8: パケット交換網
VALUES (26, 8, 'choice', 1, 1,
  'データを小さな単位（パケット）に分割して宛先情報とともに送り出し，ネットワーク上でルーティングして届けるデータ通信方式を何というか。',
  'パケット交換は，データをパケット単位に分割し各パケットが独立してルーティングされる。回線を占有しないため効率が高い。インターネット（IP網）はパケット交換方式。回線交換方式と対比される。'
