-- Q310: 双方向の追跡可能性（受入れ）
VALUES (28, 310, 'choice', 1, 1,
  '受入れテスト段階で，受入れテストケースと要件・設計・実装の間の対応関係を双方向に確認できる特性を何というか。',
  '受入れ段階での双方向の追跡可能性は，全ての要件が受入れテストでカバーされているかを確認する。検収の根拠となる重要な品質証跡。規制業種では必須の要件となることが多い。'
) RETURNING id INTO qid;

-- Q311: 教育訓練システム
VALUES (28, 311, 'choice', 1, 1,
  'システムの利用者・運用者が安全に操作訓練を行うための，本番環境とは独立した教育専用の環境を何というか。',
  '教育訓練システム（Training System）は本番データに影響を与えずに実際の操作を習得するための環境。本番環境と同等の機能を持ちながら，練習用のダミーデータで動作する。'
) RETURNING id INTO qid;

-- Q312: 運用規程
VALUES (28, 312, 'choice', 1, 1,
  'システムを安定して運用するための，業務フロー・操作手順・障害対応・バックアップ・セキュリティ管理などを定めた規則・手順書を何というか。',
  '運用規程（Operation Manual/Procedure）は本番稼働開始前に整備する重要なドキュメント。日常業務手順・定期作業・障害対応・変更管理・セキュリティ管理の手順を含む。'
) RETURNING id INTO qid;

-- Q313: 利用者用文書類
VALUES (28, 313, 'choice', 1, 1,
  'システムの利用者が参照するために作成されるドキュメント（操作マニュアル・ヘルプ・FAQ・チュートリアル等）の総称を何というか。',
  '利用者用文書類はユーザーマニュアル・オンラインヘルプ・FAQ・クイックリファレンスカードなどが含まれる。利用者の技術レベルに合わせた記述と，使いやすい構成が重要。'
) RETURNING id INTO qid;

-- Q314: システム利用文書
VALUES (28, 314, 'choice', 1, 1,
  'システム全体の概要・機能・構成・運用方法を記述した，システム管理者向けの文書を何というか。',
  'システム利用文書はシステムの全体像・アーキテクチャ・機能一覧・設定パラメータ・メンテナンス手順などを記述する。管理者・運用者が参照するシステムレベルの文書。'
) RETURNING id INTO qid;

-- Q315: ソフトウェア利用文書
VALUES (28, 315, 'choice', 1, 1,
  '特定のソフトウェア（アプリケーション・ライブラリ等）のインストール・設定・使用方法を記述した文書を何というか。',
  'ソフトウェア利用文書（ソフトウェアマニュアル）はインストールガイド・設定ガイド・リリースノート・APIリファレンスなどを含む。システム利用文書の下位概念として位置づけられる。'
) RETURNING id INTO qid;

-- Q316: 妥当性確認テストの目的
VALUES (28, 316, 'choice', 1, 1,
  '受入れテストにおいて，システムが利用者のニーズ・期待に合致しているかを確認するテストの意義・ねらいを何というか。',
  '妥当性確認（Validation）テストの目的は「正しいものを作ったか」の確認。検証（Verification・正しく作ったか）と対比される。利用者の実業務でシステムが機能することを確認する。'
) RETURNING id INTO qid;

-- Q317: 成功基準
VALUES (28, 317, 'choice', 1, 1,
  '妥当性確認テストにおいて，テストが成功したと判断するための条件・基準を何というか。',
  '成功基準（Success Criteria）は妥当性確認テストの合否判定の根拠。機能の正確性・性能目標の達成・ユーザー満足度・残存欠陥数などの定量的・定性的な基準を事前に定義する。'
) RETURNING id INTO qid;

-- Q318: 適用する妥当性確認テストの技法
VALUES (28, 318, 'choice', 1, 1,
  '受入れテスト・妥当性確認において使用するテスト手法（ユーザビリティテスト・ベータテスト・業務シナリオテスト等）を何というか。',
  '妥当性確認テストの技法には，実際の業務シナリオを使った機能テスト・使用性テスト・ベータテスト・ロールプレイテスト・パイロット運用などがある。テスト目的に応じて適切な技法を選択する。'
) RETURNING id INTO qid;

-- Q319: 各妥当性確認テストを実施するための環境条件
VALUES (28, 319, 'choice', 1, 1,
  '妥当性確認テストを実施するために必要な環境（ハードウェア・ソフトウェア・データ・ネットワーク・操作者等の条件）を何というか。',
  '妥当性確認テストの環境条件は本番環境に近いほど信頼性が高い。テストデータ（本番同等データ）・ユーザー端末・ネットワーク帯域・外部システム連携環境などを含む。'
) RETURNING id INTO qid;

-- Q320: 不具合の根本原因
VALUES (28, 320, 'choice', 1, 1,
  '発見した不具合・障害が発生した根本的な原因（設計ミス・要件の誤解・コーディングエラー等）を特定する分析結果を何というか。',
  '不具合の根本原因（Root Cause）の特定は再発防止の基礎。なぜなぜ分析・フィッシュボーン図（特性要因図）・5 Whys・フォルトツリー分析などの手法で根本原因を掘り下げる。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q321: 是正処置
VALUES (28, 321, 'choice', 1, 1,
  '不具合や欠陥の原因を特定し、再発しないように根本原因を取り除く活動を何というか。',
  '是正処置（corrective action）は問題の根本原因を排除し再発防止を図る。単なる応急処置（暫定処置）とは異なり、恒久的な原因除去を目的とする。'
) RETURNING id INTO qid;

-- Q322: 欠陥修正
VALUES (28, 322, 'choice', 1, 1,
  'ソフトウェアに発見された欠陥（バグ）を修正してシステムを正しい状態に戻す作業を何というか。',
  '欠陥修正（defect repair）は発見されたバグを取り除く作業。修正後は回帰テストを実施して新たな欠陥が混入していないことを確認する。'
) RETURNING id INTO qid;

-- Q323: 改善作業
VALUES (28, 323, 'choice', 1, 1,
  'プロセスや成果物をより良い状態にするために継続的に取り組む活動を何というか。',
  '改善作業（improvement）はプロセスや製品の品質向上を継続的に図る活動。PDCAサイクルや反省会（レトロスペクティブ）などを通じて実施する。'
) RETURNING id INTO qid;

-- Q324: 学んだ教訓の記録
VALUES (28, 324, 'choice', 1, 1,
  'プロジェクトを通じて得た成功・失敗・改善点などの知見を文書化し、将来のプロジェクトに活かすための記録を何というか。',
  '学んだ教訓の記録（lessons learned）はプロジェクト終了時などに経験知識を文書化する活動。組織の知識資産として蓄積され次プロジェクトの品質向上に寄与する。'
) RETURNING id INTO qid;

-- Q325: 使用性テスト
VALUES (28, 325, 'choice', 1, 1,
  '実際のユーザが製品を使用し、使いやすさや操作性を評価するテストを何というか。',
  '使用性テスト（usability testing）は対象ユーザが実際にシステムを操作し、使いやすさ・効率・満足度などを評価する。タスク達成率や操作時間を測定することが多い。'
) RETURNING id INTO qid;

-- Q326: ベータテスト
VALUES (28, 326, 'choice', 1, 1,
  '製品リリース前に限られた実ユーザに製品を提供し、実環境でのフィードバックを収集するテストを何というか。',
  'ベータテスト（beta testing）は開発者外部の実ユーザが実際の環境で製品を試用し問題点を報告するテスト。アルファテスト（社内）の後に実施する。'
) RETURNING id INTO qid;

-- Q327: 運用操作テスト
VALUES (28, 327, 'choice', 1, 1,
  'システムを実際に運用・管理する担当者が、運用手順や操作手順を確認するテストを何というか。',
  '運用操作テスト（operational testing）は運用担当者がシステムの起動・停止・バックアップ・障害対応などの手順を実施して問題がないか確認するテスト。'
) RETURNING id INTO qid;

-- Q328: 利用者テスト
VALUES (28, 328, 'choice', 1, 1,
  'システムの実際の利用者が業務シナリオに沿って操作し、要件を満たしているか確認するテストを何というか。',
  '利用者テスト（user acceptance testing）は発注者・エンドユーザが実際の業務シナリオでシステムを操作し、契約要件・業務要件を満たすか最終確認するテスト。'
) RETURNING id INTO qid;

-- Q329: 保守手順
VALUES (28, 329, 'choice', 1, 1,
  'ソフトウェアの保守を実施するための標準化された作業の進め方を定めた文書を何というか。',
  '保守手順（maintenance procedure）は変更要求の受付から分析・設計・実装・テスト・リリースまでの各ステップを規定する文書。品質を保ちながら安全に変更を実施するために用いる。'
) RETURNING id INTO qid;

-- Q330: 保守体制
VALUES (28, 330, 'choice', 1, 1,
  '保守作業を遂行するための組織・担当者・役割分担・連絡経路などを定めた仕組みを何というか。',
  '保守体制（maintenance organization）は保守チームの構成、責任者・担当者の役割、エスカレーション経路などを規定する。体制が不明確だと障害対応が遅れる原因となる。'
) RETURNING id INTO qid;

-- Q331: 保守の実現可能性
VALUES (28, 331, 'choice', 1, 1,
  'ソフトウェアが将来にわたって保守可能かどうかを判断するための評価を何というか。',
  '保守の実現可能性（maintainability feasibility）はソースコードの可読性、ドキュメントの充実度、依存ライブラリの継続サポート、技術者の確保可能性などを総合評価し保守継続を判断する。'
) RETURNING id INTO qid;

-- Q332: 保守テスト
VALUES (28, 332, 'choice', 1, 1,
  'ソフトウェアに変更を加えた後に、変更が正しく実施されていること、および既存機能が壊れていないことを確認するテストを何というか。',
  '保守テスト（maintenance testing）は変更後のシステムに対して実施するテスト全般を指す。変更箇所の確認テストと、影響範囲の回帰テストの両方を含む。'
) RETURNING id INTO qid;

-- Q333: 回帰テスト
VALUES (28, 333, 'choice', 1, 1,
  'ソフトウェアに変更を加えた際に、変更が他の機能に悪影響を与えていないことを確認するために既存のテストを再実行するテストを何というか。',
  '回帰テスト（regression testing）は既存の動作が変更によって壊れていないことを確認するテスト。デグレードテスト、再確認テストとも呼ばれる。自動化することでコストを削減できる。'
) RETURNING id INTO qid;

-- Q334: リファクタリング
VALUES (28, 334, 'choice', 1, 1,
  '外部から見た動作を変えずにソフトウェアの内部構造を改善し、可読性・保守性を高める作業を何というか。',
  'リファクタリング（refactoring）は機能を変えずにコード品質を向上させる作業。重複コードの除去、命名の改善、関数の分割などが含まれる。テストを維持しながら段階的に行うことが重要。'
) RETURNING id INTO qid;

-- Q335: リバースエンジニアリング
VALUES (28, 335, 'choice', 1, 1,
  '既存のソフトウェアや製品を分析して、その設計・仕様・構造を逆向きに解析・再現する手法を何というか。',
  'リバースエンジニアリング（reverse engineering）は完成品から仕様や設計を導き出す技術。ドキュメントが失われたレガシーシステムの保守や移行時に活用されるが、知的財産権に注意が必要。'
) RETURNING id INTO qid;

-- Q336: 組織の運用の完整性
VALUES (28, 336, 'choice', 1, 1,
  '保守活動が組織の方針・プロセス・手順に従い一貫性をもって実施されていることを表す概念を何というか。',
  '組織の運用の完整性（organizational operation integrity）は保守活動が組織として整合のとれた形で実施されていることを示す。属人化を防ぎ標準化されたプロセスによる品質確保が求められる。'
) RETURNING id INTO qid;

-- Q337: 保守契約
VALUES (28, 337, 'choice', 1, 1,
  'ソフトウェアの保守サービスを発注者と受注者間で取り決めた契約を何というか。',
  '保守契約（maintenance contract）は保守の範囲・SLA（サービスレベル合意）・費用・期間・連絡方法などを定めた契約。SLAには障害対応時間や稼働率目標などが含まれる。'
) RETURNING id INTO qid;

-- Q338: 保守要件の定義
VALUES (28, 338, 'choice', 1, 1,
  'システムの保守フェーズで必要とされる機能・性能・体制・プロセスなどを明確化する活動を何というか。',
  '保守要件の定義（maintenance requirements definition）は保守に必要な条件を事前に明確化する。対応時間・変更管理プロセス・ドキュメント更新基準などを定め、保守品質を担保する。'
) RETURNING id INTO qid;

-- Q339: ハードウェア保守
VALUES (28, 339, 'choice', 1, 1,
  'コンピュータ本体・周辺機器・ネットワーク機器など物理的な機器を点検・修理・交換する保守活動を何というか。',
  'ハードウェア保守（hardware maintenance）はサーバ・ストレージ・ネットワーク機器などの物理的な点検・清掃・部品交換・修理を行う。ソフトウェア保守と組み合わせてシステム全体の安定稼働を維持する。'
) RETURNING id INTO qid;

-- Q340: 日常点検
VALUES (28, 340, 'choice', 1, 1,
  'システムや機器の正常な動作を維持するために日々定期的に実施する確認・清掃などの作業を何というか。',
  '日常点検（daily inspection）はシステムのログ確認・ディスク使用量確認・機器の動作音確認・清掃などを毎日実施する作業。問題を早期発見し障害を未然に防ぐ予防保守の一環。'
) RETURNING id INTO qid;

-- Q341: 是正保守
VALUES (28, 341, 'choice', 1, 1,
  '運用中に発見された欠陥（バグ）を修正するために実施する保守を何というか。',
  '是正保守（corrective maintenance）は稼働中のシステムに存在する欠陥を取り除く保守。バグ修正・障害対応が代表例。保守の種類（是正・改良・予防・適応）の中でも最も緊急性が高い場合がある。'
) RETURNING id INTO qid;

-- Q342: 改良保守
VALUES (28, 342, 'choice', 1, 1,
  'ユーザの要求に応じて、既存システムに新機能を追加したり性能を向上させたりする保守を何というか。',
  '改良保守（perfective maintenance）は機能追加・性能改善・操作性向上など、ユーザの要求や利便性向上を目的とした保守。完全化保守とも呼ばれる。'
) RETURNING id INTO qid;

-- Q343: 予防保守
VALUES (28, 343, 'choice', 1, 1,
  '将来発生しうる問題を未然に防ぐために、現時点では問題のないシステムに対して予防的に実施する保守を何というか。',
  '予防保守（preventive maintenance）は将来の障害や品質劣化を防ぐために行う保守。技術的負債の解消・ドキュメント整備・老朽化部品の計画的交換などが該当する。'
) RETURNING id INTO qid;

-- Q344: 適応保守
VALUES (28, 344, 'choice', 1, 1,
  'OSやハードウェアのバージョンアップ、法律・規制の変更など、外部環境の変化に対応するために実施する保守を何というか。',
  '適応保守（adaptive maintenance）は外部環境の変化（OS・DB・ミドルウェアのバージョンアップ、税率変更、法規制改正など）に対応するための保守。機能そのものは変えないが、動作環境に合わせた改修を行う。'
) RETURNING id INTO qid;

-- Q345: 完全化保守
VALUES (28, 345, 'choice', 1, 1,
  'ユーザの要求や利便性向上のために機能追加・性能改善を行う保守の別称として、JIS規格で使われる用語は何か。',
  '完全化保守（perfective maintenance）は改良保守の別称で、JIS X 0161などで使われる用語。ユーザ要求に応じた機能追加・性能向上・操作性改善などを目的とした保守を指す。'
) RETURNING id INTO qid;

-- Q346: オンサイト保守
VALUES (28, 346, 'choice', 1, 1,
  '保守担当者がシステムの設置場所に直接出向いて保守作業を実施する方式を何というか。',
  'オンサイト保守（on-site maintenance）は保守員が現地に赴いて作業する方式。部品交換・現地確認が必要な場合や遠隔保守が困難な場合に採用される。対義語は遠隔保守（リモート保守）。'
) RETURNING id INTO qid;

-- Q347: 遠隔保守
VALUES (28, 347, 'choice', 1, 1,
  'ネットワークを通じて遠隔地から保守作業（ソフトウェア更新・障害対応・監視など）を実施する保守方式を何というか。',
  '遠隔保守（remote maintenance）はリモートアクセスでサーバやシステムを管理する方式。コスト削減・即時対応が可能だが、セキュリティ対策（VPN・多要素認証）が重要。'
) RETURNING id INTO qid;

-- Q348: ライフサイクルの評価
VALUES (28, 348, 'choice', 1, 1,
  'システムが計画・開発・運用・保守・廃棄という全段階にわたって品質・コスト・スケジュールなどの観点から適切に管理されているかを評価することを何というか。',
  'ライフサイクルの評価（lifecycle evaluation）はシステムの誕生から廃棄までの全フェーズを通じた評価活動。総所有コスト（TCO）の観点や保守容易性・廃棄容易性の評価が含まれる。'
) RETURNING id INTO qid;

-- Q349: 開発プロセスからの保守に必要な成果物の引継ぎ
VALUES (28, 349, 'choice', 1, 1,
  '開発フェーズから保守フェーズへ移行する際に、保守担当者が保守を実施するために必要なドキュメント・ソースコード・テストケースなどを受け渡す活動を何というか。',
  '開発プロセスからの保守に必要な成果物の引継ぎは、設計書・仕様書・ソースコード・テスト資産などを保守チームへ移管する活動。引継ぎが不十分だと保守品質が低下し、属人化が生じる。'
) RETURNING id INTO qid;

-- Q350: 計画及び手続の作成
VALUES (28, 350, 'choice', 1, 1,
  '保守活動を組織的かつ効率的に実施するために、保守計画書と各種作業手続を整備する活動を何というか。',
  '計画及び手続の作成（planning and procedures development）は保守の範囲・体制・スケジュール・手続を文書化する活動。変更管理・問題管理・リリース管理などの手続が含まれる。'
) RETURNING id INTO qid;

-- Q351: 問題管理手続の確立
VALUES (28, 351, 'choice', 1, 1,
  '保守フェーズで発生した問題（障害・不具合・要望）を受付から解決・クローズまで一貫して追跡・管理する仕組みを整備することを何というか。',
  '問題管理手続の確立（problem management procedure establishment）は問題の受付・分類・優先付け・担当者割当て・解決・記録のプロセスを定め、ITILなどのフレームワークに基づいて整備する活動。'
) RETURNING id INTO qid;

-- Q352: 保守のための文書作成
VALUES (28, 352, 'choice', 1, 1,
  '保守活動の実施内容・変更内容・手順などを記録した文書を整備・更新する活動を何というか。',
  '保守のための文書作成（maintenance documentation）は変更履歴・作業ログ・更新された設計書・手順書などを整備する活動。ドキュメントが最新に保たれることで保守の継続性・引継ぎ品質が向上する。'
) RETURNING id INTO qid;

-- Q353: 問題報告又は修正依頼の分析
VALUES (28, 353, 'choice', 1, 1,
  '受け付けた問題報告や修正依頼を精査し、影響範囲・原因・対応優先度などを明確化する作業を何というか。',
  '問題報告又は修正依頼の分析は変更要求の内容を詳細に調査し、対応の必要性・リスク・コスト・スケジュール影響などを評価する活動。分析結果を基に対応方針が決定される。'
) RETURNING id INTO qid;

-- Q354: 問題の再現又は検証
VALUES (28, 354, 'choice', 1, 1,
  '報告された問題が実際に存在することを確認するために、問題を再現させるか検証する作業を何というか。',
  '問題の再現又は検証（problem reproduction or verification）は報告された不具合をテスト環境で再現し、問題の存在・内容・再現条件を確認する作業。修正に入る前に問題を正確に把握するために行う。'
) RETURNING id INTO qid;

-- Q355: 修正実施の選択肢の用意
VALUES (28, 355, 'choice', 1, 1,
  '問題を修正するための複数の対応方法を検討し、それぞれのコスト・リスク・効果を比較できる状態にする活動を何というか。',
  '修正実施の選択肢の用意（modification implementation options）は即時修正・次リリースで対応・回避策の提供など複数の対応方法を列挙し比較検討できるように準備する活動。'
) RETURNING id INTO qid;

-- Q356: 修正するシステム及び／又はソフトウェアや関連文書の決定
VALUES (28, 356, 'choice', 1, 1,
  '問題修正のために変更が必要なシステム・ソフトウェアコンポーネント・ドキュメントを特定して決定する作業を何というか。',
  '修正するシステム及び／又はソフトウェアや関連文書の決定は、修正実施選択肢から方針を決定した後に変更対象（ソースコード・設計書・テストケース・ユーザマニュアルなど）を特定する作業。'
) RETURNING id INTO qid;

-- Q357: 機能追加
VALUES (28, 357, 'choice', 1, 1,
  '既存システムに新たな機能を追加する保守活動を何というか。',
  '機能追加（function addition）は利用者の要求や業務拡張に対応して既存システムに新しい機能を加える保守。改良保守・完全化保守の一種。既存機能への影響を考慮した設計と回帰テストが必要。'
) RETURNING id INTO qid;

-- Q358: 性能改良
VALUES (28, 358, 'choice', 1, 1,
  '既存システムの応答時間・スループット・資源効率などを向上させる保守活動を何というか。',
  '性能改良（performance improvement）はシステムの処理速度・スループット・メモリ使用量などを改善する保守。SQLチューニング・キャッシュ導入・アルゴリズム改善などが手段として用いられる。'
) RETURNING id INTO qid;

-- Q359: 問題の是正
VALUES (28, 359, 'choice', 1, 1,
  '保守フェーズで発見された問題（欠陥・不具合・ドキュメント誤りなど）を修正して正しい状態に戻す活動を何というか。',
  '問題の是正（problem correction）は是正保守の中心的な活動で、特定された問題の根本原因を除去し、システムを要件に適合した状態に戻す作業。修正後の確認テスト・回帰テストと一体で実施する。'
) RETURNING id INTO qid;

-- Q360: 双方向の追跡可能性
VALUES (28, 360, 'choice', 1, 1,
  '要求仕様から設計・実装・テストケースへの前向きの対応関係と、逆向きの対応関係の両方が追跡できる性質を何というか。',
  '双方向の追跡可能性（bidirectional traceability）は要求→設計→実装→テストの前向き追跡と、テスト→実装→設計→要求への逆向き追跡の両方が維持される性質。変更影響分析・要求カバレッジ確認に不可欠。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q361: 移行計画の文書化と検証
VALUES (28, 361, 'choice', 1, 1,
  '旧システムから新システムへの移行手順・スケジュール・役割分担などを文書にまとめ、その計画が実施可能かを事前に確認する活動を何というか。',
  '移行計画の文書化と検証は移行の手順・タイムライン・担当者・リスク・ロールバック計画などを記した移行計画書を作成し、レビューや予行演習で実施可能性を確認する活動。'
) RETURNING id INTO qid;

-- Q362: 関係者全員への移行計画などの通知
VALUES (28, 362, 'choice', 1, 1,
  'システム移行の実施前に、移行スケジュール・影響範囲・手順などを利用者・運用担当者・経営者など関係者全員に周知する活動を何というか。',
  '関係者全員への移行計画などの通知は移行に関わる全ステークホルダーに対して移行日程・サービス停止時間・影響範囲・問い合わせ先などを事前に告知する活動。周知不足は混乱や信頼失墜を招く。'
) RETURNING id INTO qid;

-- Q363: 新旧環境の並行運用と旧環境の停止
VALUES (28, 363, 'choice', 1, 1,
  '移行期間中に新旧のシステムを同時に稼働させてリスクを低減し、問題がないことを確認した後に旧システムを停止する移行方式を何というか。',
  '新旧環境の並行運用と旧環境の停止（parallel operation and old system shutdown）は移行リスクを最小化するための方式。新システムの安定稼働が確認されるまで旧システムをバックアップとして維持する。'
) RETURNING id INTO qid;

-- Q364: 関係者全員への移行の通知
VALUES (28, 364, 'choice', 1, 1,
  'システム移行が完了した後に、関係者全員に対して移行完了・新システムの利用開始・旧システムの停止などを通知する活動を何というか。',
  '関係者全員への移行の通知は移行完了後に全ステークホルダーへ新システムの稼働開始・旧システム停止・問い合わせ先などを正式に告知する活動。事後通知を適切に行うことで混乱を防ぐ。'
) RETURNING id INTO qid;

-- Q365: 移行結果の検証
VALUES (28, 365, 'choice', 1, 1,
  'システム移行完了後に、データ・機能・性能などが移行計画通りに正しく移行されたことを確認する活動を何というか。',
  '移行結果の検証（migration result verification）はデータ件数・整合性・機能動作・性能などを確認し移行が成功したことを証明する活動。不整合が発見された場合はロールバックや修正対応を行う。'
) RETURNING id INTO qid;

-- Q366: 移行評価
VALUES (28, 366, 'choice', 1, 1,
  'システム移行プロジェクト全体を振り返り、移行計画・実施プロセス・結果の達成度を評価する活動を何というか。',
  '移行評価（migration evaluation）は移行プロジェクトの計画対比・問題点・改善点・コスト・スケジュール達成度などを総合的に評価し、今後の移行プロジェクトの参考とする活動。'
) RETURNING id INTO qid;

-- Q367: 旧環境関連データの保持と安全性確保
VALUES (28, 367, 'choice', 1, 1,
