DO $$
DECLARE
  qid integer;
BEGIN

-- Q46: パーミッション要求
VALUES (29, 46, 'choice', 1, 1,
  'モバイルアプリがカメラ・位置情報・連絡先などのリソースにアクセスするためにユーザに許可を求めるダイアログや仕組みを何というか。',
  'パーミッション要求（permission request）はOSがアプリのリソースアクセスをユーザの同意に基づいて制御する仕組み。Android・iOSともに実行時パーミッションで最小権限の原則を実現する。'
) RETURNING id INTO qid;

-- Q47: アプリケーションソフトウェア審査
