) RETURNING id INTO qid;

-- Q95: 類推見積り
VALUES (30, 95, 'choice', 1, 1,
  '過去の類似プロジェクトの実績値を参考にして、現在のプロジェクトのコストや期間を見積もる手法を何というか。',
  '類推見積り（analogous estimation）はトップダウン見積りの一種。少ない情報でも概算が可能だが精度が低い。プロジェクト初期段階や詳細情報が不足している場合に使われる。'
) RETURNING id INTO qid;

-- Q96: パラメトリック見積り
VALUES (30, 96, 'choice', 1, 1,
  '統計的関係を用いて作業量パラメータ（行数・機能点数・重量など）からコストや期間を算出する見積り手法を何というか。',
  'パラメトリック見積り（parametric estimation）はFP法・LOC法・COCOMOなどが代表例。過去のデータから導いた数式でコスト・期間を計算する。類推見積りより精度が高い場合が多い。'
) RETURNING id INTO qid;

-- Q97: 三点見積り
VALUES (30, 97, 'choice', 1, 1,
  '楽観値・最可能値・悲観値の3つを使って期待値と不確かさを見積もる手法を何というか。',
  '三点見積り（three-point estimation）はβ分布を使うPERT見積り（(楽観+4×最可能+悲観)/6）と三角分布を使う手法がある。リスクを考慮した見積りが可能。'
) RETURNING id INTO qid;

-- Q98: ボトムアップ見積り
VALUES (30, 98, 'choice', 1, 1,
  'WBSの最下位レベルの作業（ワークパッケージ・アクティビティ）ごとに個別に見積もり、積み上げて全体の見積りとする手法を何というか。',
  'ボトムアップ見積り（bottom-up estimation）は最も精度が高い見積り手法だが、時間とコストがかかる。詳細なWBSが前提となる。プロジェクトの計画フェーズで使われる。'
) RETURNING id INTO qid;

-- Q99: スケジュールネットワーク分析
VALUES (30, 99, 'choice', 1, 1,
  'スケジュールネットワーク図を使って早期開始日・最遅開始日・フロートを算出しクリティカルパスを特定する手法を何というか。',
  'スケジュールネットワーク分析（schedule network analysis）はCPM・PERT・資源平準化などを含む分析技法の総称。クリティカルパス・フロート・スケジュール圧縮の計算に使われる。'
) RETURNING id INTO qid;

-- Q100: PERT
VALUES (30, 100, 'choice', 1, 1,
  '楽観値・最可能値・悲観値を使ってアクティビティの期待所要時間を計算し、確率的なスケジュール分析を行う手法を何というか。',
  'PERT（Program Evaluation and Review Technique）は期待値=(楽観+4×最可能+悲観)/6で計算する。不確実性が高いプロジェクトのスケジュール分析に適している。'
) RETURNING id INTO qid;

-- Q101: CPM
VALUES (30, 101, 'choice', 1, 1,
  'プロジェクトネットワーク上でフロートが0の最長経路を特定し、プロジェクト全体の最短完了期間を求める手法を何というか。',
  'CPM（Critical Path Method）はネットワーク図の全経路の所要時間を計算してクリティカルパスを特定する。クリティカルパスの活動が遅れるとプロジェクト全体が遅れる。'
) RETURNING id INTO qid;

-- Q102: アローダイアグラム
VALUES (30, 102, 'choice', 1, 1,
  '活動を矢線（アロー）で表し、ノードで結合してプロジェクトの作業順序と依存関係を表したネットワーク図を何というか。',
  'アローダイアグラム（arrow diagram method / ADM）はPERT図とも呼ばれる。矢線が活動、ノードが活動間の依存点を表す。ダミー活動（破線）で論理的依存を表現する。'
) RETURNING id INTO qid;

-- Q103: ガントチャート
VALUES (30, 103, 'choice', 1, 1,
