-- Q60: 需要
VALUES (31, 60, 'choice', 1, 1,
  'ユーザ・顧客がサービスや処理能力に対して必要とする量や要求の大きさを何というか。',
  '需要（demand）は業務量・アクセス数・トランザクション数などで表現される。需要管理ではピーク時の需要を予測・平準化することでキャパシティの効率的な活用を図る。'
) RETURNING id INTO qid;

-- Q61: 需要管理
VALUES (31, 61, 'choice', 1, 1,
  'ユーザのサービス需要を把握・予測し、需要とキャパシティのバランスを取ることでサービスレベルを維持する活動を何というか。',
  '需要管理（demand management）は業務パターン分析・需要予測・負荷平準化施策（ピーク時間帯の分散等）でキャパシティと需要を整合させる。キャパシティ管理と密接に連携する。'
) RETURNING id INTO qid;

-- Q62: 需要予測
VALUES (31, 62, 'choice', 1, 1,
  '過去の利用実績・業務計画・ビジネス動向を基に将来のサービス需要量を推定する活動を何というか。',
  '需要予測（demand forecasting）はキャパシティ計画の入力情報。季節変動・業務イベント・新規プロジェクト・ビジネス成長率などを考慮して将来の処理能力要件を見積もる。'
) RETURNING id INTO qid;

-- Q63: キャパシティ
VALUES (31, 63, 'choice', 1, 1,
  'システムやサービスが処理できる最大の作業量・処理能力・保存容量などのリソースの処理能力上限を何というか。',
  'キャパシティ（capacity）はCPU・メモリ・ストレージ・ネットワーク帯域などの資源の処理能力。需要がキャパシティを超えると性能劣化・障害が発生するため、計画的な管理が必要。'
) RETURNING id INTO qid;

-- Q64: キャパシティ計画
VALUES (31, 64, 'choice', 1, 1,
  '現在と将来の需要を満たすために必要な処理能力（CPU・メモリ・ストレージ等）の増強・最適化の計画を策定する活動を何というか。',
  'キャパシティ計画（capacity planning）は需要予測に基づいて将来のリソース要件を計算し、拡張・縮小のタイミングとコストを計画する。クラウドの自動スケーリングもキャパシティ計画の実装形態。'
) RETURNING id INTO qid;

-- Q65: キャパシティ管理
VALUES (31, 65, 'choice', 1, 1,
  'サービスの需要に対して適切な処理能力を確保し、コスト効率よくサービスレベルを維持するプロセスを何というか。',
  'キャパシティ管理（capacity management）はビジネスキャパシティ・サービスキャパシティ・コンポーネントキャパシティの3つのレベルで管理する。監視・予測・計画・調整のサイクルで運用する。'
) RETURNING id INTO qid;

-- Q66: 監視
VALUES (31, 66, 'choice', 1, 1,
  'サービスや構成品目のパフォーマンス・可用性・セキュリティ状態をリアルタイムまたは定期的に測定・観察する活動を何というか。',
  '監視（monitoring）はサービスマネジメントの基盤活動。サーバCPU・メモリ・ネットワーク・アプリログなどを継続的に収集・分析し、しきい値超過時にアラートを発する。'
) RETURNING id INTO qid;

-- Q67: しきい値
VALUES (31, 67, 'choice', 1, 1,
  '監視において、この値を超えた場合に警告・アラートを発生させるパフォーマンス指標の境界値を何というか。',
  'しきい値（threshold）はCPU使用率80%・ディスク残量20%未満など監視で設定する境界値。適切なしきい値設定でSLA違反前に問題を検知し、予防的な対処を可能にする。'
) RETURNING id INTO qid;

-- Q68: 管理指標
VALUES (31, 68, 'choice', 1, 1,
  'サービスやプロセスの状態を評価・管理するために定義・測定・追跡する定量的な尺度を何というか。',
  '管理指標（metric）は稼働率・MTBF・MTTR・インシデント件数・解決時間など。KPI・SLIとして使われる。有意な指標を設定して意思決定に活用することがサービスマネジメントの基本。'
) RETURNING id INTO qid;

-- Q69: 変更管理（サービスマネジメント）
VALUES (31, 69, 'choice', 1, 1,
  'サービスや構成品目への変更を記録・評価・承認・実施し、リスクを最小化しながら変更を安全に行うプロセスを何というか。',
  'サービスマネジメントの変更管理（change management）はCAB（変更諮問委員会）が変更を審査して承認する。標準変更・通常変更・緊急変更の3カテゴリで管理し、ロールバック計画を必須とする。'
) RETURNING id INTO qid;

-- Q70: 優先度
VALUES (31, 70, 'choice', 1, 1,
  'インシデント・問題・変更要求などを対応する順序を決定するために、影響度と緊急度をもとに付与するランクを何というか。',
  '優先度（priority）は「影響度×緊急度」で決定される。一般的に高・中・低または1〜4レベルで分類され、SLAの解決目標時間（SLO）と対応させて管理される。'
) RETURNING id INTO qid;

-- Q71: 変更のカテゴリー
VALUES (31, 71, 'choice', 1, 1,
  'サービスマネジメントの変更管理において、変更のリスクと影響度に基づいて分類される「標準変更」「通常変更」「緊急変更」などの区分を何というか。',
  '変更のカテゴリー（change category）は変更の審査プロセスと権限を決定する。標準変更は事前承認済みの低リスク変更、通常変更はCAB審査が必要、緊急変更は事後承認を含む迅速対応変更。'
) RETURNING id INTO qid;

-- Q72: ロールバック
VALUES (31, 72, 'choice', 1, 1,
  '変更実施後に問題が発生した場合に変更前の状態に戻すための手順を何というか。',
  'ロールバック（rollback）は変更管理の必須要素で、変更計画に含まれていなければならない。バックアップリストア・設定ファイル戻し・デプロイ取消などの手順を事前に準備し、テストしておく。'
) RETURNING id INTO qid;

-- Q73: 変更諮問委員会
VALUES (31, 73, 'choice', 1, 1,
  '変更要求の内容・リスク・影響を評価して承認可否を決定する委員会を何というか。',
  '変更諮問委員会（CAB: Change Advisory Board）はIT担当・ビジネス代表・セキュリティ担当などで構成される。緊急変更は権限委譲された小規模のECAB（緊急CAB）が審査することもある。'
) RETURNING id INTO qid;

-- Q74: 変更実施後のレビュー
VALUES (31, 74, 'choice', 1, 1,
  '変更を実施した後に、変更が計画通りに完了したか・問題が発生していないか・改善点はないかを確認する活動を何というか。',
  '変更実施後のレビュー（post-implementation review / PIR）は変更の成功・失敗を評価して教訓を次回の変更管理に活かす。インシデント発生率・SLA影響・ロールバック有無などを確認する。'
) RETURNING id INTO qid;

-- Q75: サービスの設計及び移行
VALUES (31, 75, 'choice', 1, 1,
  '新規サービスまたは変更されたサービスを設計・開発・テストして本番環境への移行を計画・実施するプロセス群を何というか。',
  'サービスの設計及び移行（design and transition of new or changed services）はJIS Q 20000の要求プロセス。計画→設計・開発→移行のフローで安全に新サービスを本番投入する。'
) RETURNING id INTO qid;

-- Q76: 新規サービス又はサービス変更の計画
VALUES (31, 76, 'choice', 1, 1,
  '新しいサービスや変更されたサービスの設計・開発・移行に必要なリソース・スケジュール・リスク・受入れ基準を定める計画活動を何というか。',
  '新規サービス又はサービス変更の計画は設計及び移行プロセスの最初のステップ。スコープ・リソース・期間・リスク・テスト計画・受入れ基準・ロールバック計画を含む移行計画書を作成する。'
) RETURNING id INTO qid;

-- Q77: サービス受入れ基準
VALUES (31, 77, 'choice', 1, 1,
  '新規または変更されたサービスが本番環境への移行を許可されるために満たすべき条件・テスト合格基準を何というか。',
  'サービス受入れ基準（SAC: Service Acceptance Criteria）は機能要件・非機能要件・セキュリティ・ドキュメント・運用手順の整備などの条件を定める。受入れテストで基準を満たすことを確認する。'
) RETURNING id INTO qid;

-- Q78: 設計・開発
VALUES (31, 78, 'choice', 1, 1,
  'サービスの要求事項に基づいてサービスのアーキテクチャ・コンポーネント・プロセスを設計し、実装・構築する活動を何というか。',
  '設計・開発（design and development）はサービスマネジメントの文脈では機能・非機能要件を満たすサービスを設計し、テスト可能な形で構築する活動。サービス設計書が主要成果物。'
) RETURNING id INTO qid;

-- Q79: サービス設計書
VALUES (31, 79, 'choice', 1, 1,
  'サービスの機能・コンポーネント・インタフェース・インフラ・プロセス・SLAなどをまとめたサービスの設計仕様文書を何というか。',
  'サービス設計書（service design package）はサービスの全設計情報を含む文書。移行チームがサービスを本番環境に正しく展開するための詳細仕様書として機能する。'
) RETURNING id INTO qid;

-- Q80: 非機能要件
VALUES (31, 80, 'choice', 1, 1,
  'サービスが実現すべき機能以外の品質特性（可用性・性能・セキュリティ・拡張性・保守性など）に関する要件を何というか。',
  '非機能要件（non-functional requirements）はサービス受入れ基準・SLAの基礎となる。JIS Q 25010の品質特性モデルが参考になる。機能要件と同様に明確に定義・合意することが重要。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q81: 構築
VALUES (31, 81, 'choice', 1, 1,
  'サービス設計書に基づいてサービスコンポーネントを実際に組み上げ、テスト可能な状態にする活動を何というか。',
  '構築（build）はサービス設計及び移行プロセスの一部。ソフトウェア開発・インフラ設定・連携テストなどを経て本番移行前のステージング環境で動作確認できる状態を作る。'
) RETURNING id INTO qid;

-- Q82: 移行
VALUES (31, 82, 'choice', 1, 1,
  'テスト済みのサービスを本番環境に展開し、安全に稼働状態に移すプロセスを何というか。',
  'サービス移行（service transition）は移行計画に基づいて実施される。並行運用・段階移行・一括移行などの方式があり、移行リハーサル・移行判断・運用引継ぎを経て完了する。'
) RETURNING id INTO qid;

-- Q83: 運用サービス基準
VALUES (31, 83, 'choice', 1, 1,
  '移行後にサービスを本番運用するために必要な運用手順・監視基準・サポート体制などの条件を定めた基準を何というか。',
  '運用サービス基準（operational service criteria）は移行完了の判断基準の一つ。運用手順書・サポート体制・監視設定・バックアップ手順などが整備されていることを確認する。'
) RETURNING id INTO qid;

-- Q84: 業務及びシステムの移行
VALUES (31, 84, 'choice', 1, 1,
  '新サービス・新システムへの切替えに際して、旧業務プロセスと旧システムを新環境へ安全に移す一連の活動を何というか。',
  '業務及びシステムの移行（business and system transition）はデータ移行・業務プロセス変更・ユーザトレーニング・旧システム廃止を含む包括的な移行活動。移行計画に基づいて実施される。'
) RETURNING id INTO qid;

-- Q85: 移行計画
VALUES (31, 85, 'choice', 1, 1,
  '新サービスを本番環境へ移行するためのスケジュール・手順・担当者・ロールバック計画・通知方法を定めた文書を何というか。',
  '移行計画（transition plan）は移行の全工程を詳細に規定する文書。移行リハーサルで検証し、移行判断基準を満たした後に実施される。ステークホルダへの通知方法も含む。'
) RETURNING id INTO qid;

-- Q86: 移行リハーサル
VALUES (31, 86, 'choice', 1, 1,
  '本番移行前にステージング環境などで移行手順を実際に試行し、問題点を洗い出す事前演習を何というか。',
  '移行リハーサル（transition rehearsal）は移行計画の実行可能性を検証する重要な活動。リハーサルで発見した問題を修正してから本番移行に臨むことで移行失敗のリスクを低減する。'
) RETURNING id INTO qid;

-- Q87: 移行判断
VALUES (31, 87, 'choice', 1, 1,
  '移行リハーサルの結果とサービス受入れ基準を照合して、本番移行を実施してよいかを公式に決定する判断活動を何というか。',
  '移行判断（go/no-go decision）は受入れ基準の達成状況・未解決問題・リスク評価を総合して判断する重要なゲートウェイ。移行責任者が最終決定を行い、Go/No-Goを宣言する。'
) RETURNING id INTO qid;

-- Q88: 移行の通知
VALUES (31, 88, 'choice', 1, 1,
  '新サービスや変更されたサービスの移行スケジュール・影響範囲・手順などを関係者に事前または事後に知らせる活動を何というか。',
  '移行の通知（transition notification）は移行前のサービス停止予告・影響範囲通知や移行完了後の稼働開始通知などを含む。適切な通知によりユーザの混乱を防ぐ。'
) RETURNING id INTO qid;

-- Q89: 移行評価
VALUES (31, 89, 'choice', 1, 1,
  '移行完了後にプロセス・成果・問題点を振り返り、移行活動の有効性と改善点を評価する活動を何というか。',
  '移行評価（transition evaluation）は移行計画通りに完了したか・SLAへの影響・未解決問題・教訓を評価する。次回の移行計画改善に活かす組織学習の機会でもある。'
) RETURNING id INTO qid;

-- Q90: 運用テスト
VALUES (31, 90, 'choice', 1, 1,
  '本番移行前に運用担当者が実際の運用手順（起動・停止・バックアップ・障害対応等）を確認するテストを何というか。',
  '運用テスト（operational test）は開発者ではなく運用担当者の視点でシステムの運用可能性を検証する。運用マニュアル・監視設定・バックアップ・リストア手順の正確性を確認する。'
) RETURNING id INTO qid;

-- Q91: 受入れテスト
VALUES (31, 91, 'choice', 1, 1,
  '顧客または顧客の代理人がサービス受入れ基準に基づいてサービスを評価し、本番移行の可否を確認するテストを何というか。',
  '受入れテスト（acceptance test）はサービス受入れ基準を満たすかを顧客視点で確認する最終テスト。UAT（User Acceptance Test）とも呼ばれ、合格後にサービスの本番利用が開始される。'
) RETURNING id INTO qid;

-- Q92: 運用引継ぎ
VALUES (31, 92, 'choice', 1, 1,
  '新サービスの移行完了後に開発・移行チームから運用チームへ運用責任を正式に引き渡す活動を何というか。',
  '運用引継ぎ（operational handover）は運用手順書・監視設定・既知の問題・サポート体制などを運用チームに移管する活動。引継ぎが不完全だと移行後の障害対応に支障をきたす。'
) RETURNING id INTO qid;

-- Q93: リリース及び展開管理
VALUES (31, 93, 'choice', 1, 1,
  '本番環境への変更をパッケージ化（リリース）して、計画的にシステムに適用（展開）するプロセスを何というか。',
  'リリース及び展開管理（release and deployment management）はリリース単位でのパッケージング・テスト・承認・スケジューリング・展開・検証を管理する。変更管理と密接に連携する。'
) RETURNING id INTO qid;

-- Q94: リリース
VALUES (31, 94, 'choice', 1, 1,
  '関連する変更を一つの単位にまとめて本番環境に展開するためにパッケージ化された変更の集合体を何というか。',
  'リリース（release）は複数の変更を同時に本番環境に適用するためのパッケージ。メジャーリリース・マイナーリリース・緊急リリースなどの種類があり、リリース受入れ基準を満たす必要がある。'
) RETURNING id INTO qid;

-- Q95: 展開
VALUES (31, 95, 'choice', 1, 1,
  '承認されたリリースを実際に本番環境のサービスコンポーネントに適用・配置する作業を何というか。',
  '展開（deployment）はリリースを本番環境に適用する技術的な作業。ローリングデプロイ・ブルーグリーンデプロイ・カナリアリリースなどの方式がある。展開後の動作確認が重要。'
) RETURNING id INTO qid;

-- Q96: リリースの受入れ基準
VALUES (31, 96, 'choice', 1, 1,
  'リリースを本番環境に展開するために満たすべきテスト・品質・ドキュメントなどの条件を何というか。',
  'リリースの受入れ基準（release acceptance criteria）はすべてのテストの合格・既知の問題の整理・ロールバック手順の確認・運用手順書の整備などの条件を定める。基準未達ではリリースは許可されない。'
) RETURNING id INTO qid;

-- Q97: 受入れ試験環境
VALUES (31, 97, 'choice', 1, 1,
  '本番環境と同等の構成でリリース候補の最終テスト・受入れテストを実施するために用意された環境を何というか。',
  '受入れ試験環境（acceptance test environment）はステージング環境とも呼ばれ、本番と近似した設定でリリース候補を検証する。本番データを使ったテストが必要な場合は匿名化して利用する。'
) RETURNING id INTO qid;

-- Q98: 稼働環境
VALUES (31, 98, 'choice', 1, 1,
  'リリースが展開されて実際のユーザが利用するサービスが稼働している本番の環境を何というか。',
  '稼働環境（production environment / live environment）はエンドユーザが直接使用する本番システム環境。変更は変更管理・リリース管理プロセスを経た後のみ適用できる。'
) RETURNING id INTO qid;

-- Q99: インシデント管理
VALUES (31, 99, 'choice', 1, 1,
  'サービスの中断または品質低下（インシデント）を可能な限り迅速に解決してサービスを正常な状態に復旧するプロセスを何というか。',
  'インシデント管理（incident management）はサービス中断の影響を最小化することを最優先目的とする。記録→優先度設定→エスカレーション→解決→クローズのフローで管理する。'
) RETURNING id INTO qid;

-- Q100: インシデント
VALUES (31, 100, 'choice', 1, 1,
  '計画されていないサービスの中断またはサービス品質の低下を引き起こす事象を何というか。',
  'インシデント（incident）はサーバ障害・ネットワーク障害・アプリケーションエラーなどサービスに影響を与える事象。問題（根本原因の調査対象）とは区別され、迅速な復旧を優先する。'
) RETURNING id INTO qid;

-- Q101: 記録
VALUES (31, 101, 'choice', 1, 1,
  'インシデント管理においてサービスに影響を与える事象の発生・状況・対応・解決の経緯を残す活動を何というか。',
  'インシデントの記録（logging / recording）はインシデント管理の最初のステップ。発生日時・影響範囲・報告者・初期症状などを記録する。記録がなければ追跡・分析・SLA評価が不可能になる。'
) RETURNING id INTO qid;

-- Q102: 影響
VALUES (31, 102, 'choice', 1, 1,
  'インシデントや問題がビジネス・サービス・ユーザに与える被害の大きさを示す指標を何というか。',
  '影響（impact）はインシデントの優先度を決める要素の一つ。影響を受けるユーザ数・業務の重要度・SLA違反リスクなどで評価される。影響度と緊急度を掛け合わせて優先度が決まる。'
) RETURNING id INTO qid;

-- Q103: 解決目標時間
VALUES (31, 103, 'choice', 1, 1,
  'インシデントが発生してから解決完了までの目標時間としてSLAで合意した時間を何というか。',
  '解決目標時間（resolution target time）はインシデントの優先度ごとにSLAで定義される。例：優先度「高」は4時間以内解決など。SLIで計測してSLO達成状況を評価する。'
) RETURNING id INTO qid;

-- Q104: エスカレーション
VALUES (31, 104, 'choice', 1, 1,
