  'MTBF（Mean Time Between Failures）は「総稼働時間 ÷ 障害発生件数」で計算する。MTBFが大きいほど信頼性が高い。可用性 = MTBF / (MTBF + MTTR) の計算に使われる。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q121: MTTR
VALUES (31, 121, 'choice', 1, 1,
  'サービスや機器が障害から回復するまでの平均時間を示す指標を何というか。',
  'MTTR（Mean Time To Repair）は「総修復時間 ÷ 障害件数」で算出する平均修復時間。MTBF と合わせてサービスの信頼性を評価する指標として使われる。'
) RETURNING id INTO qid;

-- Q122: 事業継続計画
VALUES (31, 122, 'choice', 1, 1,
