) RETURNING id INTO qid;

-- Q145: ジョブの管理
VALUES (31, 145, 'choice', 1, 1,
  'バッチ処理や定期実行処理などの業務プログラムを計画・実行・監視・制御する活動を何というか。',
  'ジョブの管理は、業務プログラム（ジョブ）のスケジューリング、実行順序の制御、完了確認、エラー時の対応などを行う運用管理活動。ジョブスケジューラなどのツールを活用する。'
) RETURNING id INTO qid;

-- Q146: データ管理
VALUES (31, 146, 'choice', 1, 1,
  '組織が保有するデータの作成・保存・利用・廃棄を適切に管理する活動を何というか。',
  'データ管理は、データの品質・整合性・セキュリティ・アクセス制御・バックアップ・保管期間などを管理する活動。運用管理においてはバックアップや世代管理が特に重要な要素となる。'
) RETURNING id INTO qid;

-- Q147: 利用者の管理
VALUES (31, 147, 'choice', 1, 1,
  'システムにアクセスするユーザのアカウント・権限・認証情報などを適切に管理する活動を何というか。',
  '利用者の管理は、ユーザアカウントの登録・変更・削除、アクセス権限の付与・剥奪、パスワード管理などを行う運用管理活動。情報セキュリティ管理とも密接に関連する。'
) RETURNING id INTO qid;

-- Q148: AIOps
VALUES (31, 148, 'choice', 1, 1,
  'AIや機械学習を活用してIT運用の自動化・高度化を図るアプローチを何というか。',
  'AIOps（AI for IT Operations）は、AI・機械学習・ビッグデータ解析をIT運用に組み合わせ、ログ解析・異常検知・根本原因分析・予測的保守などを自動化・高度化する取り組み。'
) RETURNING id INTO qid;

-- Q149: 運用オペレーション
VALUES (31, 149, 'choice', 1, 1,
  'システムの日常的な稼働維持のために実施される操作・監視・作業の総称を何というか。',
  '運用オペレーションは、システムの起動・停止、ジョブ実行、ログ確認、異常対応などの日常的な運転業務全般を指す。オペレータが担当する現場レベルの作業が含まれる。'
) RETURNING id INTO qid;

-- Q150: スケジュール設計
VALUES (31, 150, 'choice', 1, 1,
  'バッチ処理や定期ジョブをいつ・どの順序で実行するかを事前に計画・設計する活動を何というか。',
  'スケジュール設計は、日次・月次などの定期ジョブや依存関係のある処理を整理し、実行時間帯・順序・優先度・リソース使用を計画する設計活動。業務ピーク時間との調整が重要。'
) RETURNING id INTO qid;

-- Q151: ジョブスケジューリング
VALUES (31, 151, 'choice', 1, 1,
  '設計されたスケジュールに基づき、ジョブ管理ツールを使って実際にジョブの実行を制御・管理する作業を何というか。',
  'ジョブスケジューリングは、ジョブスケジューラを用いて実際にジョブの起動・監視・依存関係制御・完了確認などを行う運用作業。スケジュール設計の実行フェーズに当たる。'
) RETURNING id INTO qid;

-- Q152: バックアップ
VALUES (31, 152, 'choice', 1, 1,
  'データやシステムを障害・損失に備えて複製・保存しておく作業を何というか。',
  'バックアップは、原本データの喪失・破損に備えて複製を別媒体や場所に保存しておく作業。フルバックアップ・差分バックアップ・増分バックアップなどの種別があり、RPO に応じた頻度で実施する。'
) RETURNING id INTO qid;

-- Q153: システムの監視と操作
VALUES (31, 153, 'choice', 1, 1,
  'システムの稼働状態やリソース使用状況を継続的に確認し、必要な操作を行う運用活動を何というか。',
  'システムの監視と操作は、CPU・メモリ・ネットワーク・ストレージなどの状態を監視ツールで常時確認し、異常検知時に操作・対処を行う活動。監視エージェントや監視サーバを活用する。'
) RETURNING id INTO qid;

-- Q154: アウトプットの管理
VALUES (31, 154, 'choice', 1, 1,
  'バッチ処理や帳票出力などのジョブ実行結果を適切に確認・配布・保管する管理活動を何というか。',
  'アウトプットの管理は、ジョブが生成したファイル・帳票・レポートなどの出力物を確認し、適切な宛先への配布・保管・廃棄を管理する活動。機密帳票の誤配送防止なども含まれる。'
) RETURNING id INTO qid;

-- Q155: ジョブの復旧と再実行
VALUES (31, 155, 'choice', 1, 1,
  'ジョブが途中で異常終了した場合に、原因を解消して処理を再開・再実行する手順を何というか。',
  'ジョブの復旧と再実行は、異常終了したジョブについて原因を調査・解消し、処理を再起動または再実行する運用手順。チェックポイントからの再開や、初めからの再実行など、ジョブの性質に応じた対応が必要。'
) RETURNING id INTO qid;

-- Q156: 運用支援ツール
VALUES (31, 156, 'choice', 1, 1,
  'システム運用の効率化・自動化を支援するために使用されるソフトウェアツールの総称を何というか。',
  '運用支援ツールは、ジョブスケジューラ・監視ツール・構成管理ツール・自動化ツール（Ansible等）など、運用業務を支援・自動化するソフトウェアの総称。運用コストの削減や品質向上に貢献する。'
) RETURNING id INTO qid;

-- Q157: 業務運用マニュアル
VALUES (31, 157, 'choice', 1, 1,
  '運用業務の手順・方法・ルールを文書化し、担当者が参照できるようにした文書を何というか。',
  '業務運用マニュアルは、日常的な運用作業・障害対応・バックアップ手順などを標準化・文書化した手引き書。担当者が変わっても一定品質の運用を維持するために重要。'
) RETURNING id INTO qid;

-- Q158: サービスデスク
VALUES (31, 158, 'choice', 1, 1,
  'ユーザからのITサービスに関する問合せ・インシデント・サービス要求を一元的に受け付ける窓口を何というか。',
  'サービスデスク（Service Desk）は、ユーザとITサービスプロバイダの間のSPOC（単一連絡窓口）として機能する組織・機能。ITIL においてもサービスオペレーションの中心的な機能として位置づけられる。'
) RETURNING id INTO qid;

-- Q159: SPOC
VALUES (31, 159, 'choice', 1, 1,
  'ユーザが問合せやサービス要求を行う際の唯一の接点となる窓口の概念を何というか。',
  'SPOC（Single Point of Contact: 単一連絡窓口）は、ユーザが問合せや障害報告を行う際に、一つの窓口に集約する概念。サービスデスクが SPOC として機能し、内部で適切な担当者へ振り分ける。'
) RETURNING id INTO qid;

-- Q160: コールセンター
VALUES (31, 160, 'choice', 1, 1,
  '電話を主な通信手段として、顧客からの問合せや注文・苦情などに対応する組織・施設を何というか。',
  'コールセンターは、電話（および関連チャネル）を使って顧客対応を専門に行う組織・施設。サービスデスクがITサービスのユーザ支援に特化するのに対し、コールセンターは一般的な顧客対応業務も含む広い概念。'
) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN

-- Q161: CTI
VALUES (31, 161, 'choice', 1, 1,
  'コンピュータと電話を統合し、着信時に顧客情報を画面に表示したり自動音声応答・振り分けを行う技術を何というか。',
  'CTI（Computer Telephony Integration）はコールセンターで広く活用される技術。着信番号から顧客情報をCRMと連携して即座に表示したり、IVR（自動音声応答）でコールを適切なエージェントへ振り分ける。'
) RETURNING id INTO qid;

-- Q162: FAQ
VALUES (31, 162, 'choice', 1, 1,
  'ユーザからよく寄せられる質問とその回答をまとめ、自己解決を促すための文書・Webページを何というか。',
  'FAQ（Frequently Asked Questions: よくある質問）は、サービスデスクやコールセンターへの問合せを減らすためのセルフサービス支援ツール。知識ベースの一形態として活用される。'
) RETURNING id INTO qid;

-- Q163: 応対マニュアル
VALUES (31, 163, 'choice', 1, 1,
  'コールセンターやサービスデスクのオペレータが顧客対応を行う際の言葉遣い・手順・エスカレーション基準などを定めた文書を何というか。',
  '応対マニュアルは、オペレータが一定品質の顧客対応を行えるよう、標準的な言葉遣い・対応手順・FAQ参照方法・問題対応フローなどを文書化したガイドライン。'
) RETURNING id INTO qid;

-- Q164: 知識ベース
VALUES (31, 164, 'choice', 1, 1,
  'インシデントの解決策・FAQ・運用ノウハウなどの情報を蓄積・整理し、オペレータや利用者が参照・検索できるデータベースを何というか。',
  '知識ベース（knowledge base）はサービスデスクの対応品質向上と解決時間短縮に貢献する。既知の誤りデータベース（KEDB）もその一形態。ITILの知識管理プロセスで管理される。'
) RETURNING id INTO qid;

-- Q165: 一次サポート
VALUES (31, 165, 'choice', 1, 1,
  'ユーザからの問合せを最初に受け付け、既知の解決策で対応を完結させるサービスデスクの第一線対応レベルを何というか。',
  '一次サポート（first-line support）は、サービスデスクオペレータが標準的なFAQ・知識ベースを参照して即座に解決する対応。解決できない場合は専門チーム（二次・三次サポート）にエスカレーションする。'
) RETURNING id INTO qid;

-- Q166: AIの活用
VALUES (31, 166, 'choice', 1, 1,
  'サービスデスクやコールセンターにおいて、チャットボット・自動応答・問合せ分類などにAIを取り入れて業務を効率化する取り組みを何というか。',
  'サービスマネジメントにおけるAIの活用は、チャットボットによる24時間対応・自然言語処理による問合せ自動分類・機械学習による障害予測など多岐にわたる。AIOpsとも密接に関連する。'
) RETURNING id INTO qid;

-- Q167: ファシリティマネジメント
VALUES (31, 167, 'choice', 1, 1,
  '建物・設備・環境などの物理的施設を組織の目的に最適化するための総合的な管理活動を何というか。',
  'ファシリティマネジメント（Facility Management）はITサービスの物理的基盤（データセンター・電気・空調・通信設備等）を管理する。ITIL ではサービスオペレーションの一部として位置づけられる。'
) RETURNING id INTO qid;

-- Q168: 施設管理
VALUES (31, 168, 'choice', 1, 1,
  'ITサービスを支えるデータセンター・サーバルームなどの物理的施設の安全・維持・運用を管理する活動を何というか。',
  '施設管理（facilities management）はファシリティマネジメントの実務側面。入退室管理・物理セキュリティ・設備点検・環境監視（温湿度・電力）などを含む。ビジネス継続性にも直接影響する。'
) RETURNING id INTO qid;

-- Q169: 建物管理
VALUES (31, 169, 'choice', 1, 1,
  'データセンターや事務所などの建物の構造・安全・維持保全を専門的に管理する活動を何というか。',
  '建物管理（building management）は施設管理の一領域で、建物の耐震性・防火・防水・清掃・修繕計画などを扱う。BMS（ビルマネジメントシステム）による自動制御・監視も含まれる。'
) RETURNING id INTO qid;

-- Q170: 電気設備
VALUES (31, 170, 'choice', 1, 1,
  'データセンターやサーバルームにおいて、安定した電力供給を実現するためのUPS・自家発電機・配電盤などの設備を何というか。',
  '電気設備は、ITサービスの継続稼働に不可欠なインフラ。UPS（無停電電源装置）・自家発電機・二重化電源などにより停電時でもサービスを維持できる構成を取る。ファシリティマネジメントの重要要素。'
) RETURNING id INTO qid;

-- Q171: 空調設備
VALUES (31, 171, 'choice', 1, 1,
