) RETURNING id INTO qid;

-- Q58: ソリューション
VALUES (33, 58, 'choice', 1, 1,
  '顧客の業務課題を解決するために，製品・サービス・コンサルティングを組み合わせて提供する総合的な解決策はどれか。',
  'ソリューションは，単なる製品販売ではなく，顧客課題に対して最適なシステム・サービス・運用を組み合わせて課題解決を実現するアプローチ。ソリューション営業・ソリューションプロバイダに関連する。'
) RETURNING id INTO qid;

-- Q59: ソリューションプロバイダ
