  VALUES (38, 40, 'choice', 1, 1,
    '多様性（Diversity）・公平性（Equity）・包括性（Inclusion）の3つを組み合わせ，誰もが活躍できる職場・社会を目指す考え方はどれか。',
    'DE&I（Diversity, Equity & Inclusion）は，性別・年齢・国籍・障がい・性的指向などの多様性を認め，機会の公平性と帰属意識（インクルージョン）を実現する経営・人事の考え方。'
  ) RETURNING id INTO qid;

  VALUES (38, 41, 'choice', 1, 1,
    '身体的・精神的・社会的に良好な状態を包括的に示す概念で，近年，企業経営や人事施策でも重視されるようになった言葉はどれか。',
    'ウェルビーイング（well-being）は，WHO憲章にある「健康」の定義にも含まれる広義の幸福状態。従業員の健康経営・エンゲージメント向上・生産性改善の観点から注目されている。'
  ) RETURNING id INTO qid;

  VALUES (38, 42, 'choice', 1, 1,
    '物事を筋道立てて考え，根拠に基づいて結論を導く思考法の総称はどれか。',
    'ロジカルシンキング（論理的思考）は，物事の構造を整理し，矛盾なく一貫した論拠で結論を導く思考スキル。MECEやロジックツリーを活用して問題分析・意思決定に用いる。'
  ) RETURNING id INTO qid;

  VALUES (38, 43, 'choice', 1, 1,
    '既存の知識・ルール・前提に沿って深く掘り下げていく，論理的・分析的な思考様式はどれか。',
    '垂直思考（縦の思考）は，ひとつの考えを深化させる収束型思考。一方，水平思考は既存の枠外に発散する手法。問題の詳細分析・論理的検証に適している。'
  ) RETURNING id INTO qid;

  VALUES (38, 44, 'choice', 1, 1,
    '既存の前提・枠組みにとらわれず，新しい視点・発想で問題に取り組む創造的な思考様式はどれか。',
    '水平思考（ラテラルシンキング）は，エドワード・デボノが提唱した発散的思考。常識・先入観を排除し，斬新なアイデアを生み出す。創造的問題解決・イノベーション創出に有効。'
  ) RETURNING id INTO qid;

  VALUES (38, 45, 'choice', 1, 1,
    '限られた情報・時間の中で仮の答えを立て，検証・修正を繰り返すことで素早く問題解決に近づく思考法はどれか。',
    '仮説思考は，まず仮説を立てて優先的に検証し，早期に答えに近づく思考スタイル。コンサルティングや新規事業開発など，時間・情報が制約された場面で特に有効。'
  ) RETURNING id INTO qid;

  VALUES (38, 46, 'choice', 1, 1,
    'ハーズバーグが提唱した，「満足要因（動機付け要因）」と「不満足要因（衛生要因）」の二要素で職務満足を説明する理論はどれか。',
    '衛生理論（二要因理論）は，給与・労働環境などの「衛生要因」はあっても当然で不満解消にすぎず，達成感・成長などの「動機付け要因」が真のモチベーション向上につながると説く。'
  ) RETURNING id INTO qid;

  VALUES (38, 47, 'choice', 1, 1,
    'マクレガーが提唱した，人間観を「X理論（性悪説：強制・管理が必要）」と「Y理論（性善説：自律的に働く）」に分けたマネジメント理論はどれか。',
    'XY理論は，マネジャーの人間観が管理スタイルに影響すると説く。X理論的な上司は統制・命令型に，Y理論的な上司は委任・自律支援型になる傾向がある。'
  ) RETURNING id INTO qid;

  VALUES (38, 48, 'choice', 1, 1,
    '事業継続計画（BCP）を継続的に維持・改善するための活動全体を指すマネジメントの仕組みはどれか。',
    'BCM（Business Continuity Management，事業継続マネジメント）は，BCPの策定・訓練・見直しを含むマネジメントシステム全体。JIS Q 22301で標準化されている。'
  ) RETURNING id INTO qid;

  VALUES (38, 49, 'choice', 1, 1,
    '事業継続マネジメントシステム（BCMS）に関する国際規格（ISO 22301）を日本語に翻訳・対応させたJIS規格はどれか。',
    'JIS Q 22301は，ISO 22301に対応するBCMSの要求事項規格。リスクアセスメント・BIA・BCP策定・訓練・レビューを体系的に管理する枠組みを定める。'
  ) RETURNING id INTO qid;

  VALUES (38, 50, 'choice', 1, 1,
    '災害・事故・停電などの緊急事態が発生した場合に，重要業務への影響を評価・定量化し，優先対策を決定するための分析手法はどれか。',
    '事業影響度分析（BIA：Business Impact Analysis）は，業務停止による損失規模・復旧優先度・目標復旧時間（RTO）・目標復旧ポイント（RPO）を定量化するBCP策定の基礎分析。'
  ) RETURNING id INTO qid;

END $$;
-- 企業活動 (section_id=38) Q51〜Q100
DO $$
DECLARE
  qid integer;
BEGIN

  VALUES (38, 51, 'choice', 1, 1,
    '命令系統が上位から下位へ一本の線で繋がり，職位の権限・責任が明確な伝統的な組織形態はどれか。',
    '階層型組織（ライン組織）は，トップから現場まで明確な指揮命令系統をもつ垂直構造。意思決定が速く指揮命令系統が明確だが，横断的な連携が取りにくい。'
