  ) RETURNING id INTO qid;

  VALUES (38, 67, 'choice', 1, 1,
    '本社・自宅以外に設置された共用の仕事場で，通勤負担の軽減やテレワーク推進のために活用される施設はどれか。',
    'サテライトオフィスは，企業が本社から離れた場所に設置する作業拠点。従業員の通勤時間短縮・地域での雇用創出・BCP対策にも活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 68, 'choice', 1, 1,
