  VALUES (38, 81, 'choice', 1, 1,
    'AIやビッグデータなどの先端技術を活用して都市機能全体を丸ごとデジタル化し，住民生活を最適化する未来都市モデルはどれか。',
    'スーパーシティ構想は，国家戦略特区法の改正により2020年に制度化。医療・移動・行政・教育・エネルギーなど複数分野を連携してデータ活用する次世代都市の実現を目指す。'
  ) RETURNING id INTO qid;

  VALUES (38, 82, 'choice', 1, 1,
    '数値データの分析手法・統計的アプローチ・業務改善モデルをビジネスに適用し，意思決定を支援する分野の総称はどれか。',
    '業務分析・データ利活用は，OR（オペレーションズリサーチ）・統計的品質管理・データサイエンスなどを活用して業務効率化・意思決定支援を行う分野の総称。'
  ) RETURNING id INTO qid;

  VALUES (38, 83, 'choice', 1, 1,
    '変数間の線形関係と制約条件のもとで目的関数（利益の最大化・コストの最小化など）を求める最適化手法はどれか。',
    '線形計画法（LP：Linear Programming）は，線形の目的関数と制約条件から最適解を求めるORの基本手法。シンプレックス法などで解かれ，生産計画・輸送問題・資源配分に活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 84, 'choice', 1, 1,
    '線形計画問題の最適解を求めるためのアルゴリズムで，実行可能領域の頂点を順に移動して最適値を見つける手法はどれか。',
    'シンプレックス法（単体法）は，ダンツィクが開発した線形計画法の代表的なアルゴリズム。実行可能多面体の頂点を基底解として移動しながら最適解を探索する。'
  ) RETURNING id INTO qid;

  VALUES (38, 85, 'choice', 1, 1,
    '限られた資源（予算・人員・設備など）を複数の用途に最適に割り当てることを目的とした線形計画モデルはどれか。',
    '配分問題は，資源の最適分配を扱う線形計画の典型問題。製品ミックス・予算配分・人員配置などで，目的関数と制約条件を定式化して最適解を求める。'
  ) RETURNING id INTO qid;

  VALUES (38, 86, 'choice', 1, 1,
    '複数の供給地から複数の需要地へ，輸送コストを最小化しながら製品を輸送するための線形計画モデルはどれか。',
    '輸送問題は，供給量・需要量の制約のもとで輸送コストを最小化する線形計画の一種。北西隅法・最小コスト法などの初期解法とステッピングストーン法などで最適解を求める。'
  ) RETURNING id INTO qid;

  VALUES (38, 87, 'choice', 1, 1,
    '需要変動・供給遅延などの不確実性に対応するために，通常の発注量とは別に余分に持つ在庫はどれか。',
    '安全在庫は，需要のばらつきや調達リードタイムの変動によって在庫切れが起きないよう，計算上必要な量を上回って保有する在庫。サービス率（在庫充足率）の目標値と標準偏差から算出する。'
  ) RETURNING id INTO qid;

  VALUES (38, 88, 'choice', 1, 1,
    '注文コストと保管コストの合計が最小になる，1回あたりの最適な発注量を求めるモデルはどれか。',
    'EOQ（Economic Order Quantity，経済的発注量）は，発注費用（注文コスト）と在庫保有費用（保管コスト）の合計を最小化する発注量を算出する在庫管理モデル。√(2DS/H) で求められる。'
  ) RETURNING id INTO qid;

  VALUES (38, 89, 'choice', 1, 1,
    '在庫が一定水準まで減少したときに発注を行うことで在庫切れを防ぐ，定量発注方式における発注開始の在庫量はどれか。',
    '発注点（ROP：Reorder Point）は，「調達リードタイム中の消費量 + 安全在庫」で求められる。在庫量が発注点を下回った時点で発注するため，調達期間中の在庫切れを防ぐ。'
  ) RETURNING id INTO qid;

  VALUES (38, 90, 'choice', 1, 1,
    '生産活動において，各作業の順序・タイミング・所要期間を計画し，納期や資源を管理するための計画はどれか。',
    '日程計画（スケジューリング）は，生産・プロジェクト管理でどの作業をいつ・どの順番で行うかを決める計画。ガントチャートやアローダイアグラムが活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 91, 'choice', 1, 1,
    'プロジェクトの各作業を矢印（→）で表し，作業の依存関係・所要時間・最早開始時刻などを図示するネットワーク図はどれか。',
    'アローダイアグラム（PERT図）は，結合点（ノード）と矢印（アクティビティ）でプロジェクトの作業順序を表すネットワーク図。クリティカルパス分析の基礎となる。'
  ) RETURNING id INTO qid;

  VALUES (38, 92, 'choice', 1, 1,
    'アローダイアグラムにおいて，プロジェクト開始から完了までの最長所要時間の経路で，遅延するとプロジェクト全体の納期が遅れる経路はどれか。',
    'クリティカルパスは，余裕時間（フロート）がゼロの経路で，プロジェクトの最短完了時間を決定する。クリティカルパス上の作業を重点管理することで全体の工期短縮が可能。'
  ) RETURNING id INTO qid;

  VALUES (38, 93, 'choice', 1, 1,
    '2人のプレイヤーが競い合い，一方の利得の合計が常にゼロになるゲーム理論の基本モデルはどれか。',
    'ゼロ和2人ゲームは，一方の利得が他方の損失に等しいゲーム（例：じゃんけん，チェス）。ミニマックス定理により，混合戦略最適解が必ず存在することをフォン・ノイマンが証明した。'
  ) RETURNING id INTO qid;

  VALUES (38, 94, 'choice', 1, 1,
    '不確実な状況において，最悪のシナリオで得られる最小の利得を最大化することで安全側の意思決定を行う原理はどれか。',
    'マクシミン原理（maximin）は，各戦略の最悪ケースの中から最も大きい利得を選ぶ保守的な意思決定基準。リスク回避型の判断に対応し，ゲーム理論・意思決定理論で用いられる。'
  ) RETURNING id INTO qid;

  VALUES (38, 95, 'choice', 1, 1,
    '意思決定の選択肢と各結果の確率・期待値を木構造で表し，最適な選択を視覚的に分析する手法はどれか。',
    'デシジョンツリー（決定木）は，分岐ノードに選択肢・確率ノードに不確実事象・葉ノードに結果を配置したツリー図。期待値計算で最適意思決定を導出する。機械学習の決定木とは別概念。'
  ) RETURNING id INTO qid;

  VALUES (38, 96, 'choice', 1, 1,
    '作業者の作業時間を直接測定・分析し，作業の標準時間を設定するための分析手法はどれか。',
    '作業時間分析法は，ストップウォッチ法（直接観測）などを用いて作業要素ごとの時間を測定し，標準時間（正味時間＋余裕時間）を設定する手法の総称。'
  ) RETURNING id INTO qid;

  VALUES (38, 97, 'choice', 1, 1,
    '人間の基本動作を要素動作に分解し，各要素に標準時間値を割り当てることで，実測なしに標準時間を設定する手法はどれか。',
    'PTS法（Predetermined Time Standards，既定時間標準法）は，人間の動作をTherblig（サーブリック）などの要素に分解し，統計的な標準時間値から作業時間を算出する手法。MTMなどが代表例。'
  ) RETURNING id INTO qid;

  VALUES (38, 98, 'choice', 1, 1,
    'ランダムな瞬間に作業者・機械の状態を観測し，統計的に稼働率・作業比率を推定する手法はどれか。',
    'ワークサンプリング法は，無作為な時点に観測を行い，稼働・非稼働・作業種類の割合を統計的に推定する。連続観測より低コストで，大規模現場や管理業務の分析に適している。'
  ) RETURNING id INTO qid;

  VALUES (38, 99, 'choice', 1, 1,
    'ギルブレスが提唱した，人間の手作業を「つかむ・運ぶ・組み合わせる」などの18種類の基本動作要素に分類したものはどれか。',
    'サーブリック（Therblig）は，フランクとリリアン・ギルブレス夫妻が動作研究で定義した18の基本動作記号。PTS法の基礎となっており，動作改善・工程分析に活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 100, 'choice', 1, 1,
    '製造・サービス現場の作業内容・動作・順序・時間などを調査・記録し，改善につなげる一連の活動はどれか。',
    '作業分析は，工程分析・動作分析・時間分析などの手法を用いて，作業の無駄・非効率を発見し，標準作業の設定や改善提案につなげる活動。IEの基本的な手法のひとつ。'
  ) RETURNING id INTO qid;

END $$;
-- 企業活動 (section_id=38) Q101〜Q150
DO $$
DECLARE
  qid integer;
BEGIN

  VALUES (38, 101, 'choice', 1, 1,
    '設備・機械の稼働状態・停止理由・稼働率などを測定・分析し，生産効率向上のための改善を行う活動はどれか。',
    '稼働分析は，設備や作業者が実際に価値を生み出している時間の割合（稼働率）と，待機・段取り・故障などの非稼働時間を測定して改善点を特定する活動。ワークサンプリング法で実施されることが多い。'
  ) RETURNING id INTO qid;

  VALUES (38, 102, 'choice', 1, 1,
    '抜取検査において，不良率の変化に対してロット合格確率がどのように変化するかを示す曲線はどれか。',
    'OC曲線（Operating Characteristic Curve，検査特性曲線）は，横軸に不良率，縦軸にロット合格確率をとったS字型の曲線。抜取検査の識別能力を評価するために用いる。'
  ) RETURNING id INTO qid;

  VALUES (38, 103, 'choice', 1, 1,
    '製造した製品のうち，規格外れ品（不良品）の割合を数値で表した指標はどれか。',
    '不良率は，不良品数÷生産総数で算出される品質指標。不良率の低下が品質改善の目標となり，管理図・パレート図などで監視・分析される。'
  ) RETURNING id INTO qid;

  VALUES (38, 104, 'choice', 1, 1,
