  VALUES (38, 167, 'choice', 1, 1,
    '容量（Volume）・速度（Velocity）・多様性（Variety）・正確性（Veracity）などの特性をもつ，従来のDBMSでは処理が困難な大規模データの総称はどれか。',
    'ビッグデータは，3V（Volume・Velocity・Variety）あるいは4V（+ Veracity）で定義される大規模・高速・多種多様なデータ。Hadoopやクラウドプラットフォームで分析基盤が整備されている。'
  ) RETURNING id INTO qid;

  VALUES (38, 168, 'choice', 1, 1,
    '政府・自治体・公的機関などが保有するデータを，誰でも自由に利用・再配布できる形式で公開したデータはどれか。',
    'オープンデータは，CC0やクリエイティブコモンズライセンスなど，利用・再利用・再配布が可能なライセンスで公開されたデータ。行政サービス改善・民間ビジネス創出・研究促進に活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 169, 'choice', 1, 1,
    '特定の個人を識別できる，または識別できる可能性のある情報（氏名・住所・生体情報・購買履歴など）の総称はどれか。',
    'パーソナルデータは，個人情報保護法における「個人情報」を含む広義の概念。氏名・住所・電話番号だけでなく，位置情報・購買履歴・Cookieなどのオンライン識別子も含まれる。'
  ) RETURNING id INTO qid;

  VALUES (38, 170, 'choice', 1, 1,
    '課題定義→データ収集→データ前処理→モデル構築→評価→展開（デプロイ）の段階を繰り返すデータ分析の一連のプロセスはどれか。',
    'データサイエンスのサイクル（CRISP-DMやKDDプロセスなど）は，ビジネス課題の理解からデータ取得・前処理・モデリング・評価・運用展開まで反復的に取り組む標準的なプロセスフレームワーク。'
  ) RETURNING id INTO qid;

  VALUES (38, 171, 'choice', 1, 1,
    '現実のシステムや現象を数理モデルで再現し，コンピュータ上で仮想的に実験・検証する手法はどれか。',
    'シミュレーションは，実物の構築や実験が困難・コストが高い場合に，モデルを用いてコンピュータ上で動作を再現・検証する手法。離散事象シミュレーション・連続シミュレーション・モンテカルロ法などがある。'
  ) RETURNING id INTO qid;

  VALUES (38, 172, 'choice', 1, 1,
    'シミュレーションモデルにリアルタイムの観測データを取り込み，モデルを継続的に更新・修正することで予測精度を向上させる手法はどれか。',
    'シミュレーションのデータ同化（Data Assimilation）は，数値予報モデルに気象観測データを逐次取り込んで予報精度を上げる手法が代表例。気象・海洋・宇宙物理・自動運転などで活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 173, 'choice', 1, 1,
    'データ分析において，大量のデータから規則性・相関・クラスタなどの共通特徴を発見するタスクはどれか。',
    'パターン発見は，データマイニングの代表的なタスク。アソシエーション分析・クラスタリング・分類などの手法で，データ中に潜む意味ある構造を自動的に発見する。'
  ) RETURNING id INTO qid;

  VALUES (38, 174, 'choice', 1, 1,
    '制約条件のもとで目的関数（コスト・時間・リスクなど）を最小化または最大化する最良解を求めることを目指すタスクはどれか。',
    '最適化は，数学的計画法・メタヒューリスティクス（遺伝的アルゴリズム・粒子群最適化など）を用いて，大量の選択肢の中から最も良い解を見つけるタスク。生産計画・物流・機械学習の学習過程にも適用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 175, 'choice', 1, 1,
    'データサイエンス・統計・機械学習・プログラミングのスキルをもち，データを分析してビジネス課題の解決に貢献する専門職はどれか。',
    'データサイエンティストは，数学・統計・ITの知識とビジネス理解を組み合わせてデータから価値を引き出す専門家。Harvard Business Reviewが「21世紀で最もセクシーな職業」と称した。'
  ) RETURNING id INTO qid;

  VALUES (38, 176, 'choice', 1, 1,
    '統計調査の対象となるすべての個体（人・物・事象）の集合を示す概念はどれか。',
    '母集団は，調査・研究の対象となるすべての要素の集まり。一般に全数調査が困難なため，標本調査（サンプリング）で母集団のパラメータを推定する。'
  ) RETURNING id INTO qid;

  VALUES (38, 177, 'choice', 1, 1,
    '5年に1度，日本に住む全住民を対象に行われる，人口・世帯・住居などを調査する国の最大規模の統計調査はどれか。',
    '国勢調査は，統計法に基づき総務省が実施する全数調査。全国民・外国人を含む全住民が対象で，その結果は選挙区割り・福祉政策・都市計画の基礎データとなる。'
  ) RETURNING id INTO qid;

  VALUES (38, 178, 'choice', 1, 1,
    '質問紙（紙面・Web）を使って対象者の意見・実態・満足度などを収集する調査手法はどれか。',
    'アンケート調査は，構造化質問によって定量・定性データを収集する調査手法。郵送・Web・インタビューなど複数の方法がある。設問設計・サンプリング方法が結果の信頼性に影響する。'
  ) RETURNING id INTO qid;

  VALUES (38, 179, 'choice', 1, 1,
    '母集団のすべての要素を漏れなく調査する方法はどれか。',
    '全数調査（悉皆調査）は，母集団全体を調査するため，推定誤差がなく最も正確な結果が得られる。ただし，大規模集団では時間・コストが大きい。国勢調査や工場の全品検査が代表例。'
  ) RETURNING id INTO qid;

  VALUES (38, 180, 'choice', 1, 1,
    '母集団から各要素を等確率で偏りなく抽出するサンプリング方法はどれか。',
    '単純無作為抽出（SRS：Simple Random Sampling）は，乱数表や乱数発生プログラムを使って母集団全体から等確率で標本を選ぶ基本的なサンプリング手法。偏りがなく推定量の理論が整っている。'
  ) RETURNING id INTO qid;

  VALUES (38, 181, 'choice', 1, 1,
    '母集団をあらかじめいくつかの層（グループ）に分け，各層から一定数を無作為に抽出するサンプリング方法はどれか。',
    '層別抽出（Stratified Sampling）は，年齢・性別・地域などの特性で母集団を層に分け，各層から比例・等割で標本を取る。層内の均一性が高いと，単純無作為抽出より効率的に精度が上がる。'
  ) RETURNING id INTO qid;

  VALUES (38, 182, 'choice', 1, 1,
    '母集団をまずいくつかの単位（市区町村など）に分けて無作為に選び，選ばれた単位内でさらに標本を抽出する多段階のサンプリング方法はどれか。',
    '多段抽出（Multi-stage Sampling）は，大規模母集団の調査コスト削減に有効。第1段は都市，第2段は世帯，第3段は個人というように段階的に抽出する。全国規模調査によく使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 183, 'choice', 1, 1,
    '調査・測定値が真の値にどれだけ近いか（精度）と，系統的なずれがないか（偏りのなさ）の2つの観点から調査の質を評価する概念はどれか。',
    '精度と偏りは，統計的推定の評価尺度。精度（precision）は推定値の分散（ばらつき）の小ささ，偏り（bias）は期待値と真の値の差。両方を最小化する調査設計が理想。'
  ) RETURNING id INTO qid;

  VALUES (38, 184, 'choice', 1, 1,
    '調査・研究において，サンプルの選び方に偏りがあり，母集団を正確に代表していないことから生じるバイアスはどれか。',
    '選択バイアスは，調査対象の選定方法に系統的な偏りが生じることで推定結果が歪む問題。自己選択・健診受診者のみ調査・生存バイアスなどが代表的な例。'
  ) RETURNING id INTO qid;

  VALUES (38, 185, 'choice', 1, 1,
    '調査・測定の過程で情報の収集・記録に系統的な誤りが生じることで，推定結果に歪みが生じるバイアスはどれか。',
    '情報バイアスは，測定誤差・回答バイアス・記録ミスなど，データ収集の方法に起因する系統誤差。想起バイアス（記憶頼りの回答のずれ）や観察者バイアスなどが代表例。'
  ) RETURNING id INTO qid;

  VALUES (38, 186, 'choice', 1, 1,
    '原因と結果の関係を分析する際に，両者に共通して影響を与える第三の変数が存在することで，見かけ上の関係が歪められるバイアスはどれか。',
    '交絡バイアスは，交絡因子（confounder）が原因変数と結果変数の両方に関連するため，真の因果効果を過大・過小評価させる問題。無作為化・マッチング・多変量解析で制御する。'
  ) RETURNING id INTO qid;

  VALUES (38, 187, 'choice', 1, 1,
    '評価対象に対して，ある際立った特性（たとえば外見の良さ）が他の特性（能力・性格）の評価まで引き上げてしまう認知バイアスはどれか。',
    'ハロー効果（後光効果）は，一つの顕著な特性が他の特性の評価に影響する心理バイアス。採用面接・人事評価・マーケティングで意識的な回避が重要。'
  ) RETURNING id INTO qid;

  VALUES (38, 188, 'choice', 1, 1,
    '多数の人が選んでいる・人気があるという事実に引きずられ，自分もそれを選ぼうとする心理的傾向はどれか。',
    'バンドワゴン効果（多数派同調バイアス）は，「みんながやっているから自分も」という行動原理。選挙・流行・投資行動などに影響を与え，情報カスケードや群れ行動を引き起こす。'
  ) RETURNING id INTO qid;

  VALUES (38, 189, 'choice', 1, 1,
    '異常事態や危険な状況に直面したとき，「自分は大丈夫」「大したことはない」と思い込み，危機を過小評価してしまう心理傾向はどれか。',
    '正常性バイアスは，非常事態でも「自分には関係ない」「なんとかなる」と思い込み，適切な避難行動や対応が遅れる原因になる認知バイアス。防災・リスク管理で対策が重視される。'
  ) RETURNING id INTO qid;

  VALUES (38, 190, 'choice', 1, 1,
    '自分の先入観・仮説・信念に合致する情報を優先的に集め，矛盾する情報を無視または軽視する認知バイアスはどれか。',
    '確証バイアス（confirmation bias）は，既存の信念を支持する証拠を過大評価し，反証を無視する傾向。意思決定・データ分析・研究設計において客観性を損なうリスクがある。'
  ) RETURNING id INTO qid;

  VALUES (38, 191, 'choice', 1, 1,
    'カテゴリごとの数量・頻度を長方形の高さで比較する，最も基本的なグラフはどれか。',
    '棒グラフは，カテゴリ変数の値を棒の高さ（または長さ）で表す。縦棒・横棒があり，項目間の比較や時系列の変化の把握に広く使われる最も基本的な統計グラフ。'
  ) RETURNING id INTO qid;

  VALUES (38, 192, 'choice', 1, 1,
    '時間の経過に伴う数値の変化をデータ点を直線で結んで表示し，トレンドや変動パターンを把握するグラフはどれか。',
    '折れ線グラフは，X軸に時間・連続量，Y軸に数値をとり，各点をつないで変化の傾向を示すグラフ。時系列データの可視化に最も適しており，複数系列の比較にも使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 193, 'choice', 1, 1,
    '最小値・第1四分位・中央値・第3四分位・最大値の5数要約と外れ値を箱と線（ひげ）で表した統計グラフはどれか。',
    '箱ひげ図（ボックスプロット）は，データの分布形状・ばらつき・外れ値を一目で把握できるグラフ。複数グループの分布比較に特に有効で，Rや Pythonで標準的に利用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 194, 'choice', 1, 1,
    '行と列の交点の値の大きさを色の濃淡・グラデーションで表し，全体のパターンや集中箇所を視覚化するグラフはどれか。',
    'ヒートマップは，数値の大小を色で表現したマトリックス形式の可視化手法。Webサイトのユーザー行動分析・相関行列の可視化・遺伝子発現パターンの表示などに活用される。'
  ) RETURNING id INTO qid;

  VALUES (38, 195, 'choice', 1, 1,
    '2つのカテゴリ変数の関係を，各カテゴリの組み合わせの比率を面積で表したタイル状のグラフはどれか。',
    'モザイク図（Marimekko chart）は，2つ以上のカテゴリ変数の分布と相互関係を面積で表現したグラフ。クロス集計の可視化に適しており，カテゴリ間の比率の違いを直感的に比較できる。'
  ) RETURNING id INTO qid;

  VALUES (38, 196, 'choice', 1, 1,
    '行に一方のカテゴリ変数，列にもう一方のカテゴリ変数を配置し，各組み合わせの度数（件数）を集計した表はどれか。',
    'クロス集計表（分割表）は，2つのカテゴリ変数の頻度を行×列のマトリックス形式で集計した表。カイ二乗検定の基礎となり，変数間の関連性を検定するために使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 197, 'choice', 1, 1,
    'クロス集計の結果を行と列で整理した表で，カイ二乗検定などの独立性検定に用いられる表はどれか。',
    '分割表（contingency table）は，クロス集計表とほぼ同義。カイ二乗検定・フィッシャーの正確確率検定などで2変数間の独立性や関連性を統計的に検定するために用いる。'
  ) RETURNING id INTO qid;

  VALUES (38, 198, 'choice', 1, 1,
    '複数の変数間の相関係数をすべての組み合わせについて計算し，マトリックス形式で一覧表示したものはどれか。',
    '相関係数行列は，p個の変数があるとき，p×pの対称行列で各セルにピアソン相関係数を表示したもの。多変量解析・主成分分析の前処理として変数間の関係を把握するために用いる。'
  ) RETURNING id INTO qid;

  VALUES (38, 199, 'choice', 1, 1,
    '複数の変数の組み合わせについて散布図をすべて並べたグリッド状のグラフで，多変量データの関係を一括して視覚確認できるものはどれか。',
    '散布図行列（ペアプロット）は，p変数のすべてのペアの散布図を p×pのマトリックスに並べたグラフ。対角線にはヒストグラムや密度プロットを配置することが多く，多変量の関係確認に有効。'
  ) RETURNING id INTO qid;

  VALUES (38, 200, 'choice', 1, 1,
    'クラスタ分析の結果を，データ点の統合過程を枝の分岐として表現した樹形図はどれか。',
    'デンドログラム（樹形図）は，階層的クラスタリングの結果を視覚化する図。縦軸に距離（類似度），横軸にサンプルを配置し，どの段階でどのクラスタが統合されたかを示す。'
  ) RETURNING id INTO qid;

END $$;
-- 企業活動 (section_id=38) Q201〜Q247
DO $$
DECLARE
  qid integer;
BEGIN

  VALUES (38, 201, 'choice', 1, 1,
    '棒グラフと折れ線グラフなど，異なる種類のグラフを1つの図に組み合わせて表示するグラフはどれか。',
    '複合グラフは，棒グラフで数量を，折れ線グラフで割合や別の指標を同一図内に表示するなど，複数のグラフタイプを組み合わせた可視化手法。売上と成長率など異なるスケールの指標を同時に把握するために使う。'
  ) RETURNING id INTO qid;

  VALUES (38, 202, 'choice', 1, 1,
    '単位の異なる2種類のデータを，左右に別々のY軸（縦軸）を設けて1つのグラフに表示する手法はどれか。',
    '2軸グラフ（二軸グラフ）は，売上（百万円）と利益率（%）など単位・スケールの異なる2変数を同一グラフで表示するために，左右にそれぞれのY軸を設ける手法。複合グラフの一種。'
  ) RETURNING id INTO qid;

  VALUES (38, 203, 'choice', 1, 1,
    '問題を分解・整理し，MECEな構造で原因・手段・課題を木の枝状に展開することで，全体像を明確にするフレームワークはどれか。',
    'ロジックツリー（論理ツリー）は，問題をMECEに分解して枝状に展開するフレームワーク。Whyツリー（原因究明）・Howツリー（解決策展開）・Whatツリー（現状把握）の3種類がある。'
  ) RETURNING id INTO qid;

  VALUES (38, 204, 'choice', 1, 1,
    'アイデア・概念間の意味的な関係を矢印や線で結んだ図で，概念の構造や関係性の理解・整理に使うダイアグラムはどれか。',
    'コンセプトマップは，概念（ノード）と関係（リンク）からなるネットワーク図。マインドマップが中心から放射状に展開するのに対し，コンセプトマップは概念間の多方向の関係性を表現できる。'
  ) RETURNING id INTO qid;

  VALUES (38, 205, 'choice', 1, 1,
    'GISデータの形式の一つで，点・線・ポリゴンなどの地物を格納するベクタ形式のファイルフォーマットはどれか。',
    'シェープファイル（.shp）はESRIが開発したGISベクタデータの標準フォーマット。.shp（形状）・.dbf（属性）・.shx（インデックス）の複数ファイルで構成され，地図情報システムで広く使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 206, 'choice', 1, 1,
    'テキストデータの分析において，文書中で一緒に出現しやすい単語のペアや関係性を示すキーワードはどれか。',
    '共起キーワードは，テキストマイニングで同じ文書・文章・段落中に頻繁に一緒に登場する単語の組み合わせ。共起ネットワーク分析で，話題のクラスタやキーワード間の関係性を可視化するために使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 207, 'choice', 1, 1,
    '企業の財務管理・資産運用・会計処理など，企業経営における金銭的側面全般を扱う分野はどれか。',
    '会計・財務は，貸借対照表・損益計算書などの財務諸表の作成・分析，資金調達・運用，コスト管理，投資評価などを扱う企業経営の中核領域。'
  ) RETURNING id INTO qid;

  VALUES (38, 208, 'choice', 1, 1,
    '需要があったにもかかわらず，在庫切れや機会の不活用などで得られなかった利益（逃した利益）のことをどれか。',
    '機会損失（opportunity loss）は，在庫切れによる販売機会の消失，設備の未稼働による生産損失など，潜在的に得られたはずの利益を失うこと。販売予測・在庫管理・設備計画の精度向上で最小化を図る。'
  ) RETURNING id INTO qid;

  VALUES (38, 209, 'choice', 1, 1,
    '売上高・固定費・変動費の関係から，利益がちょうどゼロになる（収支が均衡する）売上高または生産量を求める分析はどれか。',
    '損益分岐点（BEP：Break-Even Point）分析は，固定費÷（1−変動費率）で算出。これを超えた売上から利益が生まれる。価格設定・コスト管理・事業計画立案の基本ツール。'
  ) RETURNING id INTO qid;

  VALUES (38, 210, 'choice', 1, 1,
    '取引が発生するたびに，借方・貸方・勘定科目・金額を記録する複式簿記の最初の帳簿はどれか。',
    '仕訳帳は，日付順に取引を借方・貸方の勘定科目と金額で記録する帳簿。すべての会計処理の起点となり，次に総勘定元帳へ転記される。'
  ) RETURNING id INTO qid;

  VALUES (38, 211, 'choice', 1, 1,
    '仕訳帳の記録を勘定科目ごとに集計・転記し，各科目の残高を管理する帳簿はどれか。',
    '総勘定元帳（元帳）は，仕訳帳から勘定科目別に転記した帳簿。現金・売掛金・売上など各勘定の借方・貸方の累計と残高を管理する。財務諸表作成の基礎となる。'
  ) RETURNING id INTO qid;

  VALUES (38, 212, 'choice', 1, 1,
    '総勘定元帳の各勘定残高を借方・貸方に分けて集計し，帳簿の誤りがないかを確認するために作成する表はどれか。',
    '試算表（TB：Trial Balance）は，仕訳・転記の後，各勘定残高を一覧化した表。借方合計と貸方合計が一致することを確認して，記帳の誤りを検出するための中間的な集計表。'
  ) RETURNING id INTO qid;

  VALUES (38, 213, 'choice', 1, 1,
    '試算表をもとに，決算整理仕訳・繰越手続きを経て，損益計算書・貸借対照表の数値を算出する作業シートはどれか。',
    '精算表（Work Sheet）は，試算表の各残高に決算整理事項を加算・修正し，損益計算書と貸借対照表の最終数値を一覧で確認するための帳票。決算作業の中間集計表として使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 214, 'choice', 1, 1,
    '貸借対照表・損益計算書・キャッシュフロー計算書など，企業の財務状況を示す一連の公式報告書の総称はどれか。',
    '財務諸表（financial statements）は，企業の財政状態・経営成績・資金の流れを利害関係者に開示する公式文書。会社法・金融商品取引法に基づき，決算期ごとに作成・公開される。'
  ) RETURNING id INTO qid;

  VALUES (38, 215, 'choice', 1, 1,
    '企業のある時点の資産・負債・純資産を一覧にし，財政状態を示す財務諸表はどれか。',
    '貸借対照表（BS：Balance Sheet）は，「資産の部」（流動資産・固定資産・繰延資産）と「負債・純資産の部」を対照させた財政状態の一覧表。「資産＝負債＋純資産」の恒等式が成立する。'
  ) RETURNING id INTO qid;

  VALUES (38, 216, 'choice', 1, 1,
    '一定期間における収益・費用・利益（損失）を表示し，企業の経営成績を示す財務諸表はどれか。',
    '損益計算書（P/L：Profit and Loss Statement，またはI/S：Income Statement）は，売上高から費用を差し引いて純利益を計算する期間損益の報告書。5段階利益（売上総利益・営業利益・経常利益・税前利益・当期純利益）を開示する。'
  ) RETURNING id INTO qid;

  VALUES (38, 217, 'choice', 1, 1,
    '上場企業が決算確定前に速報として公表する，業績概要・財務数値・業績予想を記載した簡略レポートはどれか。',
    '決算短信は，金融商品取引所の規則に基づき，決算発表日に公表される速報性の高い決算情報開示文書。有価証券報告書より先に公表され，投資家・アナリストが業績判断に活用する。'
  ) RETURNING id INTO qid;

  VALUES (38, 218, 'choice', 1, 1,
    '企業を買収した際に，純資産の時価評価額を超えて支払った金額（超過収益力・ブランド価値など無形の価値）を表す勘定科目はどれか。',
    'のれん（Goodwill）は，M&Aで対価が純資産を超える場合に計上される無形固定資産。ブランド力・顧客基盤・技術力などを反映し，日本基準では20年以内に償却，IFRSでは非償却（毎期減損テスト）となる。'
  ) RETURNING id INTO qid;

  VALUES (38, 219, 'choice', 1, 1,
    '国際会計基準審議会（IASB）が策定した，世界共通を目指す会計基準はどれか。',
    'IFRS（International Financial Reporting Standards，国際財務報告基準）は，IASBが策定する国際会計基準。EU・多くの国で強制適用され，日本でも任意適用が認められ，連結財務諸表に使用できる。'
  ) RETURNING id INTO qid;

  VALUES (38, 220, 'choice', 1, 1,
    '貸借対照表の資産の部において，1年以内に現金化できる（または消費される）資産の区分はどれか。',
    '流動資産は，現金・預金・売掛金・棚卸資産（在庫）など，正常営業循環基準または1年基準で流動に分類される資産。流動比率（流動資産÷流動負債）の算出に使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 221, 'choice', 1, 1,
    '貸借対照表において，1年を超えて使用・保有する土地・建物・機械・無形資産などの資産の区分はどれか。',
    '固定資産は，有形固定資産（土地・建物・機械）・無形固定資産（のれん・特許権）・投資その他の資産（投資有価証券）に分類される。長期にわたり使用され，減価償却（一部）で費用化される。'
  ) RETURNING id INTO qid;

  VALUES (38, 222, 'choice', 1, 1,
    '将来の費用・損失に備えて前払いまたは繰り延べた支出で，複数年度にわたって費用化される資産の区分はどれか。',
    '繰延資産は，創立費・開業費・開発費など，すでに支出しているが将来の期間に配分すべき費用を資産として計上したもの。BSの資産の部に計上されるが実質的な換金価値はない。'
  ) RETURNING id INTO qid;

  VALUES (38, 223, 'choice', 1, 1,
    '貸借対照表において，1年以内に支払い義務が生じる負債（買掛金・短期借入金・未払費用など）の区分はどれか。',
    '流動負債は，1年基準または正常営業循環基準で流動に分類される負債。支払能力の短期的な評価指標である流動比率（流動資産÷流動負債）の分母として用いられる。'
  ) RETURNING id INTO qid;

  VALUES (38, 224, 'choice', 1, 1,
    '貸借対照表において，1年を超えて返済義務がある長期借入金・社債・退職給付引当金などの負債の区分はどれか。',
    '固定負債は，返済期限が1年超の長期借入金・社債・リース負債・退職給付引当金などを含む。企業の長期的な財務健全性を評価する際の重要な指標となる。'
  ) RETURNING id INTO qid;

  VALUES (38, 225, 'choice', 1, 1,
    '貸借対照表において，資産から負債を差し引いた差額で，株主資本・評価・換算差額等・新株予約権などから構成される区分はどれか。',
    '純資産（自己資本）は，資産合計から負債合計を差し引いた残高。株主が出資した資本金・資本剰余金・利益剰余金などの株主資本と，その他の包括利益累計額等が含まれる。'
  ) RETURNING id INTO qid;

  VALUES (38, 226, 'choice', 1, 1,
    '純資産の一部で，株主から払い込まれた出資金（資本金・資本剰余金）と過去の利益蓄積（利益剰余金）の合計はどれか。',
    '株主資本は，純資産の主要部分を占め，資本金・資本準備金・利益準備金・利益剰余金（任意積立金・繰越利益剰余金）・自己株式で構成される。ROEの分母として使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 227, 'choice', 1, 1,
    '損益計算書において，売上獲得・事業活動のために消費した財貨・サービスの価値で，収益に対する発生コストはどれか。',
    '費用は，売上原価・販売費及び一般管理費・営業外費用・特別損失などに分類され，収益から差し引いて利益を計算する。費用収益対応の原則に従って当期の収益と対応させる。'
  ) RETURNING id INTO qid;

  VALUES (38, 228, 'choice', 1, 1,
    '損益計算書において，事業活動の対価として得た売上高・手数料・受取利息などの経済的価値の流入はどれか。',
    '収益は，売上高・営業収益・受取利息・有価証券売却益など，企業が対外活動で得た経済的便益の流入。費用を上回れば利益が生じ，下回れば損失となる。'
  ) RETURNING id INTO qid;

  VALUES (38, 229, 'choice', 1, 1,
    '損益計算書において，営業活動を支援する管理・販売に関わる費用（人件費・広告宣伝費・減価償却費など）の区分はどれか。',
    '販売費及び一般管理費（SG&A）は，営業利益＝売上総利益−SG&Aの式で計算される。販売員給与・広告費・地代家賃・役員報酬など，製造原価に含まれない期間費用をまとめた区分。'
  ) RETURNING id INTO qid;

  VALUES (38, 230, 'choice', 1, 1,
    '損益計算書において，本業以外の財務活動（受取利息・支払利息・配当金・有価証券売却損益など）に関する収益・費用の区分はどれか。',
    '営業外損益は，経常利益の計算に用いられる非主業の損益。受取利息・受取配当金（営業外収益）と支払利息・社債利息（営業外費用）の差額が経常利益に加算される。'
  ) RETURNING id INTO qid;

  VALUES (38, 231, 'choice', 1, 1,
    '損益計算書において，当期のみに発生した臨時・異常な損益（固定資産売却益・災害損失・投資有価証券評価損など）の区分はどれか。',
    '特別損益は，経常活動以外の一時的・非反復的な損益。特別利益（固定資産売却益・負ののれん発生益）と特別損失（固定資産除却損・減損損失・災害損失）に分けられる。'
  ) RETURNING id INTO qid;

  VALUES (38, 232, 'choice', 1, 1,
    '財務諸表の作成ルールを定めた，国または業界団体が公表する会計の基準・規則の総称はどれか。',
    '会計基準は，財務諸表の記載方法・測定ルールを定めた基準。日本では「企業会計原則」「収益認識基準」などの日本基準（J-GAAP）と，国際標準のIFRSが並存する。'
  ) RETURNING id INTO qid;

  VALUES (38, 233, 'choice', 1, 1,
    '企業の収益性・安全性・効率性・成長性などを財務諸表のデータから定量的に評価するための比率・数値の総称はどれか。',
    '財務指標は，ROA・ROE（収益性），流動比率・自己資本比率（安全性），棚卸資産回転率（効率性）など，財務諸表の数値を組み合わせて算出する経営評価の尺度。'
  ) RETURNING id INTO qid;

  VALUES (38, 234, 'choice', 1, 1,
    '投下した資本・資産に対してどれだけの利益を生み出しているかを評価するための財務指標の区分はどれか。',
    '収益性指標には，ROA（総資産利益率）・ROE（自己資本利益率）・売上高利益率などが含まれる。利益÷資本（または売上）の形で算出し，資本の効率的活用度を評価する。'
  ) RETURNING id INTO qid;

  VALUES (38, 235, 'choice', 1, 1,
    '企業の総資産（総資本）に対する当期純利益の比率を示す収益性指標はどれか。',
    'ROA（Return on Assets，総資産利益率）は，当期純利益÷総資産×100で算出。調達した全資本（自己資本＋負債）をどれだけ効率よく利益に変換できたかを示す。'
  ) RETURNING id INTO qid;

  VALUES (38, 236, 'choice', 1, 1,
    '株主が出資した自己資本に対する当期純利益の比率で，株主の出資に対する収益効率を示す収益性指標はどれか。',
    'ROE（Return on Equity，自己資本利益率）は，当期純利益÷自己資本（純資産）×100で算出。日本企業の低ROEが課題とされ，コーポレートガバナンス・コードでROE向上が求められている。'
  ) RETURNING id INTO qid;

  VALUES (38, 237, 'choice', 1, 1,
    '企業の支払能力・財務の健全性（倒産リスクの低さ）を評価するための財務指標の区分はどれか。',
    '安全性指標には，流動比率・当座比率（短期安全性），自己資本比率・負債比率（長期安全性）などが含まれる。債権者・投資家が企業の返済能力・財務リスクを評価する際に使う。'
  ) RETURNING id INTO qid;

  VALUES (38, 238, 'choice', 1, 1,
    '流動資産÷流動負債×100で算出され，短期的な支払能力を示す安全性指標はどれか。',
    '流動比率は，1年以内の短期的な支払い能力（短期流動性）を評価する指標。200%以上が理想とされる。当座比率（当座資産÷流動負債）はより厳格に在庫を除いた支払能力を評価する。'
  ) RETURNING id INTO qid;

  VALUES (38, 239, 'choice', 1, 1,
    '総資産（または総資本）に占める自己資本（純資産）の割合を示す，企業の長期的な財務健全性を評価する指標はどれか。',
    '自己資本比率（Equity Ratio）は，自己資本÷総資本×100で算出。高いほど借入依存度が低く財務健全性が高い。40%以上が安定企業の目安とされ，倒産リスクの評価に使われる。'
  ) RETURNING id INTO qid;

  VALUES (38, 240, 'choice', 1, 1,
    '投資・プロジェクトのコストと便益を比較し，経済的合理性・費用対効果を評価する手法の総称はどれか。',
    '経済性計算は，設備投資評価（NPV・IRR・回収期間法）やコスト分析など，意思決定における経済的合理性を定量的に評価する手法。損益分岐点分析も広義に含まれる。'
  ) RETURNING id INTO qid;

  VALUES (38, 241, 'choice', 1, 1,
    '会計上の利益だけでなく，実際の現金の流れ（キャッシュフロー）を重視して経営判断・企業評価を行う経営スタイルはどれか。',
    'キャッシュフロー経営は，P/Lの利益より実際の現金収支（CF）を優先して経営する考え方。黒字倒産（利益があっても資金繰り悪化）を防ぎ，投資・配当・財務戦略をCFに基づいて判断する。'
  ) RETURNING id INTO qid;

  VALUES (38, 242, 'choice', 1, 1,
    'グループ企業の余剰資金を本社に集中管理し，グループ全体の資金効率を最大化するための仕組みはどれか。',
    'キャッシュマネジメント（CMS：Cash Management System）は，グループ各社の資金を本社（ヘッドオフィス）が一元管理するシステム。資金の無駄な調達・保有を排除し，グループ全体の金利コスト削減と流動性最適化を図る。'
  ) RETURNING id INTO qid;

  VALUES (38, 243, 'choice', 1, 1,
    '期末時点の在庫資産を帳簿価額で評価するための会計手法の総称で，先入先出法・総平均法・移動平均法などがあるものはどれか。',
    '棚卸資産評価は，期末在庫の単価を算定する会計手法の選択。採用する方法によって売上原価・期末在庫額・利益が変わる。日本基準では原価法（先入先出・総平均・移動平均など）が認められている。'
  ) RETURNING id INTO qid;

  VALUES (38, 244, 'choice', 1, 1,
    '在庫資産の払出単価を，最も先に仕入れたものから順に使用（払出）したとみなして計算する棚卸資産評価法はどれか。',
    '先入先出法（FIFO：First In, First Out）は，古い仕入れ原価から順番に払い出す原価計算法。インフレ期には売上原価が低く，期末在庫評価額が高くなる傾向がある。IFRSでは後入先出法（LIFO）が禁止されFIFOが一般的。'
  ) RETURNING id INTO qid;

  VALUES (38, 245, 'choice', 1, 1,
    '一定期間のすべての仕入数量と仕入金額を合算して平均単価を算出し，払出単価に適用する棚卸資産評価法はどれか。',
    '総平均法は，期首在庫＋当期仕入の合計金額÷合計数量で平均単価を算出し，その期間中の全払出に適用する方法。単純で計算量が少ないが，期中の価格変動を把握しにくい。'
  ) RETURNING id INTO qid;

  VALUES (38, 246, 'choice', 1, 1,
    '仕入れのたびに平均単価を再計算し，払出単価を更新して適用し続ける棚卸資産評価法はどれか。',
    '移動平均法は，仕入ごとに（残高金額＋仕入金額）÷（残高数量＋仕入数量）で新たな平均単価を計算する方法。常に最新の平均コストを払出に反映でき，在庫管理システムと相性が良い。'
  ) RETURNING id INTO qid;

  VALUES (38, 247, 'choice', 1, 1,
    '資産や負債をバランスシート（貸借対照表）に計上せず，簿外に移す会計手法・取引の総称はどれか。',
    'オフバランス（Off-balance）化は，リース・証券化・SPC（特別目的会社）を活用して資産・負債をBSから除外する手法。自己資本比率の改善やROAの向上が目的だが，リスクの見えにくさに注意が必要。'
  ) RETURNING id INTO qid;

END $$;
-- 法務 (section_id=39) Q1〜Q55
DO $$
DECLARE
  qid integer;
BEGIN

  VALUES (39, 1, 'choice', 1, 1,
    '知的財産の創造・保護・活用に関する国家戦略を推進するために内閣に設置された組織はどれか。',
    '知的財産戦略本部は，知的財産基本法に基づき2003年に内閣に設置された。内閣総理大臣を本部長とし，知的財産推進計画を策定・推進する。'
  ) RETURNING id INTO qid;

  VALUES (39, 2, 'choice', 1, 1,
    '知的財産の創造・保護・活用を総合的かつ計画的に推進することを目的とした，日本の知的財産に関する基本的な法律はどれか。',
    '知的財産基本法（2002年制定）は，知的財産の保護と活用の基本方針を定めた法律。知的財産戦略本部の設置根拠でもある。'
  ) RETURNING id INTO qid;

  VALUES (39, 3, 'choice', 1, 1,
    '特許権・実用新案権・意匠権・商標権の4つを総称した，特許庁への登録によって発生する知的財産権の区分はどれか。',
    '産業財産権は，特許庁への出願・登録を必要とする（方式主義）。著作権（無方式主義）とは異なり，登録によって権利が発生し，一定期間の独占的な利用権が付与される。'
  ) RETURNING id INTO qid;

  VALUES (39, 4, 'choice', 1, 1,
    '新しい技術的なアイデア（発明）を独占的に実施できる権利で，出願から20年間保護される産業財産権はどれか。',
    '特許権は，自然法則を利用した高度な技術的思想の創作（発明）に与えられる独占権。出願日から20年（医薬品等は最長25年）保護される。特許庁への出願・審査・登録が必要。'
  ) RETURNING id INTO qid;

  VALUES (39, 5, 'choice', 1, 1,
    '物品の構造・形状などの考案（小発明）を保護する権利で，出願から10年間保護される産業財産権はどれか。',
    '実用新案権は，特許権より低い進歩性でも取得でき，無審査登録制度を採用する。ただし権利行使には技術評価書が必要で，保護期間は出願日から10年。'
  ) RETURNING id INTO qid;

  VALUES (39, 6, 'choice', 1, 1,
    '物品や建築物・内装のデザイン（美的外観）を保護する権利で，出願から25年間保護される産業財産権はどれか。',
    '意匠権は，工業製品の形状・模様・色彩などの視覚的なデザインを保護する。2020年改正で保護対象が内装デザインにも拡大され，保護期間が登録から25年になった。'
  ) RETURNING id INTO qid;

  VALUES (39, 7, 'choice', 1, 1,
    '商品・サービスの出所を区別するためのロゴ・文字・図形などの標識（マーク）を保護する権利で，10年ごとの更新で永続的に保護される産業財産権はどれか。',
    '商標権は，ブランドを識別するマークを独占的に使用できる権利。10年ごとの更新登録により，実質無制限に保護期間を延長できる。更新を行わなければ消滅する。'
  ) RETURNING id INTO qid;

  VALUES (39, 8, 'choice', 1, 1,
    'プログラムや文章・音楽・映像などの創作物が完成した時点で自動的に発生し，登録不要で保護される知的財産権はどれか。',
    '著作権は創作と同時に発生する（無方式主義）。ソフトウェアのプログラムも著作物として保護される。死後70年（法人著作は公表後70年）保護される。'
  ) RETURNING id INTO qid;

  VALUES (39, 9, 'choice', 1, 1,
    '半導体集積回路の回路配置を保護する権利で，半導体集積回路の回路配置に関する法律（通称：半導体チップ保護法）に基づいて付与される権利はどれか。',
    '回路配置利用権は，半導体集積回路（LSIなど）の独自の回路配置を保護する知的財産権。登録から10年間保護され，他者による複製・譲渡・輸出入を規制できる。'
  ) RETURNING id INTO qid;

  VALUES (39, 10, 'choice', 1, 1,
    '企業が保有する技術情報や経営情報のうち，秘密として管理されており，有用性があり，公然と知られていないものを保護する概念はどれか。',
    '営業秘密は，不正競争防止法で保護される。「秘密管理性」「有用性」「非公知性」の3要件を満たす必要がある。侵害に対して差止め・損害賠償請求が可能。'
  ) RETURNING id INTO qid;

  VALUES (39, 11, 'choice', 1, 1,
    '著作者が自らの著作物に対してもつ人格的利益を守る権利で，公表権・氏名表示権・同一性保持権などからなる権利はどれか。',
    '著作者人格権は，一身専属権で譲渡できない。公表権（公表の可否・方法を決める），氏名表示権（著作者名の表示方法），同一性保持権（無断改変を禁止）の3つからなる。'
  ) RETURNING id INTO qid;

  VALUES (39, 12, 'choice', 1, 1,
    '著作権のうち，経済的利益に関する権利で，複製権・上映権・公衆送信権・譲渡権・貸与権などからなり，他者に譲渡・許諾できる権利はどれか。',
    '著作財産権は，著作者人格権と異なり，財産的権利であるため譲渡・ライセンス許諾が可能。複製権・翻訳権・公衆送信権・貸与権など多数の支分権から構成される。'
  ) RETURNING id INTO qid;

  VALUES (39, 13, 'choice', 1, 1,
    '法人の発意に基づき，従業員が職務として作成したプログラムや著作物で，著作権が原則として法人（使用者）に帰属する制度はどれか。',
    '職務著作は，①法人等の発意，②従業員が職務上作成，③法人名義で公表，④契約等で別の定めがない，の4要件を満たす場合に，著作権が法人に帰属する制度。'
  ) RETURNING id INTO qid;

  VALUES (39, 14, 'choice', 1, 1,
    '既存の著作物（原著作物）を翻訳・編曲・変形・映画化などによって創作的に変更した著作物はどれか。',
    '二次的著作物は，原著作物の著作権と独自の著作権（翻案権）を有する。利用には原著作者と翻案著作者双方の許諾が必要。翻訳・映画化・パロディなどが含まれる。'
  ) RETURNING id INTO qid;

  VALUES (39, 15, 'choice', 1, 1,
    '著作権法で定められた公衆送信権のうち，インターネットなどを通じて，受信者の求めに応じて送信できる状態に置くことを指す概念はどれか。',
    '送信可能化権は，著作物をWebサーバーにアップロードするなど，いつでも送信できる状態に置く行為を規制する。アップロード行為自体が送信可能化に当たる。'
  ) RETURNING id INTO qid;

  VALUES (39, 16, 'choice', 1, 1,
    '著作権法で認められた，他人の著作物を許諾なく利用できる行為で，批評・研究・報道などを目的に，主従関係を明示しつつ正当な範囲で使用することはどれか。',
    '引用は，著作権法32条で認められた権利制限規定。①引用部分が従・自己著作が主，②出所明示，③原文の改変禁止，④引用の必然性，などの要件を満たす必要がある。'
  ) RETURNING id INTO qid;

  VALUES (39, 17, 'choice', 1, 1,
    '著作権法で認められた，機械学習・AIの学習データ収集など，著作物の内容を「享受」しない目的で行うテキスト・データ解析のための著作物の利用はどれか。',
    '情報解析（著作権法47条の5）は，文字・音声・画像などの大量の著作物から情報を抽出・分析する行為を，権利者の許諾なく行える規定。2018年改正で大幅に拡充された。'
  ) RETURNING id INTO qid;

  VALUES (39, 18, 'choice', 1, 1,
    '著作権法で認められた権利制限の一つで，個人または家庭内などの限られた範囲でのみ使用する目的であれば，著作物を無許諾でコピーできる規定はどれか。',
    '私的使用のための複製（著作権法30条）は，個人・家庭内の使用に限り著作権者の許諾なく複製できる規定。ただし，コピープロテクト外しや共有ネットワークへのアップロードには適用されない。'
  ) RETURNING id INTO qid;

  VALUES (39, 19, 'choice', 1, 1,
    '著作物の表現から情報・アイデアを享受することを目的とせず，機械処理・変換・分析などのためだけに行う著作物の利用を認める規定はどれか。',
    '非享受利用（著作権法30条の4）は，著作物の視聴・読書など表現を享受する目的でなく，情報解析・AI学習・キャッシュ生成など技術的利用のために行う行為に著作権が及ばないとする規定。'
  ) RETURNING id INTO qid;

  VALUES (39, 20, 'choice', 1, 1,
    '著作権法で認められた権利制限の一つで，公共の図書館が利用者への閲覧サービスのために著作物を一定範囲で複製できる規定はどれか。',
    '図書館での複製（著作権法31条）は，調査研究目的で著作物の一部（原則全体の半分以下）を1部のみ複製できる。国立国会図書館によるデジタル化・送信も条件付きで許容されている。'
  ) RETURNING id INTO qid;

  VALUES (39, 21, 'choice', 1, 1,
    '著作権法で認められた権利制限の一つで，学校などが授業の過程で必要な限度において著作物を無許諾で複製・公衆送信できる規定はどれか。',
    '教育機関での複製（著作権法35条）は，学校等の授業で使用する場合，必要と認められる限度で著作物を複製・送信できる。ICT活用授業でのクラス送信も改正で許容されたが，補償金が必要。'
  ) RETURNING id INTO qid;

  VALUES (39, 22, 'choice', 1, 1,
    '著作権法で認められた権利制限の一つで，入学試験問題や資格試験の問題として著作物を無許諾で利用できる規定はどれか。',
    '試験問題での利用（著作権法36条）は，入試・資格試験・検定などで著作物を問題として利用することを，著作権者の許諾なく認める規定。ただし，インターネットによる配信には補償金が必要。'
  ) RETURNING id INTO qid;

  VALUES (39, 23, 'choice', 1, 1,
    '特許法における保護対象で，自然法則を利用した技術的思想の高度な創作を指す概念はどれか。',
    '発明は，特許法上の「自然法則を利用した技術的思想の創作のうち高度のもの」と定義される。物の発明・方法の発明・製造方法の発明の3種がある。'
  ) RETURNING id INTO qid;

  VALUES (39, 24, 'choice', 1, 1,
    '実用新案法における保護対象で，自然法則を利用した技術的思想の創作（高度でなくてもよい）を指す概念はどれか。',
    '考案は，実用新案法の保護対象。発明と異なり「高度性」が求められず，物品の構造・形状・組合せに限定される。生活の知恵のような小改良的なアイデアを保護する。'
  ) RETURNING id INTO qid;

  VALUES (39, 25, 'choice', 1, 1,
    '意匠法における保護対象で，物品・建築物・画像の形状・模様・色彩またはこれらの結合で視覚を通じて美感を起こさせるものはどれか。',
    '意匠は，意匠法の保護対象。2020年の改正で建築物の外観・内装デザイン，画面上のUIデザインも意匠登録の対象となった。'
  ) RETURNING id INTO qid;

  VALUES (39, 26, 'choice', 1, 1,
    '商標法における保護対象で，商品・サービスの出所を識別するための文字・図形・記号・立体的形状・音などの標識はどれか。',
    '商標は，商品・サービスの出所識別機能・品質保証機能・広告機能をもつ標識。文字・図形・記号・音・動きなど多様な形態が登録対象となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 27, 'choice', 1, 1,
    'コンピュータプログラム自体（アルゴリズムを実装した具体的なコード）を技術的発明として特許保護の対象とする制度はどれか。',
    'ソフトウェア特許は，プログラムの機能・処理手順が「自然法則を利用した技術的思想」として認められる場合に取得できる。著作権が表現を保護するのに対し，特許はアイデア・機能を保護する。'
  ) RETURNING id INTO qid;

  VALUES (39, 28, 'choice', 1, 1,
    'インターネットを利用したビジネスの仕組みや方法をソフトウェアと組み合わせた発明として特許保護の対象とする制度はどれか。',
    'ビジネス方法の特許（BM特許）は，e-コマース・金融取引・競売システムなどのビジネスモデルをITと組み合わせた発明として保護する。純粋なビジネスのアイデアだけでは特許取得できない。'
  ) RETURNING id INTO qid;

  VALUES (39, 29, 'choice', 1, 1,
    '不正競争防止法で規制される行為で，他人の商標・ブランド等と類似したドメイン名を不正な利益目的で登録・保有・使用する行為はどれか。',
    'ドメイン名の不正取得（サイバースクワッティング）は，著名企業や有名人のブランド名等を模したドメインを先取りして転売などを図る行為。不正競争防止法で差止め・損害賠償の対象。'
  ) RETURNING id INTO qid;

  VALUES (39, 30, 'choice', 1, 1,
    'DVD・ゲームソフトなどの複製防止技術（著作権保護技術）を解除・回避する行為で，著作権法上禁止されている行為はどれか。',
    'コピープロテクト外しは，著作権法で技術的保護手段の回避として禁止されている。正規ユーザーであっても，個人使用目的であっても，保護技術を解除した複製は私的複製の例外から除外される。'
  ) RETURNING id INTO qid;

  VALUES (39, 31, 'choice', 1, 1,
    'サイバーセキュリティ基本法で定義される，電子的方式で処理・伝送・記録される情報の漏洩・滅失・毀損の防止などの措置はどれか。',
    'サイバーセキュリティは，サイバーセキュリティ基本法（2014年制定）第2条で，電磁的記録の安全管理（機密性・完全性・可用性の確保）と，これに関わる国や社会の安全確保を広く指す概念として定義されている。'
  ) RETURNING id INTO qid;

  VALUES (39, 32, 'choice', 1, 1,
    '電子的・磁気的またはその他の人の知覚によっては認識できない方式で，コンピュータや電磁的記録を処理・記録する方式はどれか。',
    '電磁的方式は，コンピュータが使うデジタルデータの記録・処理方式の総称。刑法・不正競争防止法・個人情報保護法などの法律で，書面（紙）と対比されるデジタルデータを指す用語として用いられる。'
  ) RETURNING id INTO qid;

  VALUES (39, 33, 'choice', 1, 1,
    '電磁的方式で記録を保存するための媒体で，ハードディスク・USBメモリ・CD・DVDなどを指す概念はどれか。',
    '電磁的記録媒体は，不正競争防止法・個人情報保護法・刑法などで，デジタル情報の保存装置を指す用語。「電磁的記録不正作出」など法律上の構成要件の対象となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 34, 'choice', 1, 1,
    'サイバーセキュリティ基本法に基づき政府が策定する，サイバーセキュリティ施策の基本方針・目標・重点施策をまとめた文書はどれか。',
    'サイバーセキュリティ戦略は，サイバーセキュリティ基本法11条に基づき内閣が策定する。経済社会の活力向上・強固な安全保障・国際秩序の維持を3つの柱として掲げ，おおむね3年ごとに改訂される。'
  ) RETURNING id INTO qid;

  VALUES (39, 35, 'choice', 1, 1,
    'サイバーセキュリティ基本法で定められた，サイバーセキュリティ施策推進の根本的な考え方・方向性を示す規定はどれか。',
    '基本理念（サイバーセキュリティ基本法第3条）は，サイバーセキュリティ確保の重要性・情報の自由な流通の確保・国民全体での取り組み・国際社会との連携などの基本的考え方を定める。'
  ) RETURNING id INTO qid;

  VALUES (39, 36, 'choice', 1, 1,
    'サイバーセキュリティ基本法に基づき設置された，官民が連携してサイバーセキュリティ情報を共有・対策を協議する組織はどれか。',
    'サイバーセキュリティ協議会は，2019年のサイバーセキュリティ基本法改正で設置。国・地方公共団体・企業・重要インフラ事業者などが参加し，サイバー攻撃情報の共有・対処調整を行う。'
  ) RETURNING id INTO qid;

  VALUES (39, 37, 'choice', 1, 1,
    '不正アクセス禁止法で定義される，特定の電子計算機の利用を特定の者のみに制限するためのID・パスワード認証などの機能はどれか。',
    'アクセス制御機能は，不正アクセス禁止法（不正アクセス行為の禁止等に関する法律）の保護対象。パスワード・ICカード・生体認証などが含まれる。この機能を回避・突破する行為が不正アクセスに該当する。'
  ) RETURNING id INTO qid;

  VALUES (39, 38, 'choice', 1, 1,
    '不正アクセス禁止法で禁止されている，アクセス制御機能を持つコンピュータに他人のIDを不正利用するなどして無断でアクセスする行為はどれか。',
    '不正アクセス行為は，①アクセス制御機能を回避して，②不正に電子計算機の利用を可能にする行為。IDの盗用・セキュリティホール攻撃・フィッシングで入手した情報の使用などが該当する。'
  ) RETURNING id INTO qid;

  VALUES (39, 39, 'choice', 1, 1,
    '不正アクセス禁止法で禁止されている，他人のID・パスワードを無断で第三者に提供するなど，不正アクセスの実行を容易にする行為はどれか。',
    '不正アクセス行為を助長する行為は，他人の識別符号（ID・パスワード）を不正に取得・保管・第三者提供する行為。フィッシングで入手した認証情報の売買なども該当し，不正アクセス禁止法で処罰対象となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 40, 'choice', 1, 1,
    '刑法で定められた，コンピュータウイルスなどの不正なプログラムを作成・提供・供用する行為に対する罪はどれか。',
    '不正指令電磁的記録に関する罪（刑法168条の2・168条の3）は，2011年に新設。正当な理由なくウイルスを作成・提供・取得・保管する行為が処罰対象。「ウイルス罪」とも呼ばれる。'
  ) RETURNING id INTO qid;

  VALUES (39, 41, 'choice', 1, 1,
    '刑法で定められた，不実の電磁的記録を作成したり虚偽の情報を与えたりしてコンピュータを不正に操作し，財産上の利益を得る行為に対する罪はどれか。',
    '電子計算機使用詐欺罪（刑法246条の2）は，コンピュータを用いた詐欺的行為を規制する罪。銀行システムへの不正な振込指示やポイントの不正取得などが該当する。'
  ) RETURNING id INTO qid;

  VALUES (39, 42, 'choice', 1, 1,
    '刑法で定められた，コンピュータを破壊したり虚偽のデータを入力したりして電子計算機の正常な業務を妨害する行為に対する罪はどれか。',
