  VALUES (39, 48, 'choice', 1, 1,
    '個人情報保護法で特に慎重な取り扱いが求められる，人種・信条・病歴・犯罪歴・障がいなど本人への差別や不利益を引き起こしかねない個人情報はどれか。',
    '要配慮個人情報は，不当な差別・偏見等を招かないよう，取得には原則として本人同意が必要。人種・信条・社会的身分・病歴・前科・障がい・健康診断情報・犯罪被害情報などが対象。'
  ) RETURNING id INTO qid;

  VALUES (39, 49, 'choice', 1, 1,
