  ) RETURNING id INTO qid;

  VALUES (39, 101, 'choice', 1, 1,
    'ソフトウェアを自由に使用・研究・改変・再配布できる権利をユーザーに保証する，GNU GPLなどを含むソフトウェアの概念はどれか。',
    'フリーソフトウェアは，リチャード・ストールマンが提唱した「4つの自由」（使用・研究・改変・配布の自由）を保証するソフトウェア。無料（free as in free beer）ではなく，自由（free as in free speech）を意味する。'
  ) RETURNING id INTO qid;

  VALUES (39, 102, 'choice', 1, 1,
