  ) RETURNING id INTO qid;

  VALUES (39, 104, 'choice', 1, 1,
    'GPLのコピーレフト要件を緩和し，LGPLライセンスのライブラリとリンクするプログラムはGPLでなくてもよいとするオープンソースライセンスはどれか。',
    'LGPL（GNU Lesser General Public License）は，GPL派生だがリンク（動的ライブラリとしての利用）に関してはコピーレフトを要求しない。Cライブラリや汎用ライブラリに適用されることが多い。'
  ) RETURNING id INTO qid;

  VALUES (39, 105, 'choice', 1, 1,
    'GPL等に基づく原則で，オープンソースソフトウェアを改変・利用したソフトウェアを配布する際，同じライセンスで配布することを義務付ける概念はどれか。',
    'コピーレフトは，自由なソフトウェアが将来もフリーであり続けることを保証する原則。GPLが代表的で，派生物も同じGPLで公開する必要がある。プロプライエタリなソフトウェアへの取り込みを防ぐ。'
  ) RETURNING id INTO qid;

  VALUES (39, 106, 'choice', 1, 1,
    '経済産業省が策定した，ソフトウェア開発の外注における契約の標準的な雛形で，請負型・準委任型など複数の類型を含む契約書のモデルはどれか。',
    'ソフトウェア開発委託モデル契約は，経済産業省が公表したSI・ソフトウェア開発外注の標準契約書。要件定義・基本設計・詳細設計・製造・テスト等の工程別に請負・準委任の選択基準と契約条項を示す。'
  ) RETURNING id INTO qid;

  VALUES (39, 107, 'choice', 1, 1,
