-- 法務 (section_id=39) Q111〜Q165
DO $$
DECLARE
  qid integer;
BEGIN

  VALUES (39, 111, 'choice', 1, 1,
    'デジタル社会形成基本法で定義される，国や地方公共団体が整備・公開する住所・法人・不動産などの公的な基盤データはどれか。',
    'ベースレジストリは，住所・法人・土地・建物・公共施設などの社会的基盤となる公的データ。複数の行政機関が独自に持つデータの重複や表記不統一を解消し，官民共通のデータ基盤として整備される。'
  ) RETURNING id INTO qid;

  VALUES (39, 112, 'choice', 1, 1,
    'デジタル社会形成基本法が掲げる基本理念の一つで，サイバー攻撃・個人情報漏洩等からデジタル社会の安全を守る取り組みはどれか。',
    'サイバーセキュリティの確保は，デジタル社会形成基本法の基本理念の一つ。デジタル化の進展に伴うサイバーリスクに対応するため，国・地方・民間が連携してセキュリティを確保することを求める。'
  ) RETURNING id INTO qid;

  VALUES (39, 113, 'choice', 1, 1,
    'デジタル社会形成基本法に基づき2021年9月に発足した，行政のデジタル化を統括・推進する日本の行政機関はどれか。',
    'デジタル庁は，行政のDX推進（行政システムの統一・標準化，マイナンバー活用，各省DX支援），デジタル社会の形成に向けた予算・政策を一元管理する内閣直轄の行政機関。'
  ) RETURNING id INTO qid;

  VALUES (39, 114, 'choice', 1, 1,
    '官民データ活用推進基本法で定義される，国・地方公共団体・事業者が保有する電磁的記録で構成されるデータはどれか。',
    '官民データは，官民データ活用推進基本法（2016年制定）が定義する，行政・民間が持つ電磁的形式のデータ全般。公開・共有・活用を推進することで，新たなサービス創出・行政効率化を目指す。'
  ) RETURNING id INTO qid;

  VALUES (39, 115, 'choice', 1, 1,
    '官民データ活用推進基本法が掲げる基本方針の一つで，行政手続をインターネット経由で行えるようにすることを原則とする取り組みはどれか。',
    '行政手続に係るオンライン利用の原則化は，申請・届出・交付などの行政手続をデフォルトでデジタル（オンライン）で行えるようにする原則。e-Japan戦略以来の目標であり，マイナポータル等で実現されている。'
  ) RETURNING id INTO qid;

  VALUES (39, 116, 'choice', 1, 1,
    '官民データ活用推進基本法が掲げる施策の一つで，国・地方・民間が保有するデータを相互に活用し，新サービス創出・行政効率化を促進する取り組みはどれか。',
    '国・地方公共団体・事業者が自ら保有する官民データの活用の推進は，官民データ活用推進基本法の柱の一つ。ベースレジストリ整備・オープンデータ公開・データ連携基盤構築などで実現される。'
  ) RETURNING id INTO qid;

  VALUES (39, 117, 'choice', 1, 1,
    '官民データ活用推進基本法が掲げる施策の一つで，高齢者・障がい者・地方在住者などのデジタルデバイドを解消し，誰もがデジタル技術の恩恵を受けられるようにする取り組みはどれか。',
    '情報通信技術の利用機会又は活用に係る格差の是正は，デジタルデバイド対策。ICT機器・インターネット接続・デジタルリテラシーの格差を縮小し，すべての人がデジタル社会に参画できる環境整備を目指す。'
  ) RETURNING id INTO qid;

  VALUES (39, 118, 'choice', 1, 1,
    '企業が事業活動の根本に置く価値観・行動指針・存在意義を示した，経営と倫理の基盤となる宣言はどれか。',
    '企業理念（ミッション・ビジョン・バリュー）は，企業の存在意義・向かう方向・行動基準を示す。法務・倫理の文脈では，コーポレートガバナンス・CSR活動の基盤となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 119, 'choice', 1, 1,
    '法令遵守にとどまらず，社会的に正しい行動をとることを企業・個人に求める価値観・行動規範の体系はどれか。',
    '企業倫理は，法律が定める最低限の基準を超えて，誠実・公正・透明に行動することへの規範。倫理綱領（コードオブコンダクト）として明文化され，内部統制・CSR活動の核となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 120, 'choice', 1, 1,
    '国連指導原則（ラギー原則）に基づき，企業が事業活動・サプライチェーンを通じて人権への悪影響を防止・軽減・救済する責任を示す概念はどれか。',
    'ビジネスと人権（Business and Human Rights）は，2011年国連指導原則で体系化。企業は人権を尊重する責任を負い，人権デュー・ディリジェンス（人権DDの実施）が求められる。日本でも行動計画が策定されている。'
  ) RETURNING id INTO qid;

  VALUES (39, 121, 'choice', 1, 1,
    '株主等ステークホルダーの利益を守るため，経営者の行動を監視・統制し，透明性ある経営を実現する仕組みはどれか。',
    'コーポレートガバナンス（企業統治）は，取締役会による経営監督・内部統制・情報開示・株主権利保護を通じて，経営の透明性と適正性を確保する仕組み。コーポレートガバナンス・コードがその基準を示す。'
  ) RETURNING id INTO qid;

  VALUES (39, 122, 'choice', 1, 1,
    '企業が利益追求だけでなく，環境・社会・ステークホルダーに対して責任ある行動をとることを示す概念はどれか。',
    'CSR（Corporate Social Responsibility，企業の社会的責任）は，企業が経済・社会・環境に与える影響に責任を持ち，倫理的な行動・情報公開・地域貢献を行うことを求める概念。'
  ) RETURNING id INTO qid;

  VALUES (39, 123, 'choice', 1, 1,
    '株主・従業員・顧客・取引先・地域社会・行政など，企業活動に利害関係をもつすべての関係者を指す概念はどれか。',
    'ステークホルダー（stakeholder）は，企業の意思決定や活動によって影響を受ける・影響を与えるすべての主体。CSR・ESG・コーポレートガバナンスでは，株主だけでなく多様なステークホルダーへの対応が求められる。'
  ) RETURNING id INTO qid;

  VALUES (39, 124, 'choice', 1, 1,
    '企業が業務の有効性・効率性，財務報告の信頼性，法令遵守，資産保全の4目標を達成するために整備・運用する仕組みはどれか。',
    '内部統制は，COSOフレームワークの6要素（統制環境・リスク評価・統制活動・情報と伝達・モニタリング・ITへの対応）で構成される。金融商品取引法では，上場企業に内部統制報告書の提出を義務付ける。'
  ) RETURNING id INTO qid;

  VALUES (39, 125, 'choice', 1, 1,
    '武器・軍事転用可能な技術・製品を特定の国・組織に輸出しないよう規制する，外国為替及び外国貿易法等に基づく法規制の総称はどれか。',
    '輸出関連法規（輸出管理法規）は，外国為替及び外国貿易法（外為法）・米国のEAR（輸出管理規則）等に基づき，安全保障上懸念のある国・組織への兵器・汎用品・技術の輸出を規制する。'
  ) RETURNING id INTO qid;

  VALUES (39, 126, 'choice', 1, 1,
    '経済産業省が策定した，情報システムのリスク管理・統制に関する標準的な指針で，情報システムの企画・開発・運用・廃棄の各工程での管理基準を示したものはどれか。',
    'システム管理基準は，経済産業省が策定した情報システムの管理に関するガイドライン。システム化計画・調達・開発・運用・保守・廃棄における管理項目・チェックリストを体系的にまとめた規範。'
  ) RETURNING id INTO qid;

  VALUES (39, 127, 'choice', 1, 1,
    'インターネットやデジタル通信を利用する際に守るべきマナー・礼儀作法の総称はどれか。',
    'ネチケット（netiquette）は，ネットワーク（net）とエチケット（etiquette）の造語。メール・SNS・掲示板などのオンライン空間での礼節ある行動規範。返信・引用・メールのCCなどのマナーを含む。'
  ) RETURNING id INTO qid;

  VALUES (39, 128, 'choice', 1, 1,
    '研究・調査において，存在しないデータを作り出すこと（ねつ造），既存のデータを改変・加工すること（改ざん），他人の成果を盗用すること（盗用）の不正行為をまとめた概念はどれか。',
    'データのねつ造・改ざん・盗用（FFP：Fabrication, Falsification, Plagiarism）は，研究不正の三大類型。技術者倫理・研究倫理の文脈で，社会的信頼の維持のために禁止される。'
  ) RETURNING id INTO qid;

  VALUES (39, 129, 'choice', 1, 1,
    '受信者に次々と転送を促すメッセージで，架空の警告・幸運のメッセージなどを多数の人に転送させるメールはどれか。',
    'チェーンメール（チェーンレター）は，「転送しないと不幸になる」「ウイルス情報を知らせて」等の内容で次々に転送を促す迷惑メール。デマの拡散・ネットワーク負荷増大の原因になる。'
  ) RETURNING id INTO qid;

  VALUES (39, 130, 'choice', 1, 1,
    '意図的に作られた虚偽のニュースや情報で，ソーシャルメディアなどで急速に拡散し，社会的な混乱や偏見を引き起こすものはどれか。',
    'フェイクニュースは，意図的に事実を歪めた偽情報。ミスインフォメーション（非意図的な誤情報）とは異なり，意図的な欺瞞が特徴。選挙介入・陰謀論拡散・企業信用失墜などに悪用される。'
  ) RETURNING id INTO qid;

  VALUES (39, 131, 'choice', 1, 1,
    '事実に基づく正確な情報だが，文脈から切り離したり誇張したりすることで，被害・騒動を引き起こす意図で使われる情報の種類はどれか。',
    'マルインフォメーション（malinformation）は，EUの情報操作分類の一つ。事実に基づくが，個人・組織・社会を傷つけることを意図して利用される情報。プライバシー侵害・ハラスメントに使われるケースが多い。'
  ) RETURNING id INTO qid;

  VALUES (39, 132, 'choice', 1, 1,
    '他者・社会を傷つけることを意図して意図的に拡散される虚偽・歪曲情報はどれか。',
    'ディスインフォメーション（disinformation）は，意図的に作成・拡散される偽情報。フェイクニュース・プロパガンダ・選挙干渉などが代表例。意図的でないミスインフォメーションと区別される。'
  ) RETURNING id INTO qid;

  VALUES (39, 133, 'choice', 1, 1,
    '意図はなく，誤解・不注意・誤認識によって不正確な情報が広まる現象はどれか。',
    'ミスインフォメーション（misinformation）は，悪意なく広まる誤情報。SNSのデマ拡散・情報の誤解釈・古い情報の再流通などが原因。意図的なディスインフォメーションと異なり，発信者は誤りを信じている。'
  ) RETURNING id INTO qid;

  VALUES (39, 134, 'choice', 1, 1,
    '人種・民族・宗教・性別・性的指向などの属性を理由に，特定の個人・集団を侮辱・脅迫・差別する言論はどれか。',
    'ヘイトスピーチは，差別的な言動によって特定グループに対する憎悪・暴力・差別を煽る行為。日本では「本邦外出身者に対する不当な差別的言動の解消に向けた取組の推進に関する法律」で対処が求められている。'
  ) RETURNING id INTO qid;

  VALUES (39, 135, 'choice', 1, 1,
    'SNSやオンライン空間で，同じ意見・価値観をもつ人々が集まることで，互いの意見を反響・強化し合い，多様な視点を失っていく現象はどれか。',
    'エコーチェンバー（echo chamber，反響室）は，閉鎖的なコミュニティで似た意見が増幅・強化され，異なる意見が排除されていく現象。SNSのフィルタリング機能と合わさって，極端な意見の強化につながる。'
  ) RETURNING id INTO qid;

  VALUES (39, 136, 'choice', 1, 1,
    'SNSや検索エンジンのアルゴリズムが，ユーザーの過去の行動に基づいて特定の情報だけを表示し，異なる意見や情報が届かなくなる現象はどれか。',
    'フィルターバブル（filter bubble）は，イーライ・パリサーが提唱。アルゴリズムが「見たい情報」だけを表示することで，ユーザーが情報の「泡（バブル）」の中に閉じ込められ，多様な視点が失われる現象。'
  ) RETURNING id INTO qid;

  VALUES (39, 137, 'choice', 1, 1,
    'インターネット上に一度投稿した情報は完全に削除できず，永続的に残り続けるリスクを示す比喩的な表現はどれか。',
    'デジタルタトゥーは，SNS投稿・写真・コメントが検索・アーカイブされ続け，将来的な就職・対人関係に影響を与えるリスクを指す概念。特に若者へのデジタルリテラシー教育で重視される。'
  ) RETURNING id INTO qid;

  VALUES (39, 138, 'choice', 1, 1,
    'インターネット上の有害コンテンツ（暴力・ポルノ・違法サイト等）へのアクセスをブロックする技術・サービスはどれか。',
    'フィルタリングは，URLブラックリスト・キーワードフィルタ・カテゴリ分類などで有害サイトへのアクセスを遮断する技術。学校・家庭での青少年保護，企業内のセキュリティ対策として使われる。'
  ) RETURNING id INTO qid;

  VALUES (39, 139, 'choice', 1, 1,
    '保護者が子供のインターネット・スマートフォンの利用内容・時間・通話・アプリをデバイスや専用ツールで管理・制限する機能はどれか。',
    'ペアレンタルコントロールは，OS・スマホ・ルーターに搭載される保護者向け管理機能。有害サイトのブロック・使用時間制限・課金制限・アプリ管理などで未成年の安全なデジタル環境を整える。'
  ) RETURNING id INTO qid;

  VALUES (39, 140, 'choice', 1, 1,
    'ニュースや情報の真偽・正確性を専門的な調査・根拠に基づいて検証し，誤情報の拡散防止に貢献する活動はどれか。',
    'ファクトチェック（事実確認）は，報道機関・市民ジャーナリストが主張の根拠・事実を検証する活動。フェイクニュース・ディスインフォメーション対策として世界各国で組織化されている。'
  ) RETURNING id INTO qid;

  VALUES (39, 141, 'choice', 1, 1,
    '技術の開発・利用が社会・法・倫理に与える影響を検討するフレームワークで，特にAI・バイオテクノロジーなどで重視される概念はどれか。',
    '倫理的・法的・社会的な課題（ELSI：Ethical, Legal, and Social Issues）は，科学技術の発展に伴う倫理・法律・社会問題を予防的に検討するフレームワーク。AI倫理・ゲノム研究・個人情報で重視される。'
  ) RETURNING id INTO qid;

  VALUES (39, 142, 'choice', 1, 1,
    '技術者・エンジニアが守るべき行動規範を文書化したもので，IEEE・ACM・IPAJなど技術者団体が定めたものはどれか。',
    '技術者の倫理綱領（code of ethics）は，安全・社会への貢献・公正・誠実などを技術者の行動規範として明文化したもの。IEEE・ACMの倫理綱領が国際的に参照され，日本のIEEJ・IPAJも制定している。'
  ) RETURNING id INTO qid;

  VALUES (39, 143, 'choice', 1, 1,
    '技術者が専門知識・技能を活かして社会の安全・環境・公益を守る義務として持つ責任はどれか。',
    '技術者の社会的責任は，専門知識を持つエンジニアが一般市民より高い水準の倫理的・社会的責任を負うという概念。製品の安全性・環境配慮・プライバシー保護などが対象。'
  ) RETURNING id INTO qid;

  VALUES (39, 144, 'choice', 1, 1,
    '社会規範・価値観・良識に基づいた，善悪の判断・行動の基準に関する概念はどれか。',
    'モラル（道徳）は，社会規範・文化的価値観に根ざした行動の基準。法律で規制されていなくても，道義的に許されない行為・許される行為を判断する内的基準。技術者倫理の基盤となる。'
  ) RETURNING id INTO qid;

  VALUES (39, 145, 'choice', 1, 1,
    '専門的な知識・技能・倫理基準をもち，高い品質と誠実さをもって職務を遂行する態度・在り方の総称はどれか。',
    'プロフェッショナリズム（professionalism）は，専門職としての高い水準・品位・責任感をもって業務に臨む態度。技術者・医師・弁護士などの専門職に求められる職業的倫理と能力の総称。'
  ) RETURNING id INTO qid;

  VALUES (39, 146, 'choice', 1, 1,
    '集団での意思決定で，異論を抑圧し批判的思考が失われ，画一的・非合理な結論に至る心理的現象はどれか。',
    '集団思考（groupthink）は，ジャニス（Janis）が提唱。凝集性の高い集団で異論が排除され，集団全体が誤った結論を合理的と信じる現象。重大な意思決定ミスの原因となり，悪魔の代弁者制度などで防止する。'
  ) RETURNING id INTO qid;

  VALUES (39, 147, 'choice', 1, 1,
    '組織内の不正行為・法令違反・安全上の問題などを，組織の外部（監督機関・メディアなど）に知らせる行為はどれか。',
    '内部告発（内部通報・公益通報）は，組織内部の不正を外部または内部窓口に通報する行為。公益通報者保護法で保護され，食品偽装・医薬品不正・会計不正などの発覚につながることが多い。'
  ) RETURNING id INTO qid;

  VALUES (39, 148, 'choice', 1, 1,
    '電気通信サービスを提供する事業者の業務・財務・設備に関する規制と，利用者保護（禁止行為・苦情処理等）を定めた法律はどれか。',
    '電気通信事業法は，通信事業者の参入規制（登録・届出），設備維持義務，検閲禁止，通信の秘密保護，利用者への適切なサービス提供義務などを定める。インターネットサービス提供者にも適用される。'
  ) RETURNING id INTO qid;

  VALUES (39, 149, 'choice', 1, 1,
    '無線通信に使用する電波の周波数の割り当て・利用条件・無線局の免許・妨害排除などを定めた法律はどれか。',
    '電波法は，電波の公平かつ能率的な利用を確保するための法律。無線局（携帯基地局・放送局・アマチュア無線等）の免許制度，電波利用料，不法電波の取締りなどを規定する。'
  ) RETURNING id INTO qid;

  VALUES (39, 150, 'choice', 1, 1,
    '巨大SNS・動画配信サービス等の特定プラットフォーム事業者に，偽情報・違法コンテンツへの対処義務と情報開示を求める法律はどれか。',
    '情報流通プラットフォーム対処法（2024年成立）は，月間利用者数等の基準を超える特定プラットフォームに，誹謗中傷・偽情報・違法コンテンツへの対処措置と総務大臣への報告・公表を義務付ける。'
  ) RETURNING id INTO qid;

  VALUES (39, 151, 'choice', 1, 1,
    '裁判所の令状に基づき，組織犯罪・テロ等の重大犯罪捜査のために通信の傍受（盗聴）を限定的に認める法律はどれか。',
    '通信傍受法（犯罪捜査のための通信傍受に関する法律）は，薬物・銃器・組織犯罪等の捜査で，裁判官の令状のもと通信を傍受できる手続きを定める。通信の秘密（憲法21条）との調和が課題。'
  ) RETURNING id INTO qid;

  VALUES (39, 152, 'choice', 1, 1,
    '有価証券の発行・取引に関するルール，インサイダー取引・風説流布の禁止，上場企業の開示義務などを定めた法律はどれか。',
    '金融商品取引法は，証券取引法の後継として2007年施行。有価証券の公正な流通・投資家保護を目的とし，内部統制報告書・有価証券報告書の提出義務，インサイダー取引規制，市場の不公正取引禁止を定める。'
  ) RETURNING id INTO qid;

  VALUES (39, 153, 'choice', 1, 1,
    '上場企業が金融商品取引法に基づき，1年間の財務情報・事業概況・リスク情報などを投資家向けに開示する報告書はどれか。',
    '有価証券報告書は，金融商品取引法24条に基づく上場企業の年次開示文書。財務諸表・事業内容・役員情報・リスク・株式情報などを記載し，電子開示システム（EDINET）で公開される。'
  ) RETURNING id INTO qid;

  VALUES (39, 154, 'choice', 1, 1,
    '上場企業が金融商品取引法に基づき，財務報告に係る内部統制の有効性を経営者が評価した結果を開示する報告書はどれか。',
    '内部統制報告書は，J-SOX（日本版SOX法）として2008年から義務化。経営者が財務報告内部統制の有効性を評価し，外部監査人が監査する。COSOフレームワークに基づいて作成される。'
  ) RETURNING id INTO qid;

  VALUES (39, 155, 'choice', 1, 1,
    '株式会社の設立・組織・運営・管理に関するルールを包括的に定めた，企業法制の基本法はどれか。',
    '会社法（2006年施行）は，株式会社・合同会社等の設立・株主総会・取締役会・計算書類・組織再編・解散・清算等を定める企業の基本法。商法から分離独立して制定された。'
  ) RETURNING id INTO qid;

  VALUES (39, 156, 'choice', 1, 1,
    '株式会社における最高意思決定機関で，取締役の選解任・利益配当・定款変更などの重要事項を決議する機関はどれか。',
    '株主総会は，株式会社の最高意思決定機関。定時総会（決算後3か月以内）と臨時総会がある。特別決議（2/3以上）・普通決議（過半数）など，議案の重要度に応じて決議要件が異なる。'
  ) RETURNING id INTO qid;

  VALUES (39, 157, 'choice', 1, 1,
    '会社法で定められた，株式会社の業務執行の意思決定と対外的な代表を担う役員はどれか。',
    '取締役は，株主総会で選任される役員。業務執行の意思決定（取締役会設置会社では取締役会で決定），代表取締役の選定，会社の代表機能を担う。善管注意義務・忠実義務が課される。'
  ) RETURNING id INTO qid;

  VALUES (39, 158, 'choice', 1, 1,
    '指名委員会等設置会社（3委員会設置会社）において，取締役会から権限委譲を受けて業務執行を担当する役員はどれか。',
    '執行役は，指名委員会等設置会社（旧委員会設置会社）で業務執行を担う役員。取締役会が監督機能に特化するため，業務執行は執行役に委ねられる。代表執行役が会社を代表する。'
  ) RETURNING id INTO qid;

  VALUES (39, 159, 'choice', 1, 1,
    '取締役の業務執行が適正かどうかを監視・調査し，株主の利益を守るために会計・業務の監査を行う役員はどれか。',
    '監査役は，取締役・会計参与の職務執行を監査する役員。業務監査・会計監査を行い，取締役会・株主総会への報告義務を持つ。監査役会設置会社では3人以上の監査役が必要。'
  ) RETURNING id INTO qid;

  VALUES (39, 160, 'choice', 1, 1,
    '取締役会の中に指名委員会・監査委員会・報酬委員会の3委員会を設置し，経営の監督と業務執行を分離した会社形態はどれか。',
    '委員会設置会社（現：指名委員会等設置会社）は，取締役会の下に3委員会（各委員会の過半数が社外取締役）を置き，取締役会が監督に特化する機関設計。透明性の高いガバナンス体制として大企業で採用される。'
  ) RETURNING id INTO qid;

  VALUES (39, 161, 'choice', 1, 1,
    '会社法に基づき，株式会社が株主総会に提出する，事業の経過・成果・財産の状況等を記した書類はどれか。',
    '事業報告は，会社法で株主総会の計算書類と合わせて提出が義務付けられる書類。会社の概況・役員の状況・業務の状況・内部統制の整備状況などを記載する。'
  ) RETURNING id INTO qid;

  VALUES (39, 162, 'choice', 1, 1,
    '法人が得た所得（利益）に対して課税される，企業の主要な税金に関する法律はどれか。',
    '法人税法は，内国法人・外国法人の課税所得・税率・申告・納税手続を定める。法人税は国税で，これに地方法人税・法人住民税・法人事業税が加算される。'
  ) RETURNING id INTO qid;

  VALUES (39, 163, 'choice', 1, 1,
    '商品・サービスの消費に対して課税される間接税の税率・課税標準・申告・納税手続を定めた法律はどれか。',
    '消費税法は，消費者が負担し事業者が納付する間接税を規定する。標準税率10%（うち地方消費税2.2%）・軽減税率8%（食料品等）。インボイス制度（適格請求書等保存方式）の根拠法でもある。'
  ) RETURNING id INTO qid;

  VALUES (39, 164, 'choice', 1, 1,
    '2023年10月から導入された，消費税の仕入税額控除に必要な，登録事業者が発行する一定事項を記載した請求書等の制度はどれか。',
    '適格請求書等保存方式（インボイス制度）は，消費税法の改正により2023年10月から開始。課税仕入れの仕入税額控除には，適格請求書発行事業者（インボイス発行事業者）が発行した適格請求書の保存が必要。'
  ) RETURNING id INTO qid;

  VALUES (39, 165, 'choice', 1, 1,
    '民間事業者が法令で保存義務を課されている書類（契約書・帳票・議事録等）について，電磁的記録による保存を認めた法律はどれか。',
    'e-文書法（2005年施行）は，各省庁の法令で紙保存が義務付けられた文書を，スキャン画像・電子データでの保存に代替できるよう認める一括した法律。電子化による業務効率化・保管コスト削減を実現する。'
  ) RETURNING id INTO qid;

END $$;
DO $$
DECLARE
  qid integer;
BEGIN
  -- Q166: 電子帳簿保存法
  VALUES (39, 166, 'choice', 1, 1, '電子帳簿保存法に関する記述として，適切なものはどれか。', '電子帳簿保存法は，税法上の帳簿・書類を電磁的記録（電子データ）で保存することを認める法律である。電子取引のデータ保存も義務化されている。') RETURNING id INTO qid;

  -- Q167: 道路運送車両法
  VALUES (39, 167, 'choice', 1, 1, '道路運送車両法において，自動運転システムを搭載した車両の保安基準を定めることができる根拠となる概念はどれか。', '道路運送車両法は自動車の安全確保・公害防止のための保安基準を定める法律で，自動運転車の基準策定にも活用される。') RETURNING id INTO qid;

  -- Q168: 航空法
  VALUES (39, 168, 'choice', 1, 1, '航空法においてドローン（無人航空機）の飛行に関して原則として禁止されている区域はどれか。', '航空法では，空港周辺・人口集中地区・高度150m以上等の空域でドローンの飛行が原則禁止（許可が必要）とされている。') RETURNING id INTO qid;

  -- Q169: 小型無人機等飛行禁止法
  VALUES (39, 169, 'choice', 1, 1, '「小型無人機等飛行禁止法」が対象とする施設はどれか。', '小型無人機等飛行禁止法（重要施設周辺地域の上空における小型無人機等の飛行の禁止に関する法律）は，国会議事堂・官邸・原子力発電所などの重要施設周辺上空でのドローン飛行を禁止する。') RETURNING id INTO qid;

  -- Q170: 労働安全衛生法
  VALUES (39, 170, 'choice', 1, 1, '労働安全衛生法において，事業者が50人以上の労働者を使用する場合に選任が義務付けられている者はどれか。', '労働安全衛生法では，常時50人以上の労働者を使用する事業場に衛生管理者・産業医の選任，衛生委員会の設置などが義務付けられている。') RETURNING id INTO qid;

  -- Q171: PL法
  VALUES (39, 171, 'choice', 1, 1, 'PL法（製造物責任法）の説明として，適切なものはどれか。', 'PL法（製造物責任法）は，製品の欠陥によって消費者等が被害を受けた場合，製造業者等が過失の有無にかかわらず損害賠償責任を負う（無過失責任）ことを定めた法律である。') RETURNING id INTO qid;

  -- Q172: 情報公開法
  VALUES (39, 172, 'choice', 1, 1, '情報公開法（行政機関の保有する情報の公開に関する法律）において，行政文書の開示請求ができる者はどれか。', '情報公開法では，何人も（日本国籍の有無・居住地を問わず），行政機関が保有する行政文書の開示を請求できる。') RETURNING id INTO qid;

  -- Q173: 廃棄物処理法
  VALUES (39, 173, 'choice', 1, 1, '廃棄物処理法（廃棄物の処理及び清掃に関する法律）において，産業廃棄物の処理責任を負う者はどれか。', '廃棄物処理法では，事業活動によって生じた産業廃棄物の処理（収集・運搬・処分）については，排出した事業者が責任を負う（排出者責任）。') RETURNING id INTO qid;

  -- Q174: リサイクル法
  VALUES (39, 174, 'choice', 1, 1, '資源有効利用促進法（リサイクル法）において，PCなどの情報機器に関するメーカーの義務はどれか。', '資源有効利用促進法では，PCメーカーに対して自社製品の回収・再資源化が義務付けられている（事業者による自主回収・リサイクルの義務化）。') RETURNING id INTO qid;

  -- Q175: GX推進法
  VALUES (39, 175, 'choice', 1, 1, 'GX推進法（脱炭素成長型経済構造への円滑な移行の推進に関する法律）の目的はどれか。', 'GX推進法は，化石燃料依存からの脱却と脱炭素成長型経済構造への移行（グリーントランスフォーメーション）を推進するための法律である。') RETURNING id INTO qid;

  -- Q176: GX脱炭素電源法
  VALUES (39, 176, 'choice', 1, 1, 'GX脱炭素電源法（脱炭素社会の実現に向けた電気供給体制の確立を図るための電気事業法等の一部を改正する法律）が活用を推進する電源はどれか。', 'GX脱炭素電源法は，原子力発電の活用（60年超の運転延長など）や再生可能エネルギーの拡大を通じて脱炭素電源の確保を図る法律である。') RETURNING id INTO qid;

  -- Q177: 省エネ法
  VALUES (39, 177, 'choice', 1, 1, '省エネ法（エネルギーの使用の合理化及び非化石エネルギーへの転換等に関する法律）において，特定事業者に求められる義務はどれか。', '省エネ法では，年間エネルギー使用量が一定量以上の特定事業者に対して，省エネ計画の作成・提出，エネルギー管理者の選任，定期報告の提出などが義務付けられている。') RETURNING id INTO qid;

  -- Q178: 外国為替及び外国貿易法
  VALUES (39, 178, 'choice', 1, 1, '外国為替及び外国貿易法（外為法）において，安全保障上の観点から規制される取引はどれか。', '外為法では，武器・軍事転用可能な技術・製品等の輸出（輸出規制）や，安全保障上懸念のある外国企業への外国直接投資（対内直接投資規制）が規制される。') RETURNING id INTO qid;

  -- Q179: 米国輸出関連法
  VALUES (39, 179, 'choice', 1, 1, '米国の輸出関連法であるEAR（輸出管理規則）の規制対象となるものはどれか。', 'EAR（Export Administration Regulations）は，米国の輸出管理規則であり，デュアルユース（民生・軍事両用）品目・技術・ソフトウェアの輸出・再輸出を規制する。') RETURNING id INTO qid;

  -- Q180: JIS
  VALUES (39, 180, 'choice', 1, 1, 'JIS（日本産業規格）の説明として，適切なものはどれか。', 'JIS（Japanese Industrial Standards）は，産業標準化法に基づき，製品・サービス・データ等に関する日本の国家規格である。経済産業省所管のJISCが制定・改正を行う。') RETURNING id INTO qid;

  -- Q181: JIS X部門
  VALUES (39, 181, 'choice', 1, 1, 'JISの部門記号のうち，情報処理に関する規格が属する部門はどれか。', 'JIS X部門は情報処理（情報技術）に関する規格群である。例として，JIS X 0208（文字コード），JIS X 0160（ソフトウェアライフサイクルプロセス）などがある。') RETURNING id INTO qid;

  -- Q182: JIS Q部門
  VALUES (39, 182, 'choice', 1, 1, 'JISの部門記号のうち，品質マネジメントシステムや環境マネジメントシステムなどのマネジメントシステム規格が属する部門はどれか。', 'JIS Q部門はマネジメントシステムに関する規格群である。例として，JIS Q 9001（品質マネジメントシステム），JIS Q 14001（環境マネジメントシステム）などがある。') RETURNING id INTO qid;

  -- Q183: JISC
  VALUES (39, 183, 'choice', 1, 1, 'JISCの説明として，適切なものはどれか。', 'JISC（日本産業標準調査会：Japanese Industrial Standards Committee）は，産業標準化法に基づき経済産業省に設置された審議会で，JISの制定・改正・廃止の審議やISOへの対応を行う。') RETURNING id INTO qid;

  -- Q184: JSA
  VALUES (39, 184, 'choice', 1, 1, 'JSA（日本規格協会）の主な役割はどれか。', 'JSA（Japanese Standards Association：日本規格協会）は，JIS規格票の発行・販売，規格に関する調査研究・普及活動を行う公益財団法人である。') RETURNING id INTO qid;

  -- Q185: IS
  VALUES (39, 185, 'choice', 1, 1, 'IS（国際規格：International Standard）の説明として，適切なものはどれか。', 'IS（International Standard：国際規格）は，ISOやIECなどの国際標準化機関が策定し，世界共通で使用されることを目的とした規格である。') RETURNING id INTO qid;

  -- Q186: ISO
  VALUES (39, 186, 'choice', 1, 1, 'ISOの説明として，適切なものはどれか。', 'ISO（International Organization for Standardization：国際標準化機構）は，電気・電子分野を除く広範な分野の国際規格を策定する国際機関である。本部はスイスのジュネーブに置かれる。') RETURNING id INTO qid;

  -- Q187: 国際認証
  VALUES (39, 187, 'choice', 1, 1, 'ISO 9001やISO 14001などのISOマネジメントシステム規格に基づく「国際認証」の説明として，適切なものはどれか。', '国際認証（ISO認証）とは，第三者の認証機関が，組織のマネジメントシステムがISO規格の要求事項を満たしていることを審査・証明する制度である。') RETURNING id INTO qid;

  -- Q188: ITU
  VALUES (39, 188, 'choice', 1, 1, 'ITU（国際電気通信連合）の説明として，適切なものはどれか。', 'ITU（International Telecommunication Union：国際電気通信連合）は，電気通信分野の国際標準の策定や無線周波数の割り当てなどを行う国連の専門機関である。') RETURNING id INTO qid;

  -- Q189: IEC
  VALUES (39, 189, 'choice', 1, 1, 'IEC（国際電気標準会議）の説明として，適切なものはどれか。', 'IEC（International Electrotechnical Commission：国際電気標準会議）は，電気・電子・電磁技術分野の国際規格を策定する国際機関である。ISOと並ぶ主要な国際標準化機関のひとつ。') RETURNING id INTO qid;

  -- Q190: IETF
  VALUES (39, 190, 'choice', 1, 1, 'IETFの説明として，適切なものはどれか。', 'IETF（Internet Engineering Task Force：インターネット技術特別調査委員会）は，インターネットの技術仕様（プロトコル等）を検討・策定する任意参加の標準化組織である。策定された規格はRFC（Request for Comments）として公開される。') RETURNING id INTO qid;

  -- Q191: ANSI
  VALUES (39, 191, 'choice', 1, 1, 'ANSIの説明として，適切なものはどれか。', 'ANSI（American National Standards Institute：米国国家規格協会）は，米国の国家規格（米国国家標準）を策定・認定する非営利団体であり，ISOやIECにおける米国代表機関でもある。') RETURNING id INTO qid;

  -- Q192: IEEE
  VALUES (39, 192, 'choice', 1, 1, 'IEEE 802.11として標準化されている技術はどれか。', 'IEEE（Institute of Electrical and Electronics Engineers：電気電子学会）は電気・電子・情報技術分野の学会・標準化団体で，IEEE 802.11として無線LAN規格を標準化している。') RETURNING id INTO qid;

  -- Q193: W3C
  VALUES (39, 193, 'choice', 1, 1, 'W3Cが策定している標準規格はどれか。', 'W3C（World Wide Web Consortium）は，HTML・CSS・XML・SVGなどのWeb技術の標準規格を策定する国際的な標準化団体である。') RETURNING id INTO qid;

  -- Q194: フォーラム標準
  VALUES (39, 194, 'choice', 1, 1, 'フォーラム標準の説明として，適切なものはどれか。', 'フォーラム標準とは，特定の業界や技術分野の企業・団体が集まって形成した標準化フォーラム（コンソーシアム）が策定した規格である。W3CやIETFなどが代表例。デジュレ標準（公的機関が制定）と対比される。') RETURNING id INTO qid;

  -- Q195: デジュレスタンダード
  VALUES (39, 195, 'choice', 1, 1, 'デジュレスタンダード（de jure standard）の説明として，適切なものはどれか。', 'デジュレスタンダード（デジュール標準）とは，ISO・IEC・ITUなどの公的な標準化機関の正規の手続きを経て制定された公的規格（法的根拠を持つ標準）のことである。デファクトスタンダードと対比される。') RETURNING id INTO qid;

  -- Q196: SLCP-JCF
  VALUES (39, 196, 'choice', 1, 1, 'SLCP-JCF（ソフトウェアライフサイクルプロセス-Japan Common Frame）の説明として，適切なものはどれか。', 'SLCP-JCF（共通フレーム）は，ソフトウェアの取引・開発・運用に関わる作業内容・用語を標準化した日本の規格（JIS X 0160をベースに日本向けに拡張）で，発注者とベンダ間の認識合わせに用いられる。') RETURNING id INTO qid;

  -- Q197: JIS X 0160
  VALUES (39, 197, 'choice', 1, 1, 'JIS X 0160の説明として，適切なものはどれか。', 'JIS X 0160は，ソフトウェアライフサイクルプロセスに関するJIS規格（ISO/IEC 12207に対応）であり，ソフトウェアの取得・供給・開発・運用・保守などのプロセスを定義している。') RETURNING id INTO qid;

  -- Q198: JIS X 0170
  VALUES (39, 198, 'choice', 1, 1, 'JIS X 0170の説明として，適切なものはどれか。', 'JIS X 0170は，システムライフサイクルプロセスに関するJIS規格（ISO/IEC 15288に対応）であり，システムの企画・開発・運用・廃棄等のプロセスを定義している。') RETURNING id INTO qid;

  -- Q199: ISO 14000
  VALUES (39, 199, 'choice', 1, 1, 'ISO 14000シリーズの説明として，適切なものはどれか。', 'ISO 14000シリーズは，環境マネジメントシステムに関する国際規格の体系である。中核規格であるISO 14001は，組織が環境パフォーマンスを継続的に改善するためのマネジメントシステム要求事項を規定している。') RETURNING id INTO qid;

  -- Q200: JIS Q 14001
  VALUES (39, 200, 'choice', 1, 1, 'JIS Q 14001の説明として，適切なものはどれか。', 'JIS Q 14001は，ISO 14001（環境マネジメントシステム）のJIS規格化であり，組織が環境に関する方針を定め，PDCAサイクルで継続的改善を行うためのマネジメントシステム要求事項を規定している。') RETURNING id INTO qid;

  -- Q201: ISO/IEC 15408
  VALUES (39, 201, 'choice', 1, 1, 'ISO/IEC 15408の説明として，適切なものはどれか。', 'ISO/IEC 15408は，情報技術セキュリティ評価基準（CC：Common Criteria）の国際規格である。ITセキュリティ製品・システムのセキュリティ要件の記述と評価のための共通基準を定めている。') RETURNING id INTO qid;

  -- Q202: CORBA
  VALUES (39, 202, 'choice', 1, 1, 'CORBAの説明として，適切なものはどれか。', 'CORBA（Common Object Request Broker Architecture）は，OMGが策定した分散オブジェクト技術の標準規格である。異なるプラットフォーム・言語で実装されたオブジェクト間の相互通信（メソッド呼び出し）を実現する。') RETURNING id INTO qid;

  -- Q203: OMG
  VALUES (39, 203, 'choice', 1, 1, 'OMG（Object Management Group）が策定した代表的な標準規格はどれか。', 'OMG（Object Management Group）は，オブジェクト指向技術の標準化を推進する国際コンソーシアムであり，CORBAやUML（統一モデリング言語）などを策定している。') RETURNING id INTO qid;

  -- Q204: EJB
  VALUES (39, 204, 'choice', 1, 1, 'EJB（Enterprise JavaBeans）の説明として，適切なものはどれか。', 'EJB（Enterprise JavaBeans）は，Java EE（現Jakarta EE）の仕様の一部で，サーバサイドのビジネスロジックをコンポーネントとして実装するための標準規格である。トランザクション管理・セキュリティ・分散処理を容易にする。') RETURNING id INTO qid;

  -- Q205: 文字コード
  VALUES (39, 205, 'choice', 1, 1, '文字コードの説明として，適切なものはどれか。', '文字コードとは，文字（アルファベット・数字・漢字等）と数値（コードポイント）の対応関係を定めた規格・体系である。ASCII・JISコード・Unicodeなどがある。') RETURNING id INTO qid;

  -- Q206: JISコード
  VALUES (39, 206, 'choice', 1, 1, 'JISコード（JIS X 0208）の説明として，適切なものはどれか。', 'JISコード（JIS X 0208）は，日本語の文字集合（ひらがな・カタカナ・漢字・英数字等）を定めたJIS規格の文字コードである。ISO-2022-JPなどのエンコード方式の基礎となっている。') RETURNING id INTO qid;

  -- Q207: Unicode
  VALUES (39, 207, 'choice', 1, 1, 'Unicodeの説明として，適切なものはどれか。', 'Unicodeは，世界中のほぼすべての文字（各国語・記号・絵文字等）を統一的に扱うための国際文字コード標準である。ISO/IEC 10646と同一の文字集合を持ち，UTF-8・UTF-16・UTF-32などのエンコード方式がある。') RETURNING id INTO qid;

  -- Q208: JANコード
  VALUES (39, 208, 'choice', 1, 1, 'JANコードの説明として，適切なものはどれか。', 'JANコード（Japanese Article Number code）は，日本の小売商品に使われるバーコード規格で，国際的にはEAN（European Article Number）コードの一部として標準化されている。13桁または8桁の数字で商品を識別する。') RETURNING id INTO qid;

  -- Q209: QRコード
  VALUES (39, 209, 'choice', 1, 1, 'QRコードの説明として，適切なものはどれか。', 'QRコード（Quick Response code）は，デンソーウェーブが開発したマトリックス型2次元バーコードで，ISO/IEC 18004として国際規格化されている。数字・英字・漢字等を高密度に記録でき，読取速度が速い。') RETURNING id INTO qid;

  -- Q210: ITFコード
  VALUES (39, 210, 'choice', 1, 1, 'ITFコードの主な用途はどれか。', 'ITFコード（Interleaved Two of Five code：インタリーブド2of5コード）は，物流の段ボール箱などの外装に使われるバーコード規格で，JANコードの集合体（標準14桁）の印刷に主に用いられる。') RETURNING id INTO qid;

  -- Q211: ISBNコード
  VALUES (39, 211, 'choice', 1, 1, 'ISBNコードの説明として，適切なものはどれか。', 'ISBN（International Standard Book Number）コードは，書籍を国際的に一意に識別するための13桁（旧10桁）の番号体系であり，バーコードとして書籍に印刷される。国際規格ISO 2108で定められている。') RETURNING id INTO qid;

  -- Q212: 適合性評価
  VALUES (39, 212, 'choice', 1, 1, '適合性評価の説明として，適切なものはどれか。', '適合性評価（conformity assessment）とは，製品・サービス・プロセス・システム・人物などが，規格や規制要求事項を満たしていることを評価・証明する活動の総称である。試験・検査・認証・認定などを含む。') RETURNING id INTO qid;

  -- Q213: 適合性評価機関
  VALUES (39, 213, 'choice', 1, 1, '適合性評価機関の説明として，適切なものはどれか。', '適合性評価機関とは，試験・検査・認証・認定等の適合性評価サービスを提供する機関の総称であり，認定機関・認証機関・試験機関・検査機関等が含まれる。') RETURNING id INTO qid;

  -- Q214: 認定機関
  VALUES (39, 214, 'choice', 1, 1, '認定機関の説明として，適切なものはどれか。', '認定機関（accreditation body）とは，認証機関・試験機関・検査機関などの適合性評価機関が，特定の規格に基づき適格に業務を行う能力があることを第三者として証明（認定）する機関である。日本ではJABやIAJapanが該当する。') RETURNING id INTO qid;

  -- Q215: 認証機関
  VALUES (39, 215, 'choice', 1, 1, '認証機関の説明として，適切なものはどれか。', '認証機関（certification body）とは，製品・システム・人物等が規格の要求事項を満たしていることを第三者として審査し，適合を認証する機関である。ISO 9001やISO 14001などの認証審査を行う機関がこれにあたる。') RETURNING id INTO qid;

  -- Q216: 試験機関
  VALUES (39, 216, 'choice', 1, 1, '試験機関の説明として，適切なものはどれか。', '試験機関（testing laboratory）とは，製品・材料・部品などの物理的・化学的・電気的特性等を試験・測定し，その結果を報告する機関である。国際規格ISO/IEC 17025に基づき認定を受けた機関が公認試験機関として認められる。') RETURNING id INTO qid;

END $$;
